INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111111', '道徙多阪，胡言连蹇。译喑且聋，莫使道通。请遏不行，求事无功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000000', '招殃来螯，害我邦国。病伤手足，不得安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '010001', '阳孤亢极，多所恨惑。车倾盖亡，身常忧惶。乃得其愿，雌雄相从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '100010', '鵊鵴鸤鸠，专一无忧。君子是则，长受嘉福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '010111', '目瞤足动，喜如其愿，举家蒙宠。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111010', '龙马上山，绝无水泉，喉焦唇干，舌不能言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000010', '仓盈庾亿，宜稼黍稷。年岁丰熟，民人安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '010000', '中夜犬吠，盗在墙外。神明佑助，消散皆去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '110111', '据斗运枢，顺天无忧。所行造德，与乐并居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111011', '空拳握手，委地更起。富饶丰衍，快乐无已。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000111', '不风不雨，白日皎皎，宜出驱驰，通理大道。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111000', '载日晶光，骖驾六龙。禄命彻天，封为燕王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111101', '子号索哺，母行求食。反见空巢，訾我长息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '101111', '上帝之生，福佑日成。修德行惠，乐且安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000100', '山险难登，涧中多石。车驰軎击，载重伤轴，担载差踬，踠跌失足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '001000', '禹凿龙门，通利水源。东注沧海，民得安从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '011001', '乘龙上天，两蛇为辅，踊跃云中，游观沧海，民乐安处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '100110', '彭祖九子，据德不殆。南山松柏，长受嘉福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000011', '南山昊天，刺政关身。疾悲无辜，皆憎为仇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '110000', '江河淮海，天之奥府。众利所聚，可以饶有。乐我君子，百福是受。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '101001', '坚冰黄鸟，终日悲号。不见白粒，但见藜蒿，数惊鸷鸟，为我心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '100101', '室如悬磬，既危且殆。早见之士，依山谷处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '100000', '大禹戒路，蚩尤除道。周匝万里，不危不殆，见其所使，无所不在。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000001', '三人为旅，俱归北海。入门上堂，拜谒王母，饮劳我酒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111001', '传言相误，非干径路。鸣鼓逐狐，不知迹处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '100111', '三羊争雌，相逐奔驰。终日不食，精气劳疲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '100001', '纯服黄裳，戴上以兴。德义既生，天下归仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '011110', '桀跖并处，人民愁苦。权兵荷粮，战于齐鲁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '010010', '黄鸟采绿，既嫁不答。念我父兄，思复邦国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '101101', '胎生孚乳，长息成就。充满帝室，家国昌富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '011100', '三人求桔，反得大粟。女贵以富，黄金百镒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '001110', '东山西岳，会合俱食。百家送从，以成恩福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111100', '弱鸡无距，与鹊交斗。翅折目盲，为鸠所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '001111', '隙大墙坏，蠹众木折。狼虎为政，天降罪罚。高弑望夷，胡亥以毙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '101000', '三痴俱走，迷路失道。惑不知归，反入患口。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000101', '弓矢俱张，把弹折弦。丸发不至，道遇害患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '110101', '三女求夫，伺候山隅，不见复关，长思叹忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '101011', '阳旱炎炎，伤害禾谷。穑人无食，耕夫叹息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '010100', '骑豚逐羊，不见所望。径涉虎庐，亡羝失羔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '001010', '暗昧冥语，相传诖误。鬼魅所居，谁知卧处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '100011', '姬姜祥淑，而人偶食。论仁议福，以安王室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '110001', '公孙驾骊，载聘东齐。延陵说产，遗季纻衣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '011111', '孤竹之墟，失妇亡夫。伤于蒺藜，不见少妻，东郭棠姜，武氏以亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111110', '仁政不暴，凤凰来舍。四时顺节，民安其处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '011000', '任劣力薄，孱驽恐怯。如猬见鹊，不敢格拒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000110', '卫侯东游，惑于少姬。忘我考妣，久迷不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '011010', '噂噂所言，莫如我垣。欢喜坚固，可以长安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '010110', '鸑鸣岐山，鳖应山渊。男女构精，万物化生。文王以成，为开周庭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '011101', '玄黄虺隤，行者劳疲，役夫憔悴，逾时不归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '101110', '弱足钺跟，不利出门。市贾不利，折亡为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '001001', '悬貆素餐，居非其安。失舆剥庐，休坐徒居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '100100', '民怯城恶，奸人所伏。寇贼大至，入我邦城，妻子俘获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '110100', '阳低头，阴仰首，水为灾，伤我足，进不利，难生子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '001011', '背北相憎，心意不同，如火与金。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '001101', '太微帝室，黄帝所值。藩屏周卫，不可得入，常安无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '101100', '茧栗牺牲，敬享鬼神。神嗜饮食，受福多孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '110110', '出门逢恶，与祸为怨。更相击刺，伤我手端。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '011011', '鹢飞中途，举事不进，众人乱溃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '110010', '跛踦相随，日暮牛疲。陵迟后旅，失利亡雌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '010011', '龙角博颡，位至公卿。世禄长久，起动安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '110011', '舜升大禹，石夷之野。征诣王庭，拜治水土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '001100', '从风放火，荻芝俱死。三害集房，叔子中伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '010101', '梗生荆山，命制输班。袍衣剥脱，夏热冬寒。饥饿枯槁，众人莫怜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '101010', '长面大鼻，来解己忧。遗吾福子，与我惠妻，惠吾嘉喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '000000', '不风不雨，白日皎皎。宜出驱驰，通利大道。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111111', '谷风步气，万物出生。萌庶长养，华叶茂盛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '010001', '苍龙单独，与石相触。催折两角，室家不足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '100010', '城上有鸟，自名破家。招呼鸠毒，为国患灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '010111', '霜降闭户，蜇虫隐处。不见日月，与死为伍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111010', '天之德室，温仁手福。衣裳所在，凶恶不起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '000010', '皇陛九重，绝不可登。未见王公，谓天盖高。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '010000', '孔德如玉，出于幽谷。升高鼓翼，辉光照国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '110111', '五轭四轨，复得饶有。陈力就列，驺虞悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111011', '四足无角，君子所服。南征述职，以惠我国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '000111', '雷行相逐，无有攸息。战于平陆，为夷所覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111000', '六龙争极，服在下饰。谨慎管钥，结禁毋出。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111101', '长男少女，相向共语，福禄欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '101111', '奸延恶人，使德不通。炎火为殃，禾谷大伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '000100', '修其翰翼，随风向北，至虞夏国，与舜相得。年岁大乐，邑无盗贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '001000', '铅刀攻玉，坚不可得。尽我筋力，胝茧为疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '011001', '举被覆目，不见日月。衣裳簠簋，就长夜室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '100110', '贼仁伤德，天怒不福。斩刈宗社，失其邦域。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '000011', '白龙赤虎，战斗俱怒。蚩尤败走，死与鱼口。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '110000', '北辰紫宫，衣冠立中。含和建德，常受天福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '101001', '稷为尧使，西见王母。拜请百福，赐我善子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '100101', '三人异趣，反复迷惑。一身五心，乱无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '100000', '南山大玃，盗我媚妾。怯不敢逐，退而独宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '000001', '众鬼所趋，反作大怪。九身无头，魂惊魄去，不可以居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111001', '延头远望，眯为目疾。不见叔姬，使伯心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '100111', '典册法书，藏在兰台。虽遭乱溃，独不遇灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '100001', '自卫反鲁，时不我与。冰炭异室，仁道隔塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '011110', '瘤瘿秃疥，为身疮害。疾病癃残，常不远逮。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '010010', '东齐郭卢，嫁于洛都。俊良美好，媒利过倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '101101', '齐鲁争言，战于龙门。构怨连祸，三世不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '011100', '膏泽肥壤，农人丰敞。利居长安，历世无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '001110', '仓盈庾亿，宜种黍稷。年岁丰熟，民得安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111100', '鸱鸮破斧，邦人危殆。赖其忠德，转祸为福，倾危复立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '001111', '岁疾无年，虐政害民。乾溪骊山，秦楚结冤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '101000', '捯洁累累，缔结难解。嫫母衒嫁，媒不得坐，自为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '000101', '訾陬开门，鹤鸣弹冠，章甫进用，舞韶和鸾。三人翼事，国无灾患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '110101', '弟妹和居，与类相扶。愿慕群丑，不离其处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '101011', '邯郸反言，兄弟生患。涉叔忧恨，卒死不还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '010100', '三人逐兔，各争有得，爱亡善走，多获鹿子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '001010', '北辰紫宫，衣冠立中。含和建德，常受天福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '100011', '拜跪请免，不得其哺。俯首衔枚，低头北走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '110001', '鹤盗我珠，逃于东隅。求之郭嘘，不见所居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '011111', '一簧两舌，妄言谬语。三奸成虎，曾母投杼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111110', '孤独特处，莫与为旅。身日劳苦，使布五谷，阴阳顺序。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '011000', '褰衣涉河，涧流浚多。赖遇舟子，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '000110', '凭河登山，道路阻难，求事少便。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '011010', '兔罝之荣，不失其恭，和谦致乐，君子攸同。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '010110', '三女求夫，伺候山隅，不见复关，泣涕涟如。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '011101', '螟虫为贼，害我五谷。中溜空虚，家无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '101110', '望尚阿衡，太宰国公。藩屏辅弼，福禄来同。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '001001', '三年生狗，以戌为母。荆夷上侵，姬伯出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '100100', '途遏道塞，求事不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '110100', '探怀得蚤，无有凶忧，所愿失道，善居渐好。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '001011', '飞楼属道，趾多搅垣，居之不安，覆厌为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '001101', '义不胜情，以欲自倾，几危利宠，折角催颈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '101100', '潼翁蔚荟，扶首来会，津液来降，流淹滂霈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '110110', '白驹生刍，猗猗盛姝。赫喧君子，乐以忘忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '011011', '车驰人趋，卷甲相仇。齐鲁寇战，败于犬丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '110010', '举首望城，不见子贞，使我悔生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '010011', '龙斗时门，失理伤贤。内畔外贼，则生祸难。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '110011', '安如泰山，福喜屡臻。虽有豹虎，不致危身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '001100', '初忧后喜，与福为市。八佾列陈，饮御嘉友。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '010101', '持刀操肉，对酒不食。夫行从军，小子入狱，抱膝独宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '101010', '阴衰老极，阳建其德。履离戴光，天下昭明。功业不长，虾蟆代王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '010001', '兵征大宛，北出玉关。与胡寇战，平城道西，七日绝粮，身几不全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '111111', '泛泛柏舟，流行不休。耿耿寤寐，心怀大忧。仁不逢时，身隐穷居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '000000', '采薪得麟，大命陨颠。豪雄争名，天下四分。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '100010', '山崩谷绝，天福尽竭。泾渭失纪，玉历尽已。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '010111', '夏台羑里，汤文所厄。鬼侯俞贿，商王解舍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '111010', '泥津污辱，弃捐沟渎。所共笑哭，终不显录。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '000010', '李梅冬实，国多盗贼。扰乱并作，君不能息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '010000', '獐鹿逐牧，饱归其居。反还次舍，无有疾故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '110111', '夹河为婚，期至无船。摇心失望，不见所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '111011', '百足俱行，相福为强。三圣翼事，王室宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '000111', '坐位失处，不能自居。贼破王邑，阴阳颠倒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '111000', '登几上舆，驾驷南游。合纵散横，燕齐以强。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '111101', '三孙荷弩，无益于辅。城弱不守，邦君受讨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '101111', '河伯大呼，津不得渡。船空无人，往来亦难。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '000100', '甘露醴泉，太平机关。仁德感应，岁乐民安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '001000', '重茵厚席，循皋采藿。虽踬不惧，反复其宅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '011001', '太乙驾骝，从天上来。征我叔季，封为鲁侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '100110', '南巴六安，石解戟天。所指不已，耊老复丁。弊室旧嘘，更为新家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '000011', '家给人足，颂声并作。四夷宾伏，干戈韬阁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '110000', '东邻嫁女，为王妃后。庄公筑馆，以尊王母。归于京师，季姜悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '101001', '陈妻敬仲，兆兴齐姜。营丘是适，八世大昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '100101', '路多枳棘，步刺我足。不利旅客，为心作毒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '100000', '天官列宿，五神共舍。宫阙光坚，君安所居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '000001', '牧羊稻园，闻虎呻喧。惧畏惕息，终无祸患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '111001', '鸣条之图，北奔犬胡。左衽为长，国号匈奴。主君旄头，立尊单于。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '100111', '克身洁吉，逢禹巡狩，锡我玄圭，拜受福佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '100001', '冬华不实，国多盗贼。疾病难医，鬼哭其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '011110', '襄送季女，至于荡道。齐子旦夕，留连久处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '010010', '朽根倒树，花叶落去。卒逢火焱，随风偃仆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '101101', '阴变为阳，女化作男。治道得通，君臣相承。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '011100', '炎绝续光，火灭复明。简易理得，以成乾功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '001110', '多载重负，捐弃于野。予母谁子，但自劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '111100', '江河海泽，众利安宅，可以富有，饮御嘉客。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '001111', '冬采薇兰，地冻坚坼。利走室北，暮无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '101000', '乌鸣嘻嘻，天火将起。燔我室屋，灾及姬后。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '000101', '虿室蜂户，螯我手足。不可进取，为身害速。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '110101', '崔嵬北岳，天神贵客。温仁正直，主布恩德。闵哀不已，蒙受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '101011', '伯蹇叔盲，莫与守床。失我衣裘，伐民除乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '010100', '为季求妇，家在东海。水长无船，不见所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '001010', '山陵丘墓，魂魄失舍，精神尽竭，长寝不觉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '100011', '踦牛失角，下山伤轴，失其利禄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '110001', '水载船舟，无根以浮。往来溶溶，心劳且忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '011111', '有鸟来飞，集于古树。鸣声可恶，主将出去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '111110', '东徙不时，触患离忧。井泥无濡，思叔旧居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '011000', '黄帝所生，伏羲之宇。兵刃不至，利以居止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '000110', '东山救乱，处妇思夫。劳我君子，役无休已。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '011010', '跛踬未起，先利后市，不得鹿子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '010110', '大蛇当路，使季畏惧。汤火之灾，切近我肤。赖其天幸，趋于王庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '011101', '从容长闲，游戏南山。拜祠祷神，神使无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '101110', '区脱康居，慕义入朝。湛露之欢，三爵毕恩。复归野庐，与母相扶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '001001', '龟鳖列市，河海饶有。长钱山贾，商李悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '100100', '年常蒙庆，今岁受福。三夫采葩，出必有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '110100', '二人俱东，道路争讼。意乖不同，使君汹汹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '001011', '树我藿豆，鹿兔为食。君不恤护，秋无收入。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '001101', '黄鸟悲鸣，愁不见星。困于鸷鸟，鹯使我惊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '101100', '双凫俱飞，欲归稻食。经涉萑泽，为矢所射，伤我胸臆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '110110', '久客无依，思归我乡。雷雨盛溢，道未得通。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '011011', '道路僻除，南至东辽。卫子善辞，使国无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '110010', '同枕同袍，中年相知。少贾无失，独居愁思。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '010011', '众神集众，相与议语。南国虐乱，百姓愁苦。兴师征讨，更立贤主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '110011', '北陆闭蜇，隐伏不出。目盲耳聋，道路不通。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '001100', '痴狂妄作，心逛善惑。迷行失路，不知南北。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '010101', '栋隆辅强，宠贵日光。福善并作，乐以高明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010001', '101010', '爱我婴女，牵衣不与。冀幸高贵，反曰下贱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '100010', '何草不黄，至未尽玄。室家分离，悲愁于心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '111111', '海为水王，聪圣且明。百流归德，无有叛逆，常饶优足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '000000', '天之所有，祸不过家。左辅右弼，金玉满堂。常盈不亡，富如敖仓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '010001', '安息康居，异国穹庐。非吾习俗，使我心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '010111', '范公鸱夷，善贾饰资。东之营丘，易字子皮。把珠载金，多得利归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '111010', '老杨日衰，条多枯枝。爵级不进，遂下摧隤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '000010', '小狐渡水，污濡其尾。利得无几，与道合契。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '010000', '豕生鱼鲂，鼠舞庭堂。奸佞施毒，上下昏荒，君失其国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '110111', '天地配享，六位光明。阴阳顺序，以成和平。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '111011', '踝踵足伤，右指病痈。失旅后时，利走不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '000111', '异体殊患，各有所属。喜邻孤媪，欲寄我家。王母骂詈，求之不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '111000', '操稻乡亩，折祸稷黍。饮食充口，安利无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '111101', '所受大喜，福禄重来。乐且日富，蒙庆得财。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '101111', '举杯饮酒，无益温寒，指直失取，亡利不欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '000100', '日月指望，光明盛昌。三圣茂承，功德大隆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '001000', '猾夫争强，民去其乡。公孙叔子，战于城南。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '011001', '猿堕高木，不踒手足。还归其室，保我金玉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '100110', '逐狐东山，水遏我前。深不可涉，失利后便。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '000011', '凿井求玉，非卞氏宝。名困身辱，劳无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '110000', '黄玉温厚，君子所服。甘露溽暑，万物生茂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '101001', '画龙头颈，文章不成。甘言善语，说辞无名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '100101', '招祸致凶，来弊我邦。病在手足，不得安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '100000', '履位乘势，靡有绝毙。替为隶圉，与众庶伍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '000001', '獐鹿雉兔，群聚东囿。庐黄白脊，俱往趋逐。九齚十得，君子有喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '111001', '治金未成，纬画无名。长子逐兔，鹿起失路。后利不得，因无所据。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '100111', '天厌周德，命与仁国。以礼靖民，兵革休息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '100001', '重译贺芝，来除我忧。善说逐良，与喜相求。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '011110', '膏泽肥壤，人民孔乐。宜利俱止，长安富贵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '010010', '白龙黑虎，起鬐暴怒。战于涿鹿，蚩尤败走。居止不殆，君安其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '101101', '抱关传语，聋跛摧殆。众贱无下，灾殃所在。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '011100', '忧祸解除，喜至庆来。坐立欢门，与乐为邻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '001110', '折锋载殳，舆马放休。狩军依营，天下安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '111100', '至德之君，仁政且温。伊吕股肱，国富民安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '001111', '千里望城，不见山青。老兔虾蟆，远绝无家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '101000', '有莘季女，为夏妃后。贵夫寿子，母字四海。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '000101', '不虞之患，祸至无门。奄忽暴卒，痛伤我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '110101', '飞鹰退去，不食邻鸟。忧患解除，君主安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '101011', '跮蹉侧跌，申酉为祟。亥戌灭明，颜子隐藏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '010100', '司录凭怒，谋议无道。商民失政，殷人乏祀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '001010', '望鸡得雉，冀马获驹。大德生少，有廖从居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '100011', '忉忉怛怛，如将不活。黍稷之恩，灵辄以存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '110001', '莫莫辑辑，夜作昼匿。谋议我资，来攻我室。空尽我财，几无以食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '011111', '天之所坏，不可强支。众口指笑，虽贵必危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '111110', '目动睫瞤，喜来加身。举家蒙欢，吉利无殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '011000', '鼋羹芬香，染指弗尝。口饥于手，子公恨馋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '000110', '天福所丰，兆如飞龙。成子得志，六三以兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '011010', '氓伯以婚，抱布自媒。弃礼急情，卒罹悔忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '010110', '夏姬亲附，心听悦喜。利以搏取，无言不许。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '011101', '南山昊天，刺政闵身。疾悲无辜，背憎为仇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '101110', '三人为旅，俱归北海。入门上堂，拜谒王母。劳赐我酒，欢乐无强。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '001001', '愆淫旱疾，伤害稼穑。丧制病来，农人无食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '100100', '攫饭把肉，以就口食。所往必得，无有虚乏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '110100', '鸟飞无翼，兔走折足。虽欲会同，未得所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '001011', '体重飞难，不得逾关，不离室垣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '001101', '四雄并处，人民愁苦。拥兵西东，不得安所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '101100', '译重关牢，求解己忧。心感乃成，与喜俱居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '110110', '患解忧除，王母相于。与喜俱来，使我安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '011011', '冬生不华，老女无家。霜冷蓬室，更为枯株。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '110010', '震栗恐惧，多所畏恶。行道留难，不可以步。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '010011', '三人共妻，莫适为雌。子无名氏，公不可知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '110011', '早凋被霜，花叶不长。非时为灾，家受其殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '001100', '雉兔之东，狼虎所从，贪叨凶恶，不可止息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '010101', '马惊破车，主坠深沟。身死魂去，离其室庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100010', '101010', '山林麓薮，非人所往。鸟兽无礼，使我心苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '010111', '久旱三年，草木不生。粢盛空乏，无以供灵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '111111', '火灭复息，君明其德，仁人可遇，身受利福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '000000', '温山松柏，常茂不落。鸾凤所庇，得其欢乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '010001', '西诛不复，恃强负力。倍道趋敌，师徒败覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '100010', '三涂五岳，阳城太室，神明所伏，独无兵革。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '111010', '三牛生狗，以戌为母。荆夷上侵，姬伯出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '000010', '凫游江海，役行千里。以为死亡，复见空素。长主凶忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '010000', '太乙驾骝，从天上来，征君叔季，封为鲁候，无有凶忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '110111', '纴绩独居，寡处无夫。阴阳失忘，为人仆使。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '111011', '兵征大宛，北出玉门。与胡寇战，平城道西。七日绝粮，身几不全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '000111', '楚灵暴虐，疲极民力。祸起乾溪，弃疾作毒。扶仗奔逃，身死亥室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '111000', '雌单独居，归其本巢。毛羽憔悴，志如死灰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '111101', '两矛相刺，勇力钧敌。交绥结如，不破不缺。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '101111', '乘船渡济，载水逢火。赖幸免祸，蒙我生全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '000100', '丧宠溢尤，政倾家覆。我宗失国，秦灭周室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '001000', '冬无藏冰，春阳不通。阴流为贼，国被其殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '011001', '田鼠野鸡，意常欲逃。拘制笼槛，不得动摇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '100110', '佩玉蕊兮，无所系之。旨酒一壶，莫与笑语。孤寡独特，常愁忧苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '000011', '没游源口，求鲛为宝。家危自俱，复出生道。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '110000', '河水孔穴，坏败我室。水深无岸，鱼鳖倾侧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '101001', '教羊牧兔，使鱼捕鼠。任非其人，费日无功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '100101', '升户入室，就温燠食。冰冻北陆，不能相贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '100000', '孤竹之嘘，老妇无夫。伤于蒺藜，不见少妻。东郭棠姜，武氏破亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '000001', '凶祸灾殃，日益明彰。福不可剺，三郄夷伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '111001', '载璧秉珪，请命于河。周公作誓，冲人瘳愈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '100111', '鸟升鹊举，照临东海。龙降庭坚，为陶叔后。封圻英六，履禄绥厚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '100001', '危坐至暮，请求不得。膏泽不降，政戾民忒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '011110', '宜昌娶妇，东家歌舞。宴乐有序，长乐嘉喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '010010', '凿井求玉，非卞氏宝。名因身辱，劳无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '101101', '鸿鹄思其雄，欲随凤东。顺理羽翼，出次须日。中留北邑，复反其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '011100', '早霜晚雪，伤害禾麦。损功弃力，饥无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '001110', '蝙螺生子，深目黑丑。虽饰相就，众人莫取。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '111100', '去如飞鸿，避凶直东。遂得全脱，与福相逢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '001111', '婚姻合配，同枕共牢，以降休嘉，子孙封候。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '101000', '咸阳辰巳，长安戌亥。丘陵生止，非鱼鳅市。不可辞阻，终无悔咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '000101', '螟虫为贼，害我五谷。箪食空虚，家无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '110101', '谋恩拜德，东归吾国。慷慨宴笑，欢乐有福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '101011', '斋具赎狸，不听我辞。系于虎须，牵不得来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '010100', '比目附翼，欢乐相得。行止集周，终不离忒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '001010', '一指食肉，口无所得。染其鼎鼐，舌馋于腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '100011', '曳纶江海，钩挂鲂鲤。王孙得利，以享仲友。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '110001', '商纣牧野，颠败所在。赋敛重数，黎元愁苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '011111', '北辰紫宫，衣冠立中。含和建德，常受天福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '111110', '轻战尚勇，不知兵权。为敌所制，从师北奔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '011000', '大口宣舌，神使仲言。黄龙景星，出应德门。与福上天，天下安昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '000110', '凶子祸孙，把剑向门。凶讼欢嚣，惊骇我家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '011010', '祝伯善言，能事鬼神。辞祁万岁，使君延年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '010110', '圭璧琮璋，执贽见王。百里宁戚，应聘齐秦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '011101', '昧旦乘车，履危蹈沟。亡失裙襦，催折两轴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '101110', '胶着木连，不出牛栏。斯飨羔羊，家室相安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '001001', '卷领遁世，仁德不舍。三圣攸同，周家茂兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '100100', '黍稷苗稻，垂秀方造，中旱不雨，伤风枯槁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '110100', '冠带南游，与福喜逢。期于嘉贞，拜为公卿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '001011', '一巢九子，同公共母。柔顺利贞，出入不殆，福禄所在。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '001101', '韩氏长女，稼于东海。宜家富主，柔顺以居。利得过倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '101100', '因祸受福，喜盈我室，所愿必得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '110110', '晋平有疾，迎医秦国。病乃大患，分为两竖。逃匿膏盲，和不能愈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '011011', '牡飞门启，忧患大解。修福行善，不为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '110010', '追亡逐北，至止而得。雉叔相呼，反其室庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '010011', '鸟铭既端，一呼三颠。动摇东西，危栗不安。疾病无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '110011', '龙化为虎，泰山之阳。众多从者，莫敢救藏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '001100', '焱风忽起，车驰揭揭。弃名追亡，失其和节，忧心辍辍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '010101', '游居石门，禄安身全。受福西邻，归饮玉泉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010111', '101010', '登高上山，见王自言。申理我馋，得职蒙恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '111010', '文巧俗弊，将反大质。僵死如麻，流血濡橹。皆知其母，不识其父，干戈乃止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '111111', '文王四乳，仁爱笃厚。子畜十男，夭折无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '000000', '日入望东，不见子家。长女无夫，左手搔头。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '010001', '东上泰山，见尧自言。申理我冤，以解忧患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '100010', '奎轸温汤，过角宿房。宣时布和，无所不通。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '010111', '饮船牵头，虽拘无忧。王母善祷，祸不成灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '000010', '凫得水没，喜笑自啄。毛羽悦泽，利以攻玉。公出不复，伯氏客宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '010000', '水流趋下，欲至东海。求我所有，买鲂与鲤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '110111', '獐鹿逐牧，安饱其居。反返次舍，无有疾故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '111011', '树植藿豆，不得芸锄。王事靡盬，秋无所收。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '000111', '弱水之西，有西王母。生不知死，与天相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '111000', '数穷廓落，困于历室。卒登玉堂，与尧侑食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '111101', '子鉏执麟，春秋作元。阴圣将终，尼父悲心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '101111', '尹氏伯奇，父子生离。无罪被辜，长舌所为。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '000100', '播木折枝，与母别离。九皋难扣，绝不相知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '001000', '弱鸡无距，与鹊格斗。翅折目盲，为鸠所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '011001', '甲乙丙丁，俱归我庭。三丑六子，入门见母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '100110', '桑叶螟蠹，衣弊如络。女工不成，丝布为玉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '000011', '开牢辟门，巡狩释冤。夏台羑里，汤文悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '110000', '钦明之德，坐前玉食。必保嘉美，长受安福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '101001', '武夫司空，多口争讼。金火当户，民不安处，年饥无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '100101', '紫阁九重，尊严在中。黄帝尧舜，履行至公。冠带垂衣，天下康宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '100000', '负牛上山，力劣行难。烈风雨雪，遮遏我前。中道复还，忧苦自欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '000001', '褰兔缺唇，行难齿寒，口痛不言，为身生患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '111001', '合体比翼，嘉耦相得，与君同好，使我有福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '100111', '口啄卒卒，忧从中来。丧我宝贝，妻妾失位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '100001', '两心不同，或从西东。明论终日，莫适相从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '011110', '哑哑笑言，与善饮食。长乐行觞，千秋起舞，拜受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '010010', '初忧后喜，与福为市。八佾列陈，饮御诸友。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '101101', '西徙无家，破其新车。王孙失利，不如止居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '011100', '凤凰在左，麒麟处右。仁圣相遇，伊吕集聚。时无殃咎，福为我母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '001110', '区脱康居，慕仁入朝。湛露之欢，三爵毕恩，复归旧庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '111100', '疾贫望幸，使伯行贩。关牢择羊，多得大牂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '001111', '处高不伤，虽危不亡。握珠怀玉，还归其乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '101000', '右手弃酒，左手牧牂。行逢礼御，饵得玉杯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '000101', '养虎牧狼，还自贼伤。大勇小捷，虽危不亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '110101', '戴尧扶禹，松乔彭祖。西遇王母，道路夷易，无敢难者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '101011', '秋冬探巢，不得鹊雏。衔指北去，愧我少姬。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '010100', '两羝三牂，俱为代乡。留连多难，损其食粮。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '001010', '南徙无庐，鸟破其巢。伐木思初，不利动摇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '100011', '争讼不已，更相击剑。张季弱口，被发北走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '110001', '延颈望酒，不入我口。初喜后否，得利无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '011111', '被发倾走，寇逐我后。亡失刀兵，身全不伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '111110', '麒凤所游，安乐无忧。君子抚民，世代千秋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '011000', '褰衣涉河，水深渍疲。赖幸舟子，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '000110', '愦愦不悦，忧从中来。丧我金罂，无妄失位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '011010', '绊跳不远，心与言反。尼父望家，萏菡未华。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '010110', '大壮肥牸，惠我诸舅。内外和睦，不忧饥渴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '011101', '黄帝建元，文德在身。禄若阳春，封为鲁君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '101110', '虎聚摩牙，以待臀猪。往必伤亡，宜利止居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '001001', '天地配享，六位光明。阴阳顺序，以成和平。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '100100', '猿堕高木，不踒手足。保我金玉，还归其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '110100', '营室紫宫，坚不可攻。明神建德，君受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '001011', '孤翁寡妇，独宿悲苦。目张耳鸣，无与笑语。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '001101', '低头窥视，有所畏避。行者不利，酒酸鱼败，众莫贪嗜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '101100', '载金贩狗，利弃我走。藏匿渊底，悔折为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '110110', '行触大忌，与司命牾，执囚束缚，拘制于吏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '011011', '执玉欢喜，配之解挛。危详及安，使我无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '110010', '机杼纷扰，女功不成。长妹许嫁，衣无襦绔。闻祸不成，凶恶消去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '010011', '金人铁距，火烧左右。虽俱不恐，独得全处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '110011', '谢恩拜德，东归吾国。舞蹈欣悦，欢乐受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '001100', '青牛白咽，呼我俱田，历山之下，可以多耕。岁乐时节，人民安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '010101', '白雉群雎，慕德朝贡。湛露之恩，使我得欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111010', '101010', '避患东西，反入祸门。糟糠不足，忧愁我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '000010', '乌鸣呼子，哺以酒脯。高楼之处，子来归母。穑人成功，年岁大有，妒妇无子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '111111', '一簧两舌，佞言谄语。三奸成虎，曾母投杼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '000000', '春桃生花，季女宜家。受福且多，在师中吉，男为封君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '010001', '殊类异路，心不相慕。牝牛牡猳，独无家室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '100010', '折叶蔽目，不见稚叔。三足孤鸟，远其元夫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '010111', '雀东求粒，误入网域。赖逢君子，脱复归息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '111010', '王孙季子，相与孝友。明允笃诚，升擢荐举，为国干辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '010000', '削树无枝，与子分离。饥寒莫食，独泣哀悲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '110111', '舜生大禹，石夷之野。征诣玉阕，拜理水土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '111011', '义不胜情，以欲自营。见利危宠，灭君令名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '000111', '三人北行，六位光明。道逢淑女，与我骥子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '111000', '弈张乌号，彀射天狼。柱国雄勇，斗死荥阳。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '111101', '季姬踯躅，结衿待时。终日至暮，百两不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '101111', '鸿雁翩翩，始怨劳苦。灾疫病民，鳏寡愁忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '000100', '穿胸狗邦，僵离旁舂。天地易纪，日月更始。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '001000', '北山有枣，使叔寿考。东岑多栗，宜行贾市，陆梁雌雉，所至利喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '011001', '干旄旌旗，抚帜在郊。虽有宝玉，无路致之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '100110', '精洁渊塞，为馋所言。证讯诘请，系于枳温。甘棠听断，怡然蒙恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '000011', '玄黄虺隤，行者劳疲。役夫憔悴，逾时不归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '110000', '肤敏之德，发愤忘食。虏豹禽说，以成主德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '101001', '采唐沫乡，要我桑中。失信不会，忧思约带。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '100101', '伯宁子福，惠我邦国。蠲除苛残，使季无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '100000', '馋父佞雄，贼乱邦国。生虽忠孝，败恩不福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '000001', '渊泉堤防，水道通利。顺注湖海，邦国富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '111001', '江南多蝮，螫我手足。冤繁诘屈，痛彻心腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '100111', '三人俱行，别离独食。一身五心，反复迷惑，乱无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '100001', '鸦鸣庭中，以戒灾凶。重门击柝，备不速客。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '011110', '功成事就，拱手安居。立德有言，坐饰贡赋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '010010', '国乱不安，兵革为患。掠我妻子，家中饥寒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '101101', '戴尧扶禹，从乔彭祖。西遇王母，道路夷宜，无敢难者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '011100', '长尾委蛇，画地成河。深不可涉。绝无以比，惆怅会息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '001110', '乘龙从蜺，征诣北阕。乃见宣室。拜守东城。镇慰黎元，举家蒙富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '111100', '土与山连，终身无患。天地高明，万岁长安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '001111', '久旱水涸，枯槁无泽。虚修其德，未有所获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '101000', '依天倚地，凶危不至。上清下净，受福大明，君受其利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '000101', '火烈不去，必殪僵仆。燔我衣裾，福不可悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '110101', '配合相迎，利之四乡。欣喜心释，所言得当。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '101011', '清人高子，久屯外野。道遥不归，思我慈母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '010100', '武库军府，甲兵所聚，非里邑居，不可舍止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '001010', '三德五材，和合四时。阴阳顺序，国无咎灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '100011', '解衣毛羽，飞入大都。晨门戒守，郑忽失家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '110001', '削根烧株，不生肌肤。病在心腹，日以焦枯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '011111', '文山紫芝，雍梁朱草。生长和气，福禄来处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '111110', '多栽重负，捐弃于野。予母谁子，但自劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '011000', '凫雁哑哑，以水为家。雌雄相和，心志娱乐，得其欢欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '000110', '耳目盲聋，所言不通。伫立以泣，事无成功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '011010', '天宫列宿，五神所舍。宫阙坚固，君安其居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '010110', '范子妙材，戮辱伤肤，然后相国，封为应侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '011101', '秋冬探巢，不得鹊雏。衔指北去，惭我少夫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '101110', '子畏于匡，厄困陈蔡。德行不危，竟脱厄害。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '001001', '鸿飞在陆，公出不复。仲氏任止，伯氏客宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '100100', '鹤鸣九皋，避世隐居。抱朴守真，竟不随时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '110100', '舜升大禹，石夷之野。征诣玉阕，拜治水土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '001011', '左辅右弼，金玉满匮。常盈不亡，富如厫仓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '001101', '崔嵬北岳，天神贵客。衣冠不已，蒙被恩德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '101100', '空巢注猪，獖彘不到。张弓祝鸡，雄父飞去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '110110', '胡蛮戎狄，大阴所积，涸冻冰寒，君子不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '011011', '甘露醴泉，太平机关。仁德感应，岁乐民安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '110010', '恶来呼伯，慎惊外客。甲守闭宅，以备凶急。临折之忧，将灭无灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '010011', '日月相望，光明盛昌。三圣茂功，仁德大隆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '110011', '葛藟蒙棘，华不得实。馋佞乱政，使恩壅塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '001100', '邻不我顾，而望玉女。身多癞疾，谁肯媚者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '010101', '精诚所至，神为之辅。德教尚忠，弥世长久。三圣尚功，多受福祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000010', '101010', '钻木取火，掘地索泉。主母饥渴，手为心福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '010000', '鹿得美草，鸣呼其友。九族和睦，不忧饥乏。长子入狱，霜降族哭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '111111', '继祖复宗，追明成康。光照万国，享世长久。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '000000', '麒子凤雏，生长家国。和气所居，康乐无忧，邦多圣人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '010001', '取火流泉，钓鳑山颠。鱼不可得，火不肯燃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '100010', '彭生为娱，白虎行乾。盗尧衣裳，桀跖荷兵。青禽照火，三日夷伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '010111', '黍稷醇醴，敬奉山宗。神嗜饮食，甘雨嘉降。黎庶蕃殖，独蒙福祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '111010', '李花再实，鸿飞降集。仁哲权舆，荫国受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '000010', '千岁之墟，大兵所屠。不见子都，城空无家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '110111', '公子王孙，把弹摄丸。发辄有得，室家饶足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '111011', '骊姬馋喜，与二嬖谋，谮杀恭子，贼害忠孝。申生以缢，重耳奔逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '000111', '长生无极，子孙千亿。柏柱栽青，坚固不倾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '111000', '失意怀忧，如幽狴牢。亡子丧夫，附托寄居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '111101', '仁智隐伏，麟不可得。龙蛇潜藏，虚居堂室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '101111', '列结累累，缔结难解。嫫母衒嫁，媒不得坐，自为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '000100', '蜩飞坠木，不毁头足。保我羽翼，复归其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '001000', '陈妫敬仲，兆兴齐姜。乃适营丘，八世大昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '011001', '过时不归，雌雄苦悲。徘徊外国，与母分离。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '100110', '齐鲁争言，战于龙门。构怨结祸，三世不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '000011', '府藏之富，王以赈贷。捕鱼河海，苟愿多得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '110000', '鸣鹤北飞，下就稻池。鳣鲔鳇鲤，众多饶有，一狗获两，利得过倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '101001', '苍梧郁林，道易利通。元龟象齿，宝贝南金，为吾福功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '100101', '两火争明，虽斗不伤。分离且忍，全我弟兄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '100000', '伯夷叔齐，贞廉之师。以德防患，忧祸不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '000001', '季去我东，发栉如蓬。展转空床，内怀忧伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '111001', '百足俱行，相辅为强。三圣翼事，王室宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '100111', '壅遏堤防，水不得行。火盛阳光，阴霓伏藏，退还其乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '100001', '滕蛇乘龙，年岁饥凶，民食草蓬。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '011110', '铅刀攻玉，坚不可得。尽我筋力，胝茧为侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '010010', '恒山浦寿，高邑所在。阴气下淋，洪水不处，牢人开户。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '101101', '比目四翼，来安我国。福善上堂，与我同床。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '011100', '杜口结舌，心中怫郁。去菑患生，莫告所冤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '001110', '牵尾不前，逆理失臣，忠莫往来，惠朔以奔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '111100', '早霜晚遁，伤害禾麦。损功弃力，饥无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '001111', '适戌失期，患生无聊。惧以发忧，发藏闭塞，邦国骚愁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '101000', '昊天白日，照临我国。万民康乐，咸赖嘉福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '000101', '元吉无咎，安宁不殆。时行则行，勿之有悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '110101', '懿公浅愚，不深受谋。无援失国，为狄所贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '101011', '城上有乌，自号破家。呼唤鸠毒，为国患灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '010100', '长股善走，趋步千里。王良嘉言，伯来在道。申见王母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '001010', '耕石山颠，费种家贫。无聊处作，苗发不生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '100011', '二人异步，东趋西步。千里之行，不相知处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '110001', '纯服黄裳，栽土以兴。德义茂生，天下归仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '011111', '五铣铁颐，仓库空虚。贾市无盈，与利为仇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '111110', '登昆仑，入天门，过糟丘，宿玉泉，问惠观，见仁君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '011000', '团团白日，为月所食。损上毁下，郑昭出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '000110', '仓盈庾亿，宜稼黍稷。年岁有息，国家富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '011010', '虎狼结谋，相聚为保。伺啮牛羊，道绝不通，伤我商人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '010110', '木年催折，常恐不活。老赖福庆，光荣辅相。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '011101', '同载共车，中道分去。丧我元夫，独为孤苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '101110', '饮酒醉酗，跳跃争斗，伯伤叔疆，东家治丧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '001001', '出值凶灾，逢五赤头，跳言死格，扶杖伏听，不敢动摇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '100100', '狼虎争强，利义不行。兼吞其国，齐晋无主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '110100', '南国少子，方略美好。求我长女，薄贱不与。反得丑恶，后乃大悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '001011', '一身两头，莫适其躯。乱不可治，孰为汤汉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '001101', '李耳汇鹊，更相恐怯，偃而以腹，不能距格。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '101100', '松柏栋梁，相辅为强。八哲五教，王室康宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '110110', '雀行求食，暮归孚乳。反其屋室，安宁如故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '011011', '四尾六头，为凶作妖。阴不奉阳，上失其明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '110010', '一衣三阕，结缉不便。岐道异路，日暮不到。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '010011', '牙蘖生齿，室堂启户。幽人利贞，鼓翼起舞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '110011', '春鸿飞东，以马至金。利得十倍，重载归乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '001100', '欢悦以喜，子孙俱在。守发能忍，不见殃咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '010101', '精神消落，形骸丑恶。龉齚顿挫，枯槁腐蠹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010000', '101010', '登高上山，见王自言。申理我冤，得职梦恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '110111', '白鸟衔饵，鸣呼其子。斡枝张翅，来从其母。伯仲叔季，尤贺举手。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '111111', '东遇虎地，牛马奔惊。道绝不通，南困无功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '000000', '子鉏执麟，春秋作元。阴将以终，尼父悲心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '010001', '取火泉源，钓鱼山颠。鱼不可得，火不肯燃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '100010', '机关不便，不能出言。精诚不通，为人所冤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '010111', '故室旧庐，稍弊且徐。不如新巢，可治乐居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '111010', '蛇循流，东求大鱼。预且举网，庖人歌讴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '000010', '凿山通道，南至嘉国。周公祝祖，襄适荆楚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '010000', '鹊近却缩，不见头目。日以困急，不能自复。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '111011', '五舌啄难，各自有言。异国殊俗，使心迷惑，所求不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '000111', '天门开辟，牢户寥阔。桎梏解脱，拘囚纵释。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '111000', '坚冰黄鸟，常哀悲愁。数惊鸷鸟，雏为我忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '111101', '日走月步，娶不同舍。夫妻反目，主君失居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '101111', '金牙铁齿，西王母子。无有患殃。扶舍徙道，到来不久。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '000100', '式微式微，忧祸相半。隔以岩山，室家分散。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '001000', '众神集聚，相与议语。南国虚乱，百姓劳苦。兴师征伐，更立贤主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '011001', '狼虎争食，礼义不行。兼吞其国，齐鲁无主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '100110', '寄生无根，如过浮云。本立不固，斯须落去，更为枯树。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '000011', '子啼索哺，母行求食。反见空巢，长息訾弋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '110000', '驾驷逐狐，轮挂荆棘。车不结辙，公子无得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '101001', '方喙广口，仁智圣厚。释解倒悬，唐国太安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '100101', '驾福乘西，来至家国。戴庆南行，离我安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '100000', '孔鲤伯鱼，北至高奴，木马金车，驾游大都，王母送我，来牝字驹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '000001', '三足无头，不知所之。心狂精伤，莫使为明，不见日光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '111001', '来牝龙身，日驭三千，南止苍梧，与福为婚。道里夷易，安全无忌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '100111', '辰次降娄，王驾巡时。广佑施惠，安国无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '100001', '望幸不到，文章来就。王子逐走，马骑衔伤。昳迹不得，曷其有常。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '011110', '中原有菽，以待饔食。饮御诸友，所求大得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '010010', '乱茅缩酒，灵巫拜祷。神怒不许，瘁愁忧苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '101101', '李华再实，鸿卵降集。仁哲以幸，荫国受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '011100', '源出陵足，行于山趾。不为暴害，民得安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '001110', '客人其门，奔走东西。童女不织，士奇耕亩。暴骨千里，岁寒无年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '111100', '天之所予，福禄常在。以永康宁，不忧危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '001111', '蝗食我稻，驱不可去。实穗无有，但见空藁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '101000', '牛骥同堂，郭氏已亡。国破空虚，君奔走逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '000101', '狗无前足，阴谋其比。为身贼害，何以安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '110101', '两轮自转，南上大阪。四马共辕，无有重难。与禹笑言。鹤鸣窍穴，不离其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '101011', '芽蘖生达，阳昌于外。左手执籥，公言锡爵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '010100', '秋花冬萼，数被严霜。甲兵当庭，万物不生。雄犬夜鸣，民扰大惊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '001010', '霜降必户，蜇虫隐处。不见日月，与死为伍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '100011', '身载百里，功加四海。为文开基，武立大柱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '110001', '禹作神鼎，伯益衔指。斧斤高阁，憧位独坐。卖庸不售，苦困为祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '011111', '福祚之家，喜至忧除。如风兼雨，出车入鱼。如鱼逢水，长乐受庇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '111110', '苍龙隐伏，麟凤远匿。寇来同处，未得安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '011000', '旦生夕死，名曰婴鬼，不可得视。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '000110', '白鹤衔珠，夜食为明。怀安德音，身受光荣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '011010', '行役未已，新事复起。姬姜劳苦，不得休息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '010110', '忧患解除，喜至庆来。坐立欢欣，与乐为邻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '011101', '晨风指翰，大举就温，昧过我邑，弈无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '101110', '下田稷黍，芳华生齿。大于集降，纷涝满瓮。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '001001', '君子碌碌，鸟庇茂木。见春百谷，心劳愿德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '100100', '折臂踒足，不能进酒。祠祀阔旷，神怒不喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '110100', '学灵三年，圣且神明。光见善祥，吉喜福庆。鸣鸠飞来，告我无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '001011', '三妇同夫，志不相思。心怀不平，志常愁悲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '001101', '中田膏黍，以享王母。受福千亿，所求大得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '101100', '阳火不灾，喜至庆来。降福送喜，鼓琴歌讴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '110110', '阳明不息，君无恩德。伯氏失利，农丧其力。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '011011', '燕雀衔茅，以生孚乳。兄弟六人，姣好孝悌。各得其愿，和悦相乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '110010', '鹑尾奔奔，火中成军。虢叔出奔，下失其君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '010011', '两人相距，止不同舍。夫妻立散，卫侯失居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '110011', '魃为燔虐，风吹云却。欲止不得，反鬼其宅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '001100', '关雎淑女，佩我君子。少妻在门，君子嘉喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '010101', '慈母赤子，飨赐得士。夷狄服除，以安王家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110111', '101010', '三足孤鸟，灵鸣督卸。思过罚恶，自贼其家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '111011', '十乌俱飞，弈射九雌。雄得独全，虽惊不危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '111111', '东向藩垣，相与笑言。子般执鞭，圉人作患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '000000', '循河樀舟，旁淮东游。渔夫举网，先得大鳅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '010001', '辕折轮破，马倚仆卧。后旅先宿，右足跌踒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '100010', '两人相伴，相与悖戾。心乖不同，争讼凶凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '010111', '北辰紫宫，衣冠立中。含和建德，常受天福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '111010', '游居石门，禄祉安全。受福西邻，归饮玉泉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '000010', '羊肠九萦，相推并前。止须王孙，乃能上天。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '010000', '争讼相倍，和气不处。阴阳俱否，谷风母子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '110111', '郭叔矩颐，为棘所拘。龙额重颡，祸不成殃，复归其乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '000111', '虿室蜂户，螯我手足。不得进止，为吾害咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '111000', '怒非其愿，因物有迁。贪妬腐鼠，而呼鸮鸢。自合失饵，到掖困患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '111101', '婴孩求乳，母归其子。黄麑悦喜，自乐甘饵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '101111', '针缕徒劳，锦绣不成。鹰逐雉突，爪折不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '000100', '雨潦集降，河渠不通。齐鲁闭塞，破费市空。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '001000', '封豕沟渎，水潦空谷。客止舍宿，泥涂至腹，处无黍稷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '011001', '三奸相扰，桀跖为友。上下骚离，隔绝天道。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '100110', '齐景惑疑，为孺子牛。嫡庶不明，贼孽为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '000011', '三羊俱亡，走奔南行。会暮失迹，不知所藏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '110000', '请伯行贾，岱山之野，夜历险阻，不逢危殆，利如浇酒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '101001', '桑之将落，殒其黄叶。失势倾侧，而无所立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '100101', '上山求鱼，入水捕兔。市非其归，自令久留。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '100000', '名成德就，项领不试。景公耋老，尼父逝去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '000001', '天之奥隅，尧舜所居。可以存身，保我邦家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '111001', '雎鸠淑女，贤圣配偶。宜家寿福，吉庆长久。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '100111', '两人俱争，莫能有定。心乖不同，讼言起凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '100001', '涉伯殉名，弃礼诛身。不得其道，成子奔燕。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '011110', '逾江求橘，并得大栗。烹羊食肉，饮酒歌笑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '010010', '山险难升，涧中多石，车驰轊击，重伤载轴，担负善踬，跌豕手足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '101101', '元利孔福，神所子畜。般乐无苦，得其欢欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '011100', '乌鹊食谷，张口受哺。蒙被恩福，长大成就。柔顺利贞，君臣合德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '001110', '潼滃蔚荟，肤寸来会。津液下降，流潦滂沛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '111100', '路多枳棘，步刺我足。不利旅客，为心作毒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '001111', '虺蝮所聚，戏以居处。毒螯痛甚，疮不可愈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '101000', '麟凤相随，观察安危。东郭圣人，后稷周公。共和政令，君子攸同。利以居止，长无忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '000101', '桀乱不时，使民恨忧。立祉为笑，君危臣羞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '110101', '黄帝所生，伏羲之宅。兵刃不至，利以居止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '101011', '雀行求食，暮归屋宿。反其室舍，安宁无故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '010100', '太仓积谷，天下饶食。阴阳调和，年岁时熟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '001010', '干旄旌旗，执帜在郊。虽有宝玉，无路致之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '100011', '履危蹈颠，坠入泉渊。蹇不能前，足踒不便。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '110001', '衔命上车，合和两家。峨眉皓齿，二国不殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '011111', '吉日车攻，田弋获禽。宣王饮酒，以告嘉功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '111110', '金帛贵宝，宜与我市。嫁娶有恩，得利过倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '011000', '延颈望酒，不入我口。深以自喜，得利无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '000110', '牧为代守，飨食甘赐。德利士意，战大破胡，长安国家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '011010', '日出温谷，照临万国。高明淑仁，虞夏配合。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '010110', '逐兔索乌，破我弓车。日暮不及，失利后时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '011101', '讹言妄语，传相诖误。道左失迹，不知户处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '101110', '履虎蹑尾，贬损我威。君子失否，去其国家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '001001', '本跟不固，新花落去。更为孤妪，不得相视。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '100100', '五轭四国，优得饶有。陈力就列，驺虞悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '110100', '黄帝紫云，圣哲且神，光明见祥，告我无殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '001011', '五利四福，俱田高邑。黍稷盛茂，多获藁稻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '001101', '群虎入邑，求索肉食。大人卫守，君不失国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '101100', '乌子鹊雏，常与母居。愿慕群侣，不离其巢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '110110', '蹇驴不材，骏骥失时。筋老力尽，疲于沙丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '011011', '玄鬣黑颡，东归高乡。朱鸟道引，灵龟载庄。遂抵天门，见我贞君，人马安全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '110010', '探巢得雏，鸠鹊俱来，使我欣娱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '010011', '安上宜官，一日九迁，升擢超等，牧养常山，君臣获安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '110011', '大头目明，载受嘉福。三雀飞来，与禄相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '001100', '远视千里，不见黑子。离娄之明，无益于光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '010101', '三女成奸，背夫夜行，与伯笑言，不忍王母，为失醴酒，冤天谁告。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111011', '101010', '日辰不良，强弱相振，一鸟两离，客胜主人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '000111', '有求陈国，留连东域，须我王孙，四月来复。主君有德，蒙受恩福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111111', '伯夷叔齐，贞廉之师。以德防患，忧祸不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '000000', '济深南渡，濡我衣袴。五子善擢，脱无他故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '010001', '倚立相望，适我道通，驱驾奔驰，比目同创。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '100010', '葛藟蒙棘，花不得实。馋佞为政，使恩壅塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '010111', '四并兼用，君子所服。南征述职，与福同德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111010', '踝踵足伤，大指病痈。失旅后时，利走不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '000010', '春称夏国，生长之域。可以服食，保全家国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '010000', '望骥不来，驹蹇为忧。雨惊我心，风撼我肌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '110111', '久客无床，思归故乡。雷雨浸盈，道不得通。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111011', '方船备水，傍河燃火。积善有征，终身无祸。田福吉昌，永得安康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111000', '徙岵望母，役事未已。王政靡盐，不得相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111101', '多载重负，捐弃于野。王母离子，思劳自苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '101111', '生值地乳，上皇大喜。赐我福祉，寿算无极。宾于作命。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '000100', '翕翕軥軥，稍坠山颠。灭我令名，长没不全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '001000', '东邻嫁女，为王妃后。庄公筑馆，以尊王母。归于京师，季姜悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '011001', '伯虎仲熊，德义渊闳。使布五谷，阴阳顺叙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '100110', '敏捷劲疾，如猿升木。彤弓虽调，终不能获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '000011', '举袂覆目，不见日月。衣裘簟床，就长夜室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '110000', '忍丑少羞，无面有头。耗见寡虚，日以削酒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '101001', '固阴冱塞，长冰不温，令人隳殆，庖火为灾，电火为蕃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '100101', '夏麦麸曲，霜击其芒。疾君败国，使民夭伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '100000', '渊涸龙忧，箕子为奴。干叔陨命，殷破其家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '000001', '跛踦相随，日暮牛罢。陵迟后旅，失利亡雌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111001', '桑之将落，陨萁黄叶。失势倾侧，如无所立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '100111', '长生以时，长柱根本。阴阳相和，岁乐无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '100001', '童女无室，未有配合。阴阳不和，空坐独宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '011110', '春令原宥，仁德不周。三圣攸同，周国茂兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '010010', '金景耀怒，带剑过午。两虎相距，虽惊无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '101101', '危坐至暮，谋求不得。膏泽不降，政戾民忒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '011100', '老杨日衰，条多枯枝。爵级不进，日下摧颓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '001110', '蔡侯适楚，留连江湖。逾日历月，思其后君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111100', '右抚剑头，作援钩带，凶讼不止，相与争戾，失利市肆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '001111', '水流趋下，远至东海。求我所有，买鲔与鲤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '101000', '登几上舆，驾驷南游，合纵散衡，燕寝以强。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '000101', '求兔得獐，过其所望。欢一相迎，高位夷伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '110101', '过时不归，道远且迷。旅人心悲，使我徘徊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '101011', '魂孤无室，御宿舍食。盗张民溃，见敌失内。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '010100', '居如转丸，危不得安。东西不宁，动生忧患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '001010', '坤厚地载，庶物蕃息。平康正直，以绥百福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '100011', '列敝牡荆，圣贤止悔。仇敌皆憎，孰肯相迎。上下有眚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '110001', '凤凰衔书，玄珪赐我，封为晋侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '011111', '作凶不善，相牵入井。溺陷辜罪，祸生忧滋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111110', '悲鸣北行，失其长兄。伯中不幸，骸骨败亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '011000', '羔衣豹裘，高扬我宇，君子维新。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '000110', '日中为市，各抱所有。交易资货，含珠怀宝，欣悦欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '011010', '振急绝理，恒阳不雨。物病焦干，华实无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '010110', '狐貉载剥，凌温厚蓐。寒棘为疾，何所不足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '011101', '履践危难，脱执去患。入福喜门，见诲大君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '101110', '四乱不安，东西为患。退止我足，毋出国城。乃得全完，赖齐生福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '001001', '南国少子，材略美好。求我长女，贱薄不与。反得丑恶，后乃大悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '100100', '妄弩失理，阳孤无辅。物病焦枯，年饥于黍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '110100', '倬然远咎，辟患害旱。田获三狐，见民为宝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '001011', '逐鹿山颠，利去我西。维邪南北，无所不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '001101', '龙蛇所聚，大水乐处。滑滑沛沛，使我无赖。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '101100', '从风吹火，牵骐骥尾。易为功力，因催受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '110110', '泽狗水凫，鸡畜少雏。不为家饶，心其亟逋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '011011', '水坏我里，东流为海。龟凫还嚣，不见慈母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '110010', '褰衣涉行，水深渍多。赖幸舟子，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '010011', '龟厌河海，陆行不止。自令枯槁，失其都市。有悔为咎，亦无及已。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '110011', '同本异叶，乐仁正德。东邻慕义，来兴我国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '001100', '桃李花实，累累日息。长大成熟，甘美可食，为我利福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '010101', '重瞳四乳，聪明顺理。无隐不形，微视千里。灾害不作，君子集聚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '101010', '实沈参墟，以义讨尤。次止结盟，以成霸功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '111000', '秦为虎狼，与晋争强，并吞其国，号曰始皇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '111111', '江河淮济，天之奥府，众利所聚。可以饶有，乐我君子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000000', '天之所灾，凶不可居。转徙获福，留止危忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '010001', '名成德就，项领不试。景公耋老，尼父逝去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '100010', '持善避患，福禄长存。虽有豺虎，不能危患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '010111', '避患东西，反入祸门。糟糠不足，忧动我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '111010', '珪璧琮璋，执贽见王。百里宁戚，应聘齐秦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000010', '扬水潜凿，使石洁白。衣素表朱，游戏皋沃。得君所愿，心志娱乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '010000', '官爵相保，居之无咎。求免不得，使伯悔恨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '110111', '载车无裈，裸裎出门。小儿作笑，君为忧患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '111011', '把珠入口，为我利宝。得吾所有，欣然嘉喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000111', '行不如止，直不如曲，进不如退，可以安吉。-。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '111101', '众鬼瓦聚，中有大怪，九身无头。魂惊魄去，不可以居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '101111', '家给人足，颂声并作。四夷宾服，干戈囊阁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000100', '人面鬼口，长舌如斧。斫破瑚琏，殷商绝祀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '001000', '南山之峻，真人所在。德配唐虞，天命为子。保佑饮享，身受大庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '011001', '春桃生花，季女宜家。受福多年，男为邦君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '100110', '鸱鸮破斧，冲人危殆。赖其忠德，转祸为福，倾危复立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000011', '猿堕高木，不踒手足。保我金玉，还归其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '110000', '天之奥隅，尧舜所居。可以存身，保我邦家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '101001', '伯蹇叔盲，足痛难行。终日至暮，不离家乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '100101', '日月相望，光明盛昌。三圣茂功，仁德大隆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '100000', '桃李花实，累累日息。长大成就，甘美可食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000001', '入和出明，动作有光。运转休息，所为允康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '111001', '阴衰老极，阳见其德。履离载光，天下昭明。功业不长，虾蟆代王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '100111', '行役未已，新事复起。姬姜劳苦，不得休止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '100001', '狐鸣室北，饥无所食。困于空丘，莫与同力。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '011110', '雄圣伏名，人匿麟远。走凤飞北，扰乱未息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '010010', '病贫望幸，使伯行贩。开牢择羊，多得大牂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '101101', '翕翕軥軥，陨坠崩颠。灭其令名，长没不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '011100', '华薄实槁，衣敝入络。女工不成，丝布如玉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '001110', '温山松柏，常茂不落。鸾凤所庇，得其欢乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '111100', '失持毋教，嘉偶出走。傫如失老，如丧家狗。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '001111', '太乙驾骝，从天上来。征我季叔，封为鲁侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '101000', '双凫俱飞，欲归稻池。径涉萑泽，为矢所射，伤我胸臆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000101', '深坑复平，天下安宁。意娱心乐，赖福长生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '110101', '俱为天民，云过我西。风伯雨师，与我无恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '101011', '野鸟山鹊，来集六博。三枭四散，主人胜客。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '010100', '北阴司寒，坚冰不温。凌人惰殆，大雹为灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '001010', '伊伯致仕，去桀耕野。执顺以待，反和无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '100011', '秋风牵手，相提笑语。伯歌季舞，燕乐以喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '110001', '徙巢去家，南过白马。东西受福，与母相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '011111', '鸟飞跌破，两两相和。不并四肢，但去莫疑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '111110', '三年生狗，以戌为母。荆夷上侵，姬伯出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '011000', '破筐敝莒，弃损于道。坏落穿败，不复所实。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000110', '结纽得解，忧不为祸。食利仙家，受福安坐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '011010', '白日扬光，雷车避藏。云雨不行，各自还乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '010110', '杜口结舌，心中怫郁。去灾生患，无所告冤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '011101', '赍贝赎狸，不听我辞。系于虎髯，牵不得来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '101110', '持鹤抱子，见蛇何咎。室家具在，不失其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '001001', '逐兔山西，利走入门。赖我仁德，获为我福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '100100', '兴役不休，与民争时。牛生五趾，行危为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '110100', '春栗夏梨，少鲜稀有。斗千石万，贵不可求。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '001011', '悲号北行，失其长兄。伯仲不幸，骸骨散王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '001101', '赋敛重数，政为民贼。杼轴空尽，家去其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '101100', '履服自敌，殃咎并列，忧不能笑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '110110', '杜口结舌，言为祸母。代伯受患，无所祷免。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '011011', '免冠进贤，步出朝门。仪礼不正，贼孽为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '110010', '娶于姜女，驾迎新妇。少齐在门，夫子悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '010011', '牡羊稻园，闻虎喧欢。畏恐悚息，终无祸患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '110011', '老妾踞机，纬绝不知。女功不成，冬寒无衣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '001100', '黑龙吐光，使阴复阳。荣猎载圣，六师以昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '010101', '东邻嫁女，为王妃后。庄公筑馆，以尊王母。归于京师，季姜悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '101010', '灌颉同徒，道顿跌踦。日辰不良，病为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '111101', '槖置山颠，销锋铸刃。示不复用，天下大欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '111111', '一臂六手，不使堵口。莫肯为用，利弃我走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '000000', '獐鹿逐牧，饱归其居，安息无悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '010001', '鸿鱼逆流，至人潜渚。蓬蒿代柱，大屋颠倒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '100010', '三羖五牂，相随俱行。迷入空泽，经涉六骏，为贼所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '010111', '黄帝出游，驾龙乘马，东上泰山，难过齐鲁。邦国咸喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '111010', '履危不安，心欲东西。步走逐鹿，空无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '000010', '望尚阿衡，太宰周公，藩屏汤武，立为侯王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '010000', '白龙黑虎，起伏俱怒，战于阪兆，蚩尤走败，死与鱼首。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '110111', '载石上山，步跌不前。颦眉之忧，不得所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '111011', '周德既成，行轴不倾。中酉跌墓，耋老衰去，箴石不佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '000111', '乘云带雨，与飞鸟俱。动举千里，见我慈母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '111000', '赍贝赎狸，不听我辞。系于虎须，牵不得来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '101111', '三翼飞来，字我逢时。俱行先至，多得大利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '000100', '两足四翼，飞入吾国。宁我伯姊，与母相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '001000', '案民湖池，玉贝文案。鱼如白云，一国获愿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '011001', '季姬踟蹰，望我城隅。终日至暮，不见齐侯，君上无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '100110', '龙渴求饮，黑云影从。河伯捧觞，跪进酒浆。流潦滂滂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '000011', '出门逢患，与怒为怨。更相击刺，伤我手端。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '110000', '播天舞地，神明所守，安乐无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '101001', '两金相击，勇武敢敌。终日大战，不破不缺。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '100101', '车虽驾，两纼绝，马奔出，双轮脱，行不至，道遇害。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '100000', '文山紫芝，雍梁朱草。长生和气，王以为宝。公尸侑食，福禄来处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '000001', '把珠入口，为我畜宝。得吾所有，欣然嘉喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '111001', '负车上山，力尽行难。烈风雨雪，遮过我前。中道复还，忧者得欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '100111', '陶朱白珪，善贾息资。三致千金，德放上人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '100001', '子鉏执麟，春秋作元。阴圣将终，尼父悲心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '011110', '春日载阳，福履齐长。四时不忒，与乐为昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '010010', '孔德如玉，出于幽谷。飞上乔木，鼓其羽翼，大光照国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '101101', '瓯脱康居，慕仁入朝。湛露之欢，三爵毕恩。复归穷庐，以安其居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '011100', '秋冬夜行，照览星辰。道理利通，终身无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '001110', '鸣鹄抱子，见蛇何咎。室家俱在，不失其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '111100', '安如泰山，福禄屡臻。虽有豺虎，不能危身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '001111', '老目瞢眠，不知东西。岁君失理，命直为曲。王称为宝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '101000', '植璧秉珪，请命于河。周公克敏，冲人瘳愈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '000101', '大王执政，岁熟民富。国家丰有，王者有喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '110101', '争讼相悖，和气不处。阴阳俱否，谷风母子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '101011', '齐鲁争言，战于龙门。构怨结祸，三世不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '010100', '鹿得美草，鸣呼其友。九族和睦，不离邦域。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '001010', '百里南行，虽微复明。去虞适秦，为穆国卿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '100011', '梅李冬实，国多寇贼，扰乱并行，王不能制。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '110001', '府藏之富，王以赈贷。捕鱼河海，笱网多得，巨蛇大鳅。战于国郊，君遂走逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '011111', '牡飞门启，忧患大结。去老乘马，不为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '111110', '宜昌娶妇，东家歌舞长乐欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '011000', '正阳之央，甲氏以亡。祸及留吁，湮灭为墟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '000110', '凫过稻庐，甘乐麦鳅。虽驱不去，田畯怀忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '011010', '跛踦俱行，日暮车伤，失旅乏粮。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '010110', '龙门水穴，流行不害。民安其土，君臣相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '011101', '山陵四塞，遏我径路。欲前不得，复还故处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '101110', '两虎争斗，血流漂忤。城郭空虚，蒿藜塞道。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '001001', '依东墙隅，志下心老。楚亭晨食，韩子低头。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '100100', '龙生无常，或托空桑。凭乘风云，为尧立功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '110100', '魁行摇尾，逐云吹水。淤泥为陆，下田为稷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '001011', '跛踦相随，日暮牛罢。陵迟后旅，失利亡雌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '001101', '三人俱行，北求大祥。长子病足，请季负囊。柳下之责，不失骊黄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '101100', '凤凰在左，麒麟在右。仁圣相遇，伊吕集聚。伤害不至，时无殃咎，福为我母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '110110', '乘筏渡海，虽深不殆。曾孙皇祖，累累具在，受其大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '011011', '比目四翼，来安吾国。畿福上堂，与我同床。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '110010', '娶于姜吕，驾迎新妇。少妻在门，夫子悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '010011', '螟虫为贼，害我稼穑。尽禾单麦，秋无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '110011', '衣裳颠倒，为王来呼。成就东周，邦国大休。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '001100', '王孙季子，相与为友。明允笃诚，升擢荐举。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '010101', '涌泉滑滑，流行不绝。污为江海，败坏邑里，家无所处。闻虎不俱，向我笑喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111101', '101010', '桑户窃脂，啄粟不宜。乱政无常，使心乱明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '101111', '白虎张牙，征伐东来。朱雀前驱，赞道说辞。敌人请服，衔璧前驱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '111111', '南山大行，困于空桑。老沙为石，牛马无食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '000000', '蟠枝失岐，与母别离，绝不相知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '010001', '噂噂所言，莫如我垣。欢乐坚固，可以长安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '100010', '李桃零坠，心思精愦。欢忧小愧，乱我魂气。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '010111', '火虽炽，在吾后。寇虽多，在吾右。身安吉，不危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '111010', '虎卧山隅，鹿过后朐，弓矢设张，猬为功曹，伏不敢起，遂至平野，得我美草。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '000010', '三火起明，雨灭齐光。高位疾颠，骄恣诛伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '010000', '疋居楚鸟，遇馋无辜，久散离忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '110111', '一室十子，同公异母。以义防患，祸灾不起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '111011', '商人行旅，资无所有。贪贝利珠，留连王市。还家内顾，公子何咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '000111', '禹将为君，北入昆仑。稍进阳光，登入温汤。代舜为治，功德昭明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '111000', '乾行天德，覆帱无极，呕呼烹熟，使各自得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '111101', '南国茂盛，庶稷酿酒。可以享老，乐我嘉友。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '000100', '方船备水，旁河燃火。终身为祸，与夫吉昌，永得安康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '001000', '雷行相逐，无有休息。战于平陆，为夷所覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '011001', '踯躅踟蹰，拊心搔头。五昼四夜，睹我齐候。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '100110', '大口宣唇，神使伸言。黄龙景星，出应侯门。与福上堂，天下吉昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '000011', '阴衰老极，阳建其德。离阳载光，天下昭明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '110000', '三涂五岳，阳城太室，神明所伏，独无兵革，下有保国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '101001', '年岁丰熟，政仁民乐。利以居止，旅人获福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '100101', '楚乌逢矢，不可久放。离居无辜，意昧精丧。作此哀诗，以告孔忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '100000', '出门大步，与凶恶忤。骂公詈母，为我忧耻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '000001', '火之井谷，杨芒生角。犯历天市，窥观太极。登上玉床，家易六公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '111001', '牧羊逢狼，虽忧不伤。畏不惕息，终无祸殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '100111', '茧栗牺牲，敬奉贵神。享者饮食，受福多孙。望季不来，孔圣厄陈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '100001', '大泽治妆，南归羖羊。长伯为我，多得马牛。利于徙居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '011110', '枯树无枝，与子分离。饥寒莫养，独立哀悲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '010010', '天地九重，尧舜治中。正冠衣裳，宇宙平康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '101101', '凫鹥游泾，君子以宁。履德不愆，福禄来成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '011100', '裸裎逐狐，为人所笑，牝鸡司晨，主作乱根。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '001110', '典册法书，藏在兰台。虽遭乱溃，独不遇灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '111100', '三痴俱狂，欲之平乡。迷惑失道，不知昏明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '001111', '瘿瘤疡疥，为身疮害。疾病癃痢，常不危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '101000', '三豕俱走，斗于谷口。白豕不胜，死于坂下。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '000101', '赖主之光，受德之佑。遂造颠沛，独不凶咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '110101', '上义崇德，以建大福。吉宜诰旦，周武功立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '101011', '四乱不安，东西为恨，身止无功。不出国城，乃得完全，赖其生福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '010100', '金牙铁齿，西母王子。无有患殆，涉道大利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '001010', '贺喜从福，日利蕃息，欢乐有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '100011', '昊天白日，照临我国。万民康宁，咸赖受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '110001', '左眇右盲，视暗不明。下民多蘖，君失其常。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '011111', '吾有黍梁，委积道旁。有架服箱，运我到乡，藏于嘉仓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '111110', '殊类异路，心不相慕。牝豕无豭，鳏居室家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '011000', '雀行求食，出门见鹞。颠蹶上下，几无所处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '000110', '野有积庾，穑人驾取，不逢虎狼，暮归其宅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '011010', '肤敏之德，发愤忘食。虏豹禽越，为王求福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '010110', '光祀春成，陈宝鸡鸣。阳明失道，不能自守，消亡为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '011101', '左抱金玉，右得熊足。常盈不亡，获心所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '101110', '履泥污足，名困身辱。两仇相得，身其为虚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '001001', '安居重迁，不去其廛。禾米相闻，乐得常产。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '100100', '天灾所游，凶不可居。转徙获福，留止危忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '110100', '昧昧默默，不知白黑。景云乱扰，光明隐伏。犬戎攻来，幽王失国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '001011', '凫雁哑哑，以水为宅。雌雄相和，常共娱乐。得其所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '001101', '长生无极，子孙千亿。柏柱载梁，坚固不倾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '101100', '麒麟凤凰，善政得祥。阴阳合调，国无灾殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '110110', '天之奥隅，尧舜所居。可以存身，保我室家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '011011', '配合相迎，利之四邻。昏以为期，与福笑喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '110010', '砥德砺材，果当成周。拜受大命，封为齐侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '010011', '与福俱坐，畜水备火。思患豫防，终无殃祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '110011', '晨昏潜处，候时熙熙。卒逢白日，为世荣主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '001100', '视日再光，与天相望。长生欢悦，与福为兄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '010101', '大头明目，载受嘉福。三雀飞来，与禄相触。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101111', '101010', '梗生荆山，命属输班。袍衣剥脱，夏热冬寒。立成枯槁，众人莫怜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '000100', '王乔无病，狗头不痛。亡跛失履，之我逆从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '111111', '喋嗫处曜，昧冥相待。多言少实，终无成事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '000000', '北辰紫宫，衣冠中立。含和达德，常受大福。铅刀攻玉，坚不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '010001', '东壁为光，数暗不明。王母嫉妒，乱我事业。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '100010', '下背其上，资明其让。子婴两头，陈破其墟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '010111', '凤生会稽，稍具能飞。翱翔桂林，与众鸟雄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '111010', '凿井求玉，非卞氏宝。名困身辱，劳无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '000010', '拜杰载复，送至东莱。百僚具举，君王嘉喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '010000', '安息康居，异国穹庐，非吾邦域，使伯忧戚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '110111', '江河淮海，天之都市。商人受福，国家富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '111011', '同木异叶，乐仁上德。东邻慕义，来兴吾国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '000111', '白鹤衔珠，夜室反明。怀我德音，身受光荣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '111000', '践履危难，脱厄去患。入福喜门，见吾邦君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '111101', '宫商既和，声音相随。骊驹在门，主君以欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '101111', '天地配享，六位光明。阴阳顺序，以成厥功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '001000', '江河淮海，天之奥府，众利所聚，可以饶有，乐我君子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '011001', '双凫俱飞，欲归稻池。径涉萑泽，为矢所射。伤我胸臆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '100110', '伯仲叔季，日暮寝寐。裸卧失明，丧我贝囊，衔卸道旁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '000011', '受阻文祖，承率复起。以义自闲，虽苦无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '110000', '旋斗运枢，顺天无忧，与乐并俱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '101001', '周师伐纣，战于牧野。甲子平旦，天下悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '100101', '十雌百雏，常与母俱。抱鸡博虎，谁敢害诸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '100000', '桀跖并处，人民愁苦。拥兵荷粮，战于齐鲁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '000001', '南山昊天，刺政闵身。侯悲无辜，皆憎为仇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '111001', '百川朝海，流行不止。道虽辽远，无不到者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '100111', '目不可合，忧来摇足，悚惕危惧，去其邦域。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '100001', '乌夫鹄举，照临东海。龙降庭坚，为陶叔后。封于蓼丘，福履绥厚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '011110', '北方多枣，橘柚所聚。荷囊载香，盈我筐筥。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '010010', '悬貆素食，食非其任。失望远民，实劳我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '101101', '羔羊皮革，君子朝服。辅政扶德，以合万国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '011100', '齐鲁争言，战于龙门。构怨致祸，三岁不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '001110', '久阴霖雨，涂行泥潦。商人休止，市空无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '111100', '桃雀窃脂，巢于小枝。摇动不安，为风所吹。寒心悚悚，常忧殆危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '001111', '防患备灾，凶祸不来。虽困无灾，未或安休。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '101000', '引颈绝粮，与母异门。不见所欢，孰与共言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '000101', '鳅虾去海，藏于枯里。街巷偏隘，不得自在。南北无极，渴馁成疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '110101', '恭宽信敏，功加四海。辟去不祥，喜来从母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '101011', '岁饥无年，虐政害民。乾溪骊山，秦楚结冤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '010100', '右目无瞳，偏视寡明。十步之外，不知何公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '001010', '蜩螗欢喜，草木喜茂。百果蕃炽，日益庶行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '100011', '常德自如，安坐无尤。幸如贵乡，到老安荣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '110001', '狡兔趯趯，犬良逐咋。雄雉受害，为鹰所获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '011111', '春桃生花，季女宜家。受福多年，男为封君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '111110', '山石朽弊，少崩坠落。上下离心，君受其祟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '011000', '水坏我里，东流为海。龟凫欢哗，不睹我家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '000110', '七窍龙身，造化八元。法天则地，顺时施恩。富贵长存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '011010', '四夷慕德，来兴我国。文君徙降，同受福德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '010110', '华首山头，仙道所游。利以居上，长无咎忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '011101', '鹯鸠徙巢，西至平州。遭逢雷雹，辟我苇芦。室家饥寒，思吾故初。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '101110', '狗无前足，阴谋叛背，为身害贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '001001', '阳孤亢极，多所恨惑。车倾盖亡，身常惊惶。乃得其愿，雌雄相从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '100100', '空巢注猪，豚彘不至。张弓祝鸡，雄父飞去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '110100', '长夜短日，阴为阳贼。万物空枯，藏于北陆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '001011', '爪牙之士，怨毒乞父。转忧于己，伤不及母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '001101', '拜跪请兔，不得臭腐。挽眉衔指，低头北去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '101100', '有莘季女，为王妃后。贵夫寿子，母字四海。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '110110', '季姜踟蹰，待孟城隅。终日至暮，不见齐侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '011011', '邯郸反言，父兄生患。涉此忧恨，卒死不还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '110010', '逐鹿山颠，利去我西。维邪南北，所求不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '010011', '穿鼻系株，为虎所拘。王母祀福，祸不成灾，突然自来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '110011', '虎豹熊罴，游戏山谷。君子仁贤，亦得所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '001100', '梅李冬实，国多盗贼，扰乱并作，王不得制。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '010101', '望幸不到，文章未就。羊子逐兔，犬踦不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000100', '101010', '千柱百梁，终不倾僵。仁智辅圣，周宗宁康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '001000', '冰将泮散，鸣雁雍雍。丁男长女，可以会同。生育贤人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '111111', '龙马上山，绝无水泉。喉焦唇干，口不能言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '000000', '蔡侯朝楚，留连江滨。逾时历月，思其后君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '010001', '文厄羑里，汤囚夏台。仁圣不害，数困何忧。免于缧绁，为世明侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '100010', '典册法书，藏阁兰台。虽遭乱溃，独不遇灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '010111', '毡裘膻国，文礼不饬。跨马控弦，伐我都邑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '111010', '星陨如雨，力弱无辅。强阴制阳，不得安土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '000010', '蝗啮我稻，驱不可去。实穗无有，但见空藁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '010000', '虎饥欲食，为猬而伏。禹导龙门，避咎除患，元丑以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '110111', '蝙蝠夜藏，不敢昼行。酒是酸浆，鲂死鲍羹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '111011', '精华堕落，形体丑恶。龃龉挫顿，枯槁腐蠹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '000111', '两足不获，难以远行。疾步不能，后旅失时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '111000', '令妻寿母，宜家无咎。君子之欢，得以长久。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '111101', '饥蚕作室，缗多乱缠，绪不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '101111', '子鉏执麟，春秋作元。阴圣将终，尼父悲心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '000100', '螟虫为贼，害我稼蔷。禾殚麦尽，秋无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '011001', '忧在腹内，山崩为疾。祸起萧墙，竟制其国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '100110', '茹芝饵黄，饮食玉瑛。与神流通，长无忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '000011', '一夫两心，技刺不深。所为无功，求事不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '110000', '十里望烟，散涣四方。形容灭亡，终不见君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '101001', '张弓控弩，经涉山道。虽有伏虎，谁敢害诸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '100101', '泉闭泽竭，王母饥渴。君子困穷，乃徐有说。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '100000', '野鸢山雀，弈棋六博。山枭四散，主人胜客。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '000001', '羊惊马走，上下挥扰。鼓音不绝，顷公奔败。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '111001', '黄帝神明，八子圣聪。俱受大福，天下康平。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '100111', '住车醊酒，疾风暴起。泛乱福器，飞扬位卓，明神降禄，道无害寇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '100001', '腾蛇乘龙，宋郑饥凶，民食草蓬。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '011110', '扬水潜凿，使石洁白。里素表朱，游戏皋泽。得君所欲。心志娱乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '010010', '西过虎庐，惊我前驱。虽忧无危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '101101', '衣成无开，不知所穿。客指东西，未得使安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '011100', '晨风文翰，随时就温。雄雌相和，不忧危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '001110', '心多悔恨，出言为怪。枭鸣室比，声丑可恶。请谒不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '111100', '离女去夫，闵思苦忧。齐子无良，使我心悲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '001111', '过时不归，雌雄苦悲。徘徊外国，与叔分离。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '101000', '鹊巢柳树，鸠夺其处。任力德薄，天命不佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '000101', '鹤盗我珠，逃于东都。鹄怒追求，郭氏之墟。不见踪迹，使伯心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '110101', '夫妇相背，和气弗处。阴阳俱否，庄姜无子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '101011', '月走日步，趣不同舍。夫妻反目，主君失居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '010100', '洛阳嫁女，善逐人走。三寡失夫，妇妒无子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '001010', '周德既成，杼轴不倾。太宰东西，夏国康宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '100011', '日中为市，交易资宝。名利所有，心悦以喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '110001', '童妾独宿，长女为室，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '011111', '忠言辅成，王政不倾。公刘兆基，文武绥之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '111110', '牛骥同堂，郭氏以亡。国破为墟，主君奔逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '011000', '中原有菽，以待雉食。饮御诸友，所求大得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '000110', '多虚少实，语不可知。尊空无酒，飞言如雨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '011010', '青蝇集蕃，君信谗言，害贤伤忠，患生妇人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '010110', '履株履舆，马惊伤车，步为我忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '011101', '商风召寇，呼我北盗。间谍内应，与我争斗。殚以宝藏。主人不胜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '101110', '逸豫好游，不安其家。或有少姬，久迷不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '001001', '无有骅骝，畜之以时。东家翁孺，来诣我车，价极可与，后无贱忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '100100', '厄穷上通，与尧相逢。登升大麓，国无凶人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '110100', '众兔俱走，熊罴在后。踦不能进，失信寡处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '001011', '旁行不远，三思复返。心多畏恶，中日止舍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '001101', '仓皇奉使，中山以孝。文侯悦喜，击子征召。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '101100', '入天门，守地户，君安乐，不劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '110110', '等阶上堂，见吾父兄。左酒右浆，与福相迎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '011011', '秋蛇向穴，不失其节。夫人姜氏，自其复入。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '110010', '忍丑少羞，有面无头。耗减寡虚，日以削消。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '010011', '景星照堂，麟游凤翔。仁施大行，颂声以兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '110011', '竿旄旌旗，执帜在郊。虽有宝珠，无路致之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '001100', '李华再实，鸿卵降集。仁德以兴，萌国受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '010101', '白马赤乌，战于东都。天辅有德，败亡为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001000', '101010', '采薪得麟，大命陨颠。豪雄争名，天下四分。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '011001', '鸟鸣东西，迎其群侣。似有所属，不得自专，空返独还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '111111', '必自易处，不知香臭。君密于是，失其宠位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '000000', '唐虞相辅，鸟兽喜舞。安康无事，国家富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '010001', '左辅右弼，金玉满匮。常盈不亡，富如仓廒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '100010', '苍龙单独，与石相触，摧折两角。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '010111', '钓目厌部，善逐人走。来嫁无父，不安其庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '111010', '逐兔驱狼，避去不祥。凶恶北行，与善相逢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '000010', '赍贝赎狸，不听我辞。系于虎须，牵不得来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '010000', '同载共舆，中道别去。丧我元夫，独与孤居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '110111', '奋翅鼓翼，将之嘉国。愆期失时，乃得所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '111011', '目倾心惑，夏姬在侧。申公颠倒，巫臣乱国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '000111', '博鸠弹鹊，逐兔山北，丸尽日暮，失获无得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '111000', '鹿求其子，虎庐之里。唐伯李耳，贪不我许。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '111101', '败鱼鲍室，臭不可息。上山履涂，归伤我足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '101111', '花灯百枝，消暗衰微。精光讫尽，奄有灰靡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '000100', '颜叔子夏，遨游仁宇。温良受福，不失其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '001000', '梁柱坚固，子孙蕃盛。福喜盈积，终无祸悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '100110', '边鄙不宁，民狎于野。穑人成功，年岁大有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '000011', '蜗牛鸣呴，呼求水潦。云雨大会，流成河海。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '110000', '志合意同，姬姜相从。佳偶在门，夫子悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '101001', '白马驳骝，更生不休。富有商人，利得如丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '100101', '大姒夏禹，经启九道。各有攸处，民得安所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '100000', '甲戊己庚，随时转行。不失其心，得且安宁。唐季发愤，擒灭子婴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '000001', '穆违百里，使孟历武。将帅袭战，败于淆石。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '111001', '茅如木居，与类相投。顾慕群旅，不离其巢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '100111', '伯仲叔季，日暮寝寐。坐卧失明，丧其贝囊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '100001', '亡羊补牢，张氏失牛。骍驷奔走，鹄盗我鱼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '011110', '雀目燕颡，畏昏无光。思我狡童，不见子充。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '010010', '人和出明，动作有光。运转休息，常乐允康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '101101', '不胜私情，以利自婴。其室出孤，毁其良家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '011100', '称幸上令，媚悦于神。受福重重，子孙蕃功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '001110', '齐姜叔子，天命在位。实沈参墟，封为康侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '111100', '遨游无患，出入安全，长受其欢，君子万年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '001111', '被服文德，升入大麓。四门雍肃，登受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '101000', '负金怀玉，南归嘉国。蜂虿不螯，利入我室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '000101', '日在阜颠，向昧为昏。小人成群，君子伤伦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '110101', '水火父母，先来鸣呴。泽高之上，从高而处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '101011', '东邻少女，为王长归。柔顺利贞，宜夫寿子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '010100', '戴瓶望天，不见星辰。愿小失大，福逃于外。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '001010', '王乔不病，狗头不痛。三尸头履，乏我逆从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '100011', '使燕筑室，身无庇宿。家不容车，微我衣服。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '110001', '威权分离，乌夜徘徊。争蔽月光，大人诛伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '011111', '辩变白黑，巧言乱国。大人失福，君子迷惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '111110', '衣锯甲铠，敝筐为具。大人不顾，少妇不取。弃捐于道。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '011000', '燕雀衔泥，以生孚乳。兄弟六人，叫好孝悌。得心欢欣，和悦相乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '000110', '登几上舆，驾驷南游。合从散衡，燕秦以强。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '011010', '黯黯许许，仇偶相得。冰入炭室，消亡不息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '010110', '鸱鸮破斧，邦人危殆。赖其忠德，转祸为福。倾亡复立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '011101', '载金贩狗，利弃我走。藏匿渊渠，悔折为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '101110', '渊坑复平，宇穴安宁。忧患解除，赖福长生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '001001', '骊姬馋嬉，与二孽谋。谮我恭子，贼害忠孝。驾出喜门，商伯有害。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '100100', '刺羊不当，血少无羹。女执空筐，不得采桑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '110100', '牧羊稻园，闻虎喧嚷。畏惧悚息，终无祸患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '001011', '明德隐伏，麟凤远匿。周室倾侧，不知所息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '001101', '邻不我顾，而求玉女。身多秃癞，谁肯媚者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '101100', '处虽无舆，后得战车。赖幸逢福，不罹兵革。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '110110', '水坏我里，东流为海。龟凫欢嚣，不睹王母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '011011', '两心不同，或欲西东。明论终始，莫适所从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '110010', '天地悬车，废礼不朝。禳服不制，失宠其家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '010011', '交川合浦，远湿难处。水土不同，思吾皇祖。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '110011', '勾践之危，栖于会稽。太宰机言，越国复存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '001100', '慈鸟鸣鸠，执一无尤。寝门内治，军自悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '010101', '富年早寡，孤与独居。鸡鸣犬吠，无敢问者。我生不遇，独罹寒苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011001', '101010', '江海变服，淫湎无测。高位颠崩，宠禄反复。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '100110', '鲂生江淮，一转为百。周流天下，无有难恶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '111111', '首释与目，载受福庆。我有好爵，与善相迎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '000000', '軥軥轠轠，岁暮编敝。宠名弃捐，君襄在位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '010001', '折箬蔽日，屏遮王目。司马无良，平子没伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '100010', '家在海隅，绕旋深流。王孙单行，无妄以趋。固阴互寒，长冰不温。后入坠胎，大雹为害。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '010111', '执义秉德，不危不殆。延颈盘恒，安其室垣。屯耗未得，终无大恤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '111010', '长舌乱国，大斧破车。阴阳不顺，姬姜衰忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '000010', '二人共路，东趋西步。千里之外，不相知处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '010000', '视暗不明，云蔽日光。不见子都，郑人心伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '110111', '初忧后喜，与福为市。八佾列陈，饮御嘉友。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '111011', '童妾独宿，长女未室，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '000111', '玄黄四塞，阴雌伏谋。呼为墙屋，为巫所识。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '111000', '中岁摧陨，常恐衰微，老复赖庆，五羖为相。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '111101', '伯氏杀牛，行悖天时。亳社夷烧，朝歌丘墟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '101111', '日短夜长，禄命不光。早离父兄，免见忧伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '000100', '采唐深乡，徼期桑中。失心不会，忧思忡忡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '001000', '昧视无光，夜不见明。冥抵空床，季叶逃亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '011001', '举趾振翼，南至嘉国，见我伯姑，与惠相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '000011', '则天顺时，周流其墟。与乐并居，无有咎忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '110000', '虿室蜂户，螯我手足。不可进取，为我害咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '101001', '公孙驾骊，载游东齐。延陵悦产，遗季纻衣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '100101', '转作骊山，大失人心。刘季发怒，命灭子婴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '100000', '羊肠九萦，相推稍前。止须王孙，乃得上天。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '000001', '螮蝀充测，佞人倾惑。女遏横行，正壅道塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '111001', '福禄不遂，家多怪祟。麋鹿悲啼，思其大雄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '100111', '云雷因积，大雨重叠。久不见日，使我心悒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '100001', '三河俱合，水怒涌跌。坏我王室，民因无食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '011110', '旦雨夜行，早遍都城。更相覆倾，终无所成。三头两眠，不见其真。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '010010', '褒后生蛇，经老育微。侧跌哀公，酒减黄离。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '101101', '鸿雁南飞，随时休息。转送天和，千岁不衰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '011100', '后时失利，不得所欲。莫享偕结，自逐自逐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '001110', '心多恨悔，出言为怪。枭鸣室北，丑声可恶。请谒不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '111100', '四马过隙，时难再得。尼父孔圣，系而不食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '001111', '阴变为阳，女化为男。治道得通，君臣相承。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '101000', '昆仑源口，流行不止。龙门砥柱，民不安处。母归扶子，黄麋悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '000101', '葛藟蒙棘，华不得实。馋佞乱政，使恩壅塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '110101', '公无长驱，天王骏马。非其当所，伤折为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '101011', '大仓充盈，万物蕃盛，年岁熟荣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '010100', '执簧照牺，为风所吹，火灭无光，不见玄黄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '001010', '鸟反故巢，归其室家，心平意正，与叔相鸣。登高陨坠，失其宠贵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '100011', '弩驰弓藏，良犬不烹。内无怨女，征夫在堂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '110001', '牡牺孔博，日新其德。文君出猎，姜氏受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '011111', '秋季孟冬，寒露霜降。大阴在庭，庶物不生。鸡鸣犬吠，家忧数惊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '111110', '心多恨悔，出门见怪。歹蛇三足，丑声可恶。嫫母为媒，请求不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '011000', '虎豹争强，道闭不通。小人欢讼，贪天之功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '000110', '鸡方啄粟，为狐所逐。走不得食，惶怖惕息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '011010', '陈妫敬仲，兆兴齐姜。乃适营丘，八世大昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '010110', '昊天白日，照临我国。万民康宁，咸赖喜福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '011101', '云梦大薮，嘉有所在。虞人共职，骊驹乐喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '101110', '獐鹿雉兔，群聚东国。芦黄白春，俱往逐追，九齚十得。主君有喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '001001', '得惠孔明，主君复章，保其室堂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '100100', '天之所坏，不可强支。众口嘈嘈，虽贵必危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '110100', '天之奥隅，尧舜所居。可以全身，保我邦家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '001011', '下泉苞稂，十年九主。旬伯遇时，忧念周京。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '001101', '江河海隅，众利聚居。可以遨游，卒岁无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '101100', '南山黄竹，三身六目。出入制命，东皇宣政。主尊君安，郑国无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '110110', '重译置之，来除我忧。与喜俱居，同其福休。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '011011', '南山高岗，麟凤室堂。含和履中，国无灾殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '110010', '紫芝朱草，生长和气。公尸侑食，福禄来下。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '010011', '宫城室就，进乐相舞。英俊在堂，福禄光明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '110011', '商之子孙，资无所有。贪贝逐狐，留连都市。还辕内乡，嘉喜何咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '001100', '执贽入朝，献其狐裘。元戎燮安，妙漠以欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '010101', '涌泉汩汩，南流不绝。洿为淮海，坏败邑里。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100110', '101010', '固阴冱寒，常冰不温。凌人惰殆，大雹为灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '000011', '弱水之西，有西王母。生不知老，与天相保。行者危殆，利居善喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '111111', '黄獹生子，白戌为母。晋师在郊，虞公出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '000000', '仓皇奉使，中山以孝。文侯悦喜，系子征召。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '010001', '机关不便，不能出言。精诚不通，为人所冤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '100010', '白茅醴酒，灵巫拜祷。神嗜饮食，使君寿考。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '010111', '重瞳四乳，目聪耳明。普仁表圣，为作元辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '111010', '水涨无船，破城坏堤，大夫从役。一朝亡殒，不见少妻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '000010', '六人俱行，各遗其囊。鸿鹄失珠，无以为明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '010000', '随时转行，不失其常。各乐厥类，身无咎殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '110111', '蔡女荡舟，为国患忧。褒后在侧，屏蔽王目。早衰六畜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '111011', '驾龙骑虎，周遍天下。为神人使，西见王母。不忧危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '000111', '胥恐之吴，画策阖闾。鞭平服荆，除大咎殃。威震敌国，还受上卿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '111000', '唐邑之庐，晋人以居。虞叔受福，实贶是国。世载其乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '111101', '管鲍相知，至德不离。三言于桓，齐国以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '101111', '三十无室，长女独宿。心劳未得，忧在胸臆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '000100', '散涣水长，风吹我乡。火灭无光，隳败桓功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '001000', '蜎飞蠕动，各有配偶。大小相保，咸得其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '011001', '安乐几筵，未出王门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '100110', '大生灾祸，下土恩塞，抵乱我国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '110000', '长生无极，子孙千亿。柏柱载梁，坚固不倾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '101001', '钦敬昊天，历象星辰。宜受民时，阴阳和调。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '100101', '三河俱合，水怒踊跃。坏我王室，民困于食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '100000', '寿如松乔，与日月俱。常安康乐，不离祸忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '000001', '天之所予，福禄常在，不忧危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '111001', '受谶六符，招摇室虚。虽跌无忧，保我命则。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '100111', '金买车，失道后时，劳罢为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '100001', '华首山头，仙道所游。利于居止，长无咎忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '011110', '采唐沫乡，徼期桑中。失信不会，忧思约带。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '010010', '人面九口，长舌为斧。斲破瑚琏，殷商绝后。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '101101', '临溪桥疚，虽恐不危，乐以笑歌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '011100', '泱泱沸溢，水泉为害，使我无赖。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '001110', '蝗螟为贼，害我稼穑。秋饥于年，农夫鲜食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '111100', '八百诸侯，不期同时。慕西文德，兴我宗族。家门雍睦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '001111', '长男少女，相向笑语。来欢致福，和悦乐喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '101000', '平国不君，夏氏作乱。乌号窃发，灵公殒命。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '000101', '春多膏泽，夏润优渥。稼穑成熟，亩获百斛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '110101', '客宿卧寒，席蓐不安。行为危害，留不得欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '101011', '乘槎浮海，虽惧不殆。母载其子，终焉何咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '010100', '手拙不便，不能伐檀。车无轴辕，行者苦难。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '001010', '唐虞相辅，鸟兽率无。民安无事，国家富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '100011', '秋蛇向穴，不失其节。夫人姜氏，自齐复入。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '110001', '病笃难医，和不能治。命终永讫，下即蒿芦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '011111', '青蛉如云，城邑闭门。国君御守，民困于患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '111110', '牙孽生齿，室堂启户。出入利贞，鼓翼起舞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '011000', '凫游江湖，役行千里。以为死亡，复见空桑，长生乐乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '000110', '黄帝出游，驾龙乘凤。东上泰山，南游齐鲁。邦国咸喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '011010', '履危不止，与鬼相视。惊恐失气，如骑虎尾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '010110', '秋南春北，不失消息。涉和履中，时无阴匿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '011101', '龙门砥柱，通利水道。百川顺流，民安其居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '101110', '千岁庙堂，栋桡倾僵。天厌周德，失其宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '001001', '折箬蔽目，不见稚叔。五足孤鸟，远离室家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '100100', '望叔山北，陵隔我目。不见所得，使我心惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '110100', '匏瓠之息，一亩十室。万国都邑，北门有福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '001011', '域域牧牧，忧和相伴。隔我岩山，室家分散。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '001101', '麒麟騄耳，游食萍草。逍遥石门，循山上下。不失其子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '101100', '天所祚昌，文以为良。笃生武王，姬受其福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '110110', '羊肠九萦，相推稍前。止须王孙，乃能上天。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '011011', '贫鬼守门，日破我盆。孤牝不驹，鸡不成雏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '110010', '饱食从容，入门上堂。不失其常，家无咎殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '010011', '阴淫不止，白马为海。泽皋之子，就高而处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '110011', '执戈俱立，以备暴急。千人举龙，困危得海。终安何畏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '001100', '夹河为婚，水涨无船。追心失望，不见欢君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '010101', '阴阳变化，各得其宜。上下顺通，奏为肤功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000011', '101010', '狂劣德薄，失其臣妾。田不见禽，犬无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '110000', '历山之下，虞唐所处。躬耕致孝，名闻四海。为尧所荐，禅位天子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '111111', '蜎飞蠕动，各有所配。欢悦相迎，咸得其处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '000000', '继祀宗邑，追明成康。光照万国，享世久长。病疾不医，下即蒿芦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '010001', '秋冬探巢，不得鹊雏。衔指北去，媿我少姬。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '100010', '僮妾独宿，长女未室，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '010111', '洪鱼逆流，至人潜去。蒿蓬代柱，大屋颠仆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '111010', '日闇不明，谗夫在堂。右臂疾痹，君失其光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '000010', '王孙季子，相与孝友。明允笃诚，升擢荐举。为国干柱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '010000', '麟趾龙身，日驭三千。南上苍梧，与福为婚。道里夷易，安全无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '110111', '三子成驹，折损辕轴。轮载空舆，后时失期。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '111011', '逐福除患，道德神仙。避恶万里，常欢以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '000111', '黄池之盟，吴楚争强。勾践为患，夷门不安。探得螽，所愿不喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '111000', '青牛白咽，呼我俱田。历山之下，可以多耕。岁藏时节，人保安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '111101', '有头无目，赫赫粟粟。消耗为疾，三年不复。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '101111', '山没丘浮，陆为水鱼。燕雀无巢，民无室庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '000100', '高冈凤凰，朝阳梧桐。雝雝喈喈，奉奉萋萋。陈辞不多，以告孔嘉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '001000', '鳏寡独宿，忧动胸臆，莫与笑食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '011001', '踬马破车，恶妇破家。青蝇污白，暴子离居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '100110', '长女二嫁，进退无羞。逐狐作妖，行者离忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '000011', '人无足法，缓行长奸。地雄走归，阳不制阴。男失其家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '101001', '茹芝饵黄，饮食玉英。与神流通，长无忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '100101', '东行无门，西出华山。道塞于难，游子为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '100000', '寿如松乔，与日月俱。常安康乐，不罹祸忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '000001', '探得螽，所愿不喜。黄池之盟，吴楚争强。勾践为患，夷门不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '111001', '蝠螺生子，深目黑丑。虽饰相就，众人莫取。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '100111', '喜怒不时，霜雪为灾。稼穑无功，后稷饥寒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '100001', '乌升鹊举，照临东海。尨降庭坚，为陶叔后。封为蓼丘，履禄绥厚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '011110', '黄离白日，照我四国。元首昭明，民赖其福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '010010', '黍稷醇醲，敬奉山宗。神嗜饮食，甘雨嘉降。独蒙福力，时灾不至。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '101101', '祸不更生，福过我里。入门笑喜，与吾利市。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '011100', '昼卧牢门，怵惕不安。目不得阖，鬼搔我足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '001110', '春草荣华，长女宜夫。受福多年，世有封禄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '111100', '雍门内崩，贼贤伤仁。暴乱狂悖，简公失位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '001111', '心壮无良，猖獗妄行。触抵墙壁，不见户房。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '101000', '胶车木马，不利远贾。出门为患，安止不危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '000101', '家在海隅，桡短流深。企立望宋，无木以趋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '110101', '冬桑枯槁，当风失道。蒙被尘埃，左右劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '101011', '过时不行，妄逐王公。老女无夫，不安其居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '010100', '履泥污足，名困身辱。两仇相当，自为痛疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '001010', '精华堕落，形客丑恶。龃龉挫顿，枯槁腐蠹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '100011', '长生无极，子孙千亿。松柏为梁，坚固不倾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '110001', '去辛就蓼，毒愈酷甚。避井入坎，忧患日生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '011111', '行尧钦德，养贤致礼。众英积聚，国无寇贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '111110', '狗逐兔走，俱入谷口。与虎逢之，迫不得去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '011000', '望尚阿衡，太宰周公。藩屏汤武，立为侯王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '000110', '清人高子，久屯外野。逍遥不归，思我慈母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '011010', '三虫作蛊，削迹无与。胜母盗泉，居不安处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '010110', '作龙身，进无所前。三日五夜，得其所钦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '011101', '黄里绿衣，君服不宜。淫湎毁常，失其宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '101110', '天所顾佑，祸灾不到，安吉无惧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '001001', '盘纡九回，行道留难。止须千丘，乃睹所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '100100', '暴虐失国，为下所逐。北奔阴胡，主君旄头。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '110100', '御骍从龙，至霍华东。与禹相逢，送至子邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '001011', '铜人铁距，雨露劳苦。终日卒岁，无有休息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '001101', '大人失宜，盈满复亏。成长之木，盛者灭衰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '101100', '梅李冬实，国多盗贼。乱扰并作，王不能制。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '110110', '泽枯无鱼，山童难株。长女嫉妒，使身虚空。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '011011', '天门冬虚，晋季为灾。膉暌默苍，秦伯受殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '110010', '褰衣涉河，水深渍衣。赖幸舟子，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '010011', '推车上山，高仰重难。终日至暮，不见阜颠。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '110011', '鼎易其耳，热不可举。大路壅塞，旅人辛苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '001100', '四乱不安，东西为患。退身止足，无出邦域。乃得完全，赖其生福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '010101', '班马还师，以息劳疲。役夫嘉喜，入户见妻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110000', '101010', '积德不怠，遇生逢时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '101001', '麒麟凤凰，善政得祥。阴阳和调，国无灾殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '111111', '北风相牵，提笑语言。伯歌叔舞，燕乐以喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '000000', '甲戊己庚，随时运行。不失常节，咸逢出生。各乐其类，达性任情。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '010001', '破亡之虚，神所忧衰。进德无光，留止有庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '100010', '注斯膏泽，祈卫百毒。防以江南，虺不能螫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '010111', '日月相望，光辉盛昌。三圣成功，仁德大降。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '111010', '大蛇巨鱼，战于国郊。上下济塞，卫侯庐漕。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '000010', '龙入天关，经历九山。登高上下，道里险难。日晏不食，绝无甘酸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '010000', '沙漠北塞，纯无水泉。君子征凶，役夫力殚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '110111', '关柝门启，衿带解堕。福与善生，忧不为祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '111011', '狼虎所嗥，患害必遭。不利有为，宜以遁逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '000111', '金精耀怒，带剑过午。两虎相距，弓弩满野，虽忧无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '111000', '朽根枯树，华叶落去。卒逢火焱，相随偃仆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '111101', '入和出暗，动作有光。转运休息，常乐允康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '101111', '国多忌讳，大人恒畏。结口无患，可以长存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '000100', '天地淳亨，六合光明。阴序阳顺，厥功以成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '001000', '裸裎逐狐，为人观笑。牝鸡鸣晨，主作乱妖。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '011001', '阴失阳复，桀失其室，相餧不食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '100110', '蜎飞蠢动，各有配偶。大小相保，咸得其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '000011', '鬼守我庐，欲呼伯去。曾孙寿考，司命不许。与生相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '110000', '祸走患伏，喜为我福。凶恶消亡，灾害不作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '100101', '智不别扬，张诳妄行。陷渊仆颠，伤杀伯身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '100000', '凶忧灾殃，日益明章。祸不可救，三都夷伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '000001', '长尾蜲蛇，画地为河。深不可涉，绝无以北。怅然愤息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '111001', '爱我婴女，牵引不与。冀幸高贵，反曰下贱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '100111', '凫游江湖，甘乐其饵。既不近人，虽惊不骇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '100001', '明灭光息，不能复食。精魄既丧，以夜为室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '011110', '奇适无偶，习静独处。所愿不从，心思劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '010010', '葛藟蒙棘，花不得实。谗乱政，使忠壅塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '101101', '鹊笑鸠舞，来遗我酒。大喜在后，授我龟纽。龙喜张口，超拜福祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '011100', '摇尾逐灾，云孽辟除。洿泥生粱，下为田主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '001110', '白鹤衔珠，夜食为明。膏润优渥，国岁年丰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '111100', '内执柔德，止讼以默。宗邑赖德，祸灾不作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '001111', '犬吠惊骇，公拔戈起。元冥厌火，消散瓦解。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '101000', '公悦妪喜，子孙俱在。荣誉日登，福禄来处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '000101', '鸟鸣捕，长欲飞去。循枝上下，适与风遇。颠损树根，命不可救。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '110101', '析薪炽酒，使媒求妇。和合齐宋，姜子悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '101011', '邻不我顾，而望玉女。身多疣癞，谁当媚者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '010100', '远视无光，不知青黄。黈纩塞耳，使君闇聋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '001010', '克身整己，逢禹巡狩。赐我元圭，蒙受福佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '100011', '远望千里，不见黑子。离娄之明，无益于光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '110001', '斧斤所斫，疮疣不息。针口不施，下即空室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '011111', '齐侯少子，才略美好。求我长女，贱薄不与。反得丑陋，后乃大悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '111110', '失俪后旅，天门地户。不知所在，安止无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '011000', '乌孙氏女，深目黑丑。嗜欲不同，过时无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '000110', '伯驾纯骝，南至东华。求索车马，道阙中止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '011010', '二女宝珠，误郑大夫。君父无礼，自为作笑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '010110', '阳城太室，神明所息。仁者之君，独无兵革。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '011101', '反（蛇为殃，使道不通。岁收甚少，年谷败伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '101110', '三足孤鸟，灵明为御。司过罚恶，自残其家。毁败为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '001001', '车驾两靷，绝马欲步。双轮脱行，至道遇害。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '100100', '郁映不明，为阴所伤。众雾丽集，共夺日光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '110100', '鹯枭，治城御灾。周公勤劳，绥得安家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '001011', '名成德就，项领不试。景公耄老，尼父逝去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '001101', '一夫两心，岐刺不深。所为无功，求事不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '101100', '羿张乌号，彀射天狼。赵国雄勇，败于荥阳。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '110110', '东家杀牛，污臭腥臊。神皆西顾，命衰绝周。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '011011', '火起我后，喜炙吾庐。苍龙衔水，泉噀屋柱，虽难无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '110010', '桃雀窃脂，巢于小枝。摇动不安，为风所吹。寒心飘摇，常忧殆危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '010011', '徒足去域，飞入东国。有所畏避，深藏远匿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '110011', '璚英朱草，仁政得道。凫鹥在渚，福禄来下。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '001100', '陈蔡之厄，从者饥瘦。明德上通，忧不为凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '010101', '春桃生花，季女宜家。受福多年，男为邦君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101001', '101010', '径邪贼田，政恶伤民。夫妇咒诅，太山覆颠。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '100101', '仁政不暴，凤凰来舍。四时顺节，民安其居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '111111', '八口九头，长舌破家。帝辛沈湎，商灭其墟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '000000', '鬼守我门，呼伯入山。去其室家，舍其兆墓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '010001', '日出阜东，山蔽其明。章甫荐履，箕子佯狂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '100010', '戴盆望天，不见星辰。顾小失大，福逃墙外。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '010111', '两轮日转，南上大阪。四马共辕，无有重难。与语笑言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '111010', '羊惊狼虎，耸耳群聚。行旅稽难，留连愁苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '000010', '楩生荆山，命制输班。袍衣剥脱，夏热冬寒。饥饿枯槁，众人莫怜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '010000', '鸟飞无翼，兔走折足。不常其德，自为羞辱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '110111', '条风制气，万物出生。明庶长养，花叶壮茂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '111011', '坤厚地德，万物蕃息。平康正直，以绥大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '000111', '昴毕附耳，将军乘怒。路径隔塞，燕雀惊骇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '111000', '东风启户，黔啄翻舞。各乐其类，咸得生处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '111101', '两足四翼，飞入家国。宁我伯姊，与母相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '101111', '岁暮花落，阳入阴室。万物伏匿，岁不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '000100', '释然远咎，避患高阜。田获三狐，以贝为宝。君子所在，安宁不殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '001000', '迁延却缩，不见头目，日以困急。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '011001', '秋隼冬翔，数被严霜。雄犬夜鸣，家扰不宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '100110', '班马还师，以息劳疲。役夫嘉喜，入室见妻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '000011', '老杨日衰，条多枯枝。爵级不进，遂至摧隤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '110000', '顺风吹火，牵骑骥尾。易为功力，因惧受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '101001', '六人俱行，各遗其囊。黄鹄失珠，无以为明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '100000', '依叔墙隅，志下心劳。楚王晨食，韩子低头。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '000001', '三年生狗，以戌为母。荆夷上侵，姬伯出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '111001', '鹤盗我珠，逃于东都。鹄起追求，郭氏之墟。不见踪迹，反为祸灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '100111', '外与中退，举事不遂。餔麋毁齿，失其道理。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '100001', '鸿鹄高飞，鸣求其雌。雌来在户，雄哺嘻嘻。甚独劳苦，炮鳖脍鲤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '011110', '褰衣涉河，水深渍衣。幸赖舟子，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '010010', '虎啮龙指，泰山之崖。天命不佑，不见其雌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '101101', '明不处暗，智不履危。终年卒岁，乐以笑歌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '011100', '三足俱行，倾危善僵。六指不便，慁累弟兄。树柱阂车，失其正当。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '001110', '含车而徒，亡其驳牛。虽丧白头，酒以疗忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '111100', '析薪炽酒，使媒求妇。和合齐宋，姜子悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '001111', '夜视无明，不离商贾。子反笑欢，与市为仇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '101000', '徒行离车，厌泥涂，利以休居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '000101', '作室山根，人以为安。一夕崩巅，破我飧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '110101', '东山西山，各自言安。虽相登望，竟未同堂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '101011', '君子在朝，凶言消去。惊骇逐狼，不见雄英。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '010100', '慎慎，火烧山根。不润我邻，独不蒙恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '001010', '南山之蹊，真人所游。德配唐虞，天命为子。保佑歆享，身受大庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '100011', '龙蛇所聚，大小来处。泱泱霈霈，淡淡磕磕。使我无赖。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '110001', '旃裘若阖，慕德献服。边鄙不悚，以安王国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '011111', '光体春成，陈仓鸡鸣。阳明失道，不能自守。消亡为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '111110', '下泉苞稂，十年无王。荀伯遇时，忧念周京。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '011000', '仁德不暴，五精就舍。四序允厘，民安其居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '000110', '隋和重宝，众所贪有。相如睨柱，赵王危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '011010', '凤生五雏，长于南郭。君子康宁，悦乐身荣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '010110', '二人为旅，俱归北海。入门上堂，拜谒王母。劳赐我酒，女功不喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '011101', '逐忧除殃，洿泥生粱，下田为王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '101110', '东门之墠，茹藘在阪。礼义不行，与我心反。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '001001', '凫遇稻芦，甘乐，虽驱不去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '100100', '清人高子，久屯外野。逍遥不归，思我君母。公子谒请，王孙嘉许。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '110100', '谗所言，语不成全。虎狼之患，不为我残。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '001011', '张罗捕鸠，鸟丽其灾。雌雄俱得，为网所贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '001101', '安仁尚德，东邻慕义，来安吾国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '101100', '猾丑假诚，前后相违。言如鳖咳，语不可知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '110110', '怀璧越乡，不可远行。蔡侯两裘，久苦流离。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '011011', '伯氏归国，多所恨惑。车顿盖倾，身常惊惶。乃得其愿，雌雄相从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '110010', '火石相得，乾无润泽，利少囊缩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '010011', '君明圣哲，鸣呼其友。显德之徒，可以礼仕。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '110011', '骑豚逐羊，不见所望。径涉虎庐，亡豚失羊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '001100', '元黄虺隤，行者劳罢。役夫憔悴，处子猥衰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '010101', '右手掩目，不见长叔。失其所得，悔吝相仍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100101', '101010', '免冠进贤，步出朝门。仪体不正，贼孽为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '100000', '行触大讳，与司命忤。执囚束缚，拘制于吏。忧人有喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '111111', '穿胸狗邦，僵离旁舂。天地易纪，日月更始。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '000000', '从风纵火，荻芝俱死。三害集房，十子中伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '010001', '北山有枣，橘柚所聚。荷囊载担，香盈筐筥。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '100010', '金赎狸，不听我辞。系于虎须，牵不得来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '010111', '上下惟邪，寡妇无夫。欢心隔塞，君子离居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '111010', '二人辇车，徙去其家。并沸釜鸣，不可安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '000010', '蹇驴不才，骏骥失时。筋力劳尽，罢于沙丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '010000', '明伤之初，为穆出郊。以谗复归，名曰竖牛。剥乱叔孙，饫于空丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '110111', '天火大起，飞鸟惊骇。作事不时，为多咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '111011', '土与山连，共保岁寒。终无灾患，万世长安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '000111', '日出阜东，山蔽其明。章甫荐履，箕子佯狂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '111000', '龙马上山，绝无水泉。喉焦唇乾，口不能言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '111101', '雄处弱水，雌在海滨。将别持食，悲哀于心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '101111', '庭燎夜明，追嗣日光。阳软不至，阴雄生戾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '000100', '三妇同夫，忽不相思。志恒不愁，颜色不怡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '001000', '鹤盗我珠，逃于东都。鹄怒追求，郭氏之墟。不见踪迹，反为患灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '011001', '沐猴冠带，盗在非位。众犬共吠，仓狂蹶足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '100110', '黍稷禾稻，垂亩方好。中旱不雨，伤风病稿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '000011', '雄圣伏名，人匿麟远。走凤飞北，乱祸未息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '110000', '三母多福，天禄所伏。居之宠光，君子有福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '101001', '被服文德，升入大麓。四门雍肃，登受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '100101', '褰裳涉河，水流渍衣。幸赖舟子，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '000001', '班马还师，以息劳疲。役夫嘉喜，入户见妻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '111001', '东邻嫁女，为王妃后。庄公筑馆，以尊王母。归于京师，季姜悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '100111', '百足俱行，相辅为强。三圣翼事，王室宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '100001', '危坐至暮，请求不得。膏泽不降，政戾民忒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '011110', '百川朝海，泛流不止。路虽辽远，无不到者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '010010', '乘骝驾骊，东至于济。遭遇仁友，送我以资。厚得利归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '101101', '礼坏乐崩，阴请不当。成子傲慢，为简生殃。欲求致理，力疲心烂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '011100', '一人辇车，乘入虎家。王母贪饕，盗我犁牛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '001110', '羊头兔足，少肉不饱。漏囊败粟，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '111100', '新田宜粟，上农得谷。君子怀德，以千百福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '001111', '夷羿所射，发辄有获。双凫俱得，利伐王国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '101000', '凫舞鼓翼，嘉乐尧德。虞夏美功，要荒宾服。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '000101', '登丘上山，对酒遇欢。终年卒岁，优福无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '110101', '岁暮花落，阳入阴室。万物伏匿，藏不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '101011', '螟虫为贼，害我禾谷。箪瓶空虚，饥无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '010100', '阳虎胁主，使德不通。炎离为殃，年谷患伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '001010', '四马共辕，东上泰山。骍骊同力，无有重难。与君笑言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '100011', '牧羊稻园，闻虎喧讙。畏惧悚息，终无祸患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '110001', '阳花不时，冬实生危。忧多横贼，生不能服。昆仑之玉，取求必得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '011111', '高阜所在，阴气不淋。洪水不处，为家利宝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '111110', '释然远咎，避患革害。田获三狐，以贝为宝。君子所在，安宁不殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '011000', '两目失明，日夺无光。胫足跛曳，不可以行。顿于丘旁，亡妾莫逐。嵬然独宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '000110', '鸿飞循陆，公出不复，伯氏客宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '011010', '佩玉累蕊，无以系之。孤怨独处，愁哀相忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '010110', '载船渡海，虽深何咎。孙子俱在，不失其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '011101', '鹄求鱼食，道遇射弋。缯加我颈，缴缚两翼。欲飞不能，为羿所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '101110', '泥面乱头，忍耻少羞，日以削消。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '001001', '桑方将落，陨其黄叶。失势倾倒，如无所立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '100100', '巨蛇大，战于国邦。上下隔塞，主君走逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '110100', '已动死，连商子。扬砂石，胡貉扰。军鼓振，吏士恐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '001011', '张罗搏鸠，鸟丽其灾。雌雄俱得，为网所灭。贲之归妹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '001101', '三圣相辅，鸟兽喜舞。安乐富有，二人谐偶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '101100', '三奇六耦，相随俱市。王孙善贾，先得利宝。居止不移，大盗为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '110110', '三人俱行，一人言北。伯叔欲南，少叔不得。中路分道，争斗相贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '011011', '播天舞地，扰乱神所。居乐无咎，言不信误。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '110010', '坐争立讼，纷纷汹汹。幸成祸乱，灾及我公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '010011', '蛇行蜿蜒，不能上阪。履节安居，可以无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '110011', '隙大墙坏，蠹众木折。狼虎为政，天降罪伐。高杀望夷，胡亥以毙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '001100', '阳不违德，高山多泽。颜子逐兔，未有所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '010101', '心多畏恶，时愁日惧。虽有小咎，终无大悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100000', '101010', '众神集聚，相与议语。南国虐乱，百姓愁苦。举师征讨，别立贤主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '000001', '周师伐纣，克于牧野。甲子平旦，天下悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '111111', '任武负力，东征不伏。陷履泥涂，雄师败覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '000000', '义不胜情，以欲自营。觊利危躬，折角摧颈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '010001', '悬貆素餐，食非其任。失舆剥庐，休坐徙居，室家何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '100010', '鹠鸱娶妇，深目窈身。折腰不媚，与伯相背。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '010111', '东风解冻，河川流通。西门子产，升擢有功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '111010', '三足俱行，倾危善僵。六指不便，累慁弟兄。树柱阂车，失其正当。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '000010', '京庾积仓，黍稷以兴。亟行疾至，以厌饱食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '010000', '南山之蹊，真人所在。德配唐虞，天命为子。保佑歆享，身受大庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '110111', '车驰人趋，卷甲相仇。齐鲁寇战，败于犬丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '111011', '十五许室，柔顺有德。霜降归嫁，夫以为合。先王日至，不利出域。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '000111', '任力劣薄，远托邦国。辅车不僵，为痈所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '111000', '千载旧室，将有困急。荷粮负囊，出门直北。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '111101', '恶灾殆盈，日益章明。祸不可救，三郄夷伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '101111', '冠危载患，身惊不安。与祸驰逐，凶来入门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '000100', '虎狼并处，不可以事。忠谋转改，祸必及己。退隐深山，身乃不殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '001000', '卵与石斗，糜碎无处。挈瓶之使，不为忧惧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '011001', '五心六意，岐道多怪。非君本志，生我恨悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '100110', '雨雪载涂，东行破车，旅人无家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '000011', '尚利坏义，月出平地。国乱天常，咎征灭亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '110000', '东行破车，步入范家。衡门穿射，无以为主。卖袍续食，糟糠不饱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '101001', '逐金出门，并失玉丸。往来井上，甑破缺盆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '100101', '春孟醴酒，使君寿考。南山多福，宜行贾市。秋梁雌雉，所至利喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '100000', '持刃操肉，对酒不食。夫亡从军，长子入狱，抱膝独宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '111001', '踦牛伤暑，不能成亩。草莱不垦，年岁无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '100111', '南邦大域，鬼魅满室。讙声相逐，为我行贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '100001', '噂噂所言，莫如我垣。欢乐坚固，可以长安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '011110', '尧舜禹汤，四圣敦仁。允施德音，民安无穷。旅人相望，未同朝卿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '010010', '桎梏拘获，身入牢狱。髡刑受法，终不得释。耳闭道塞，求事不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '101101', '跖并桀处，民困愁苦。行旅迟迟，留连齐鲁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '011100', '求鸡获雉，买鳖失鱼。出入均货，利得无余。齐姜宋子，婚姻孔喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '001110', '雨师驾驷，风伯吹云。秦楚争强，施不得行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '111100', '仲冬兼秋，鸟散饮忧。困于米食，数惊鹯鵰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '001111', '三羝上山，俱至阴安。遂到南阳，完其芝香。两崖相望，未有枕状。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '101000', '飞之日南，还归辽东。雌雄相从，和鸣雍雍。解我胸舂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '000101', '尧饮舜舞，禹拜上酒。礼乐所丰，可以安处。保我淑女。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '110101', '太乙置酒，乐正起舞。万神攸同，可以安处。绥我齿儿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '101011', '白马骍骝，生乳不休。富我商人，得利饶优。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '010100', '宛马疾步，盲师坐御。目不见路，中止不到。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '001010', '春桃萌生，万物华荣。邦君所居，国乐无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '100011', '把珠入口，蓄为玉宝。得吾所有，欣然嘉喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '110001', '襦烧裤燔，羸剥饥寒，病证冻挛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '011111', '水沬沉浮，沮湿不居，为心疾忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '111110', '行如桀纣，虽祷不佑。命衰绝周，文君乏祀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '011000', '蜉蝣戴盆，不能上山。脚摧跛蹶，损伤其头。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '000110', '长子入狱，妇馈母哭。霜降旬甚，向晦伏法。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '011010', '求犬得兔，请新遇故。虽不当路，踰吾旧舍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '010110', '鸟鸣葭端，一呼三颠。动摇东西，危而不安。灵符祷祉，疾病无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '011101', '天厌禹德，命兴汤国。祓社衅鼓，以除民疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '101110', '阴雾作匿，不见白日。邪径迷通，使君乱惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '001001', '猿堕乔木，不跛手足。握珠怀玉，还归我室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '100100', '三骊负衡，南取芝香。秋兰芬馥，盈满箧筐，利我少姜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '110100', '春生孚乳，羽毛成就。举不失宜，君臣相好。盗走奔北，终无所悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '001011', '东行破车，还反室家。天命讫终，无所祷凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '001101', '九雁列阵，雌独不群。为罾所牵，死于庖人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '101100', '二人辇车，从去其家。井沸釜鸣，不可以居。从疑作徙）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '110110', '闭塞复通，与丧相逢。甘棠之人，解我忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '011011', '赋敛重数，政为民贼。杼轴空虚，家去其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '110010', '怒非其怨，贪妒腐鼠。而呼鹊鸱，自令失饵，倒被灾患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '010011', '簪短带长，幽思最苦。瘠貌少疲，以疾病降。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '110011', '三人俱行，各别采桑。蕴其筐筥，留我嘉侣。得归无咎，四月来处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '001100', '逐鸠南飞，与喜相随。井获鹿子，多得利归，虽忧无危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '010101', '驱羊南行，与福相逢。狼惊吾马，虎盗我子。悲恨自咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000001', '101010', '东邻西国，福喜同乐。出得隋珠，留获和玉。俱利有息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '111001', '夏台羑里，汤文厄处。皋陶听断，岐人悦喜。西望华首，东归无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '111111', '儋耳穿胸，缠离劳舂。天地易纪，日月更始。蝮螫我手，痛为吾毒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '000000', '慈母之恩，长大无孙。消息褓襁，害不入门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '010001', '言妄语，转相诖误。道左失迹，不知郎处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '100010', '郁映不明，阴积无光。日在北陆，万物雕藏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '010111', '主母多福，天禄所伏。居之宠昌，君子有光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '111010', '不耕而获，家食不给。中女无良，长子跛足。疏齿善市，商人有喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '000010', '火起上门，不为我残。跳脱东西，独得生完。不利山邻，病疾忧患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '010000', '持刃操肉，对酒不食。夫亡从军，少子入狱。抱膝独宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '110111', '虾去海，游于枯里。街巷迫狭，不得自在。南北四极，渴馁成疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '111011', '哑哑笑语，与欢饮酒。长乐行觞，千秋起舞。拜受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '000111', '登高上山，宾于四门。士伍得欢，福为我根。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '111000', '天厌周德，命与南国。以礼静民，兵革休息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '111101', '壅遏堤防，水不得行。火光盛阳，阴魄伏匿。走归其乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '101111', '河海都市，国之奥府。商人受福，少子玉石。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '000100', '东行避兵，南去不祥。西逐凶恶，北福生。与喜相逢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '001000', '东家中女，嫫母最丑。三十无室，媒伯劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '011001', '破亡之国，天所不福，难以止息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '100110', '骖驾蹇驴，日暮失时。居者无忧，保我乐娱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '000011', '蝃蝀之侧，佞幸倾惑。女谒横行，王道充塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '110000', '三羖五羊，相随并行。迷入空泽，有谷直北。径涉六驳，为所伤贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '101001', '戴喜抱子，与利为友。天之所命，不忧危殆。荀伯劳苦，西来王母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '100101', '织缕未就，针折不复。女工多态，乱我政事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '100000', '行露之讼，贞女不行。君子无食，使道壅塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '000001', '羿张乌号，彀射天狼。钟鼓不鸣，将军振攘。赵国雄勇，斗死荥阳。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '100111', '延颈望酒，不入我口。商人劳苦，利得无有。夏台羑里，难为复喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '100001', '冠带南游，与喜相期。邀于嘉国，拜位逢时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '011110', '东西触垣，不利出门。鱼藏深水，无以乐宾。爵级摧颓，光威咸衰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '010010', '两母千子，转息无已。五乳百雏，骍驳骧驹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '101101', '重祖后，司马太史。阳氏之灾，雕宫悲苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '011100', '内执柔德，止讼以默。宗邑赖福，祸灾不作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '001110', '采唐沬乡，邀期桑中。失信不会，忧思约带。巽之乾，师之噬嗑。一作牛骥同堂，郭氏以亡。国破为墟，君奔走逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '111100', '官成立政，衣就缺袂。恭谦为卫，终无祸尤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '001111', '麒麟凤凰，子孙盛昌。少齐在门，利以合婚。贵人大欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '101000', '乱危之国，不可涉域。机机发发，身顿僵覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '000101', '千雀万鸠，与鹞为仇。威势不敌，虽众无益。为鹰所击，万事皆失。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '110101', '众神集聚，相与议语。南国虐乱，百姓愁苦。兴师征讨，更立贤主。剥之末济。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '101011', '颜渊闵骞，以礼自闲。君子所居，祸灾不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '010100', '三桓子孙，世秉国权。爵势上卿，富于周公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '001010', '鹤鸣九皋，处子失时。载土贩盐，难为功力。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '100011', '方轴圆轮，车行不前。组囊以锥，失其事便。还师振旅，兵革休止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '110001', '鱼扰水浊，桀乱我国。驾龙出游，东之乐邑。天赐我禄，与生为福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '011111', '白虎黑狼，伏伺山阳。遮遏牛羊，病我商人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '111110', '履危不安，疏颠我颜，伤肿为瘢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '011000', '三人辇车，东入旁家。主母贪饕，盗我资财。亡失犁牛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '000110', '三鹤南飞，俱就塘池。虾饶有，利得过倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '011010', '鹰栖茂树，候雀往来。一击获两，利在枝柯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '010110', '尧舜钦明，禹稷股肱。伊尹往来，进履登堂。显德之徒，可以辅王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '011101', '枯旱三年，草莱不生。粢盛空乏，无以供灵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '101110', '方口圆舌，为知枢门。解释钩带，商旅以欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '001001', '凫池水溢，高陆为海。江河横流，鱼鳖成市。千里无墙，鸳凤游行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '100100', '烹鱼失刀，驾车马亡。锡刃不入，鲂鲤腥臊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '110100', '戎狄蹲踞，无礼贪饕。非吾族类，君子攸去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '001011', '渡河踰水，狐濡其尾。不为祸忧，捕鱼遇蟹。利得无几。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '001101', '河出小鱼，不宜劳烦。苛政害民，君受其患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '101100', '偃武修文，兵革休安。清人逍遥，来归空闲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '110110', '九疑郁林，沮湿不中。鸾鸟易去，君子不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '011011', '搏逢虎，患厌不起。遂至欢国，与福笑语。君子乐喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '110010', '狗生龙马，公劳妪苦。家无筐筥，折悔为吝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '010011', '婴孩求乳，慈母归子。黄麑悦喜，得其甘饵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '110011', '有两赤鹞，从五隼噪。操矢无筈，趣释尔射。扶伏听命，不敢动摇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '001100', '伊尹智士，去桀耕野。执顺以强，天佑无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '010101', '逐鹿山西，利入我门。阴阳和调，国无灾殃。长子东游，须其三仇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111001', '101010', '龙兴之德，周武成福。长女宜家，与君相德。长股远行，狸且善藏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '100111', '朝鲜之地，姬伯所保。宜人宜家，业处子孙。求事大喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '111111', '金柱铁关，胶固卫灾。君子居之，安无忧疑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '000000', '转祸为福，喜来入屋。春城夏国，可以饮食。保全家室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '010001', '水暴横行，浮屋坏墙。泱泱溢溢，市师惊惶。居止不殆，与母相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '100010', '虎豹熊罴，游戏山隅。得其所欲，君子无忧。旅人失利，市空无人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '010111', '躬礼履仁，尚德止讼。宗邑已安，三伯无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '111010', '江淮易服，元黄朱饰。灵公夏征，哀祸无极。高位崩巅，失其宠室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '000010', '不虞之患，祸至无门。奄忽暴卒，痛伤我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '010000', '三涂五岳，去危入室。凶祸不作，桀盗尧服。失其宠福，贵人有疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '110111', '配合相迎，利之四乡。昏以为期，明星煌煌。欣喜奭怿，所言得偿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '111011', '三首六身，莫适所闲。更伏摇动，动失事便。箕子佯狂，国乃不昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '000111', '虎卧山隅，鹿过后胊。弓矢设张，猬为功曹。伏不敢起，遂全其躯。得我羙章之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '111000', '麟凤执获，英雄失职。自卫反鲁，畏昧不起。福禄讫己。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '111101', '栾子作殃，伯氏诛伤。州犁奔楚，失其宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '101111', '黄帝出游，驾龙乘马。东至泰山，南过齐鲁。王良御右，文武何咎。不利市贾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '000100', '齐鲁争言，战于龙门。构怨致祸，三世不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '001000', '道礼和德，仁不相贼。君子往之，乐有其利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '011001', '妪妒公姥，毁益乱类。使我家愤，利不得遂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '100110', '一巢九子，同公共母。柔顺利贞，君子不殆。福禄所在。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '000011', '崔嵬北岳，天神贵客。温仁正直，主布恩德。闵哀不已，蒙受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '110000', '三蛆逐蝇，陷堕釜中。灌沸淹殪，与母长诀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '101001', '东山西陵，高峻难升。灭夷掘垒，使道不通。商旅无功，复反其邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '100101', '常德自如，不逢祸殃，福禄自来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '100000', '范子妙材，戮辱伤肤。后相秦国，封为应侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '000001', '狼虎结谋，相聚为俦。同啮牛羊，道绝不通。病我商人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '111001', '不宜杜公，与我争讼。媒伯无礼，自令塞壅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '100001', '上天楼台，登拜受福，喜庆大来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '011110', '三羊上山，东至平康。黄龙服箱，南至鲁阳。完其佩囊，执绥车中。行人有庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '010010', '天地闭塞，仁智隐伏。商旅不行，利深难得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '101101', '延陵适鲁，观乐太史。车辚白颠，知秦兴起。卒兼其国，一统为主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '011100', '櫜戢甲兵，归放马牛。径路开通，国无凶忧。一下有朽墙难凿，疾病难治。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '001110', '牛骥同堂，郭氏以亡。国破为垆，君奔走趍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '111100', '大尾小腰，重不可摇。栋挠壤坏，臣为君忧。汤火之言，消不为患，使我复安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '001111', '太乙置酒，乐正起舞。万福攸同，可以安处。保我齯齿。一下有暗空无饵，不利为旅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '101000', '饮酒醉酗，跳起争斗。伯伤叔僵，东家治丧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '000101', '陵险难登，涧中多石。车驰击，重载伤轴。担负善踬，跌踒右足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '110101', '争讼不已，更相咨询。张李弱口，被发北走。一下有耳顺从心，躬行至仁。不须以兵，天下太平。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '101011', '心志无良，伤破妄行。触墙抵壁，不见户房。先王闭关，商旅委弃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '010100', '鸋鴂鸱鸮，治成御灾。绥德安家，周公勤劳。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '001010', '清人高子，久屯外野。逍遥不归，思我慈母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '100011', '两虎争斗，股创无处。不成仇雠，行解却去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '110001', '天女推床，不成文章。南箕无舌，饭多沙糠。虐众盗名，雄鸡折颈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '011111', '太子扶苏，出于远郊。佞幸成邪，改命生忧。慈母之恩，无路致之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '111110', '寒暑相推，一明一微。赫赫宗周，荣光灭衰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '011000', '鸡狗相望，仁道笃行。不吠昏明，各安其乡。周鼎和饵，国富民有。八极蒙佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '000110', '窗牖户房，通利明光。贤智辅圣，仁施大行。家给人足，海内殷昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '011010', '雨雪三月，鸟兽饥乏。旅人失宜，利不可得。机言解患，以疗笃难，危身复安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '010110', '白鹤衔珠，夜食为明。膏润优渥，国岁年丰。中子来同，见恶不凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '011101', '从豕牵羊，与虎相逢，虽惊不凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '101110', '凫雁哑哑，以水为宅。雌雄相和，心志娱乐。得其所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '001001', '逐狐平原，水遏我前。深不可涉，暮无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '100100', '窟室蓬户，寒贱所处。千里望烟，涣散四方。形体灭亡，下入深渊，终不见君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '110100', '桀纣之主，悖不堪辅。贪荣为人，必定其咎。聚敛积实，野在都邑，未来我室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '001011', '仓库盈亿，年岁有息。商人留连，虽久有得。阴多阳少，因地就力。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '001101', '泰山不然，钓鲤失纶。鱼不可得，利去我北。一作三人同福，以兴周国，君子安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '101100', '童女无媒，不利动摇。安其室庐，待母动忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '110110', '载风云母，游观东海。鼓翼千里，见吾爱子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '011011', '鸿盗我襦，逃于山隅。不见其迹，使伯心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '110010', '夜视失明，不利远乡。闭门塞牖，福为我母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '010011', '三狗逐兔，于东门路。利以进取，商人有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '110011', '武王不豫，周公祷谢。载璧秉珪，安宁如故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '001100', '同载共车，中道别去。爵级不进，君子下舆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '010101', '六雁俱飞，游戏稻池。大饮多食，食饱无患。一下有举事不遂，商旅作僓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100111', '101010', '符左契右，相与合齿。乾以坤利，季生六子。长大成就，风言如母，不利为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '100001', '家给人足，颂声并作。四夷宾服，干戈卷阁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '111111', '思初道古，哀吟无辅。阳明不制，上失其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '000000', '江淮河海，天之奥府。众利所聚，可以饶有。乐我君子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '010001', '三雁俱飞，避暑就凉。适与矰遇，为缴所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '100010', '秋南春北，随时休息。处和履中，安无忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '010111', '履危无患，逃脱独全。不利出门，伤我左膝。疾病不食，鬼哭其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '111010', '东家凶妇，怨其公姥。毁盘破盆，弃其饭餐。使我困贫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '000010', '泥滓污辱，弃捐沟渎。众所笑哭，终不显录。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '010000', '旦往暮还，吝与相存，身无患凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '110111', '六翮长翼，夜过射国，羿氏无得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '111011', '蜂虿之国，难以止息。嘉媚之士，为王所食。从去其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '000111', '被乘龙，为王道东。过时不返，使我忧聋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '111000', '雪梅零坠，心思愦愦。怀忧少愧，乱我魂气。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '111101', '长女三嫁，进退多态。牝狐作妖，夜行离忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '101111', '轰轰，驱东向西。盛盈必毁，高位崩颠。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '000100', '乘船涉济，载水逢火。赖得无患，蒙我全生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '001000', '德至之君，政仁且温。伊吕股肱，国富民安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '011001', '生不逢时，困且多忧。无有冬夏，心常悲愁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '100110', '南历玉山，东入生门。登福上堂，饮万岁浆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '000011', '大斧斫木，谗人败国。东关二五，祸及三子。晋人乱危，怀公出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '110000', '一室百孙，公悦妪欢。相与笑言，家乐以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '101001', '随阳转行，不失其常。君安于乡，国无咎殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '100101', '群虎入邑，求索肉食。大人御守，君不失国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '100000', '弱足刖跟，不利出门。商贾无赢，折崩为患。汤火之忧，转解喜来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '000001', '夏台幽户，文王厄处。鬼侯饮食，岐人悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '111001', '栋挠壤坏，廊屋大败。宫阙空廓，如冬枯树。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '100111', '谗以内安，不利其国。室家大惧，幽囚重闭。疾病多求，罪乱愤愦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '011110', '六龙俱怒，战于陂下。苍黄不胜，旅人艰苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '010010', '天下雷行，尘起不明。市空无羊，疾人忧凶。三木不喜，脱归家邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '101101', '一指食肉，口无所得。染其鼎鼐，舌馋于腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '011100', '喜笑不常，失其福庆。口辨言疥，行者畏忌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '001110', '毛生毫背，国乐民富，侯王有德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '111100', '豮豕童牛，害伤不来。三光同堂，生我福仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '001111', '江河淮济，盈溢为害。邑被其癞，年困无岁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '101000', '两虎争斗，股疮无处。不成仇雠，行解却去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '000101', '五岳四渎，润洽为德。行不失理，民赖恩福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '110101', '载车乘马，南逄君子。与我嘉福，离忧无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '101011', '缺囊破筐，空无黍粱。不媚始公，弃于粪场。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '010100', '杀行桃园，见虎东还。螳螂之敌，使我无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '001010', '箕仁入室，政衰弊极。抱其彝器，奔于他国。因祸受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '100011', '庭燎夜明，追古伤今。阳弱不制，阴雄坐戾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '110001', '悬貆素餐，食非其任。失舆剥庐，休坐徙居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '011111', '嘉闻福喜，缯帛盛织，日就为得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '111110', '执绥登车，骖乘东游。说齐解燕，霸国以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '011000', '水深无桴，蹇难何游。商伯失利，庶人愁忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '000110', '三鸟鸳鸯，相随俱行。南到饶泽，食鱼与粱。君子长乐，见恶不伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '011010', '远视目盻，临深苦眩。不离越都，旅人留难。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '010110', '终风东西，涣散四方。终日至暮，不见子欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '011101', '言无要约，不成券契。殷叔季姬，公孙争之。强入委命，不悦我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '101110', '牛马聋聩，不知声味。远贤贱仁，自令乱愦。疾病无患，生福在门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '001001', '从商近游，食饱无忧。囹圄之困，中子见囚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '100100', '据斗运枢，顺天无忧，与乐并居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '110100', '姬奭姜望，为武守邦。藩屏燕齐，周室以强。子孙亿昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '001011', '亡羊东泽，循堤直北。子思其母，随返其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '001101', '张鸟开口，舌直距齿。然诺不行，政乱无绪。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '101100', '载船逢火，忧不为祸。家在山东，入门见公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '110110', '绝国异路，心不相慕。蛇子两角，使我相恶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '011011', '鼻项移徙，居不安坐。枯竹后生，失其宠荣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '110010', '火息无光，千岁不长，殷汤远明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '010011', '文王四乳，仁孝笃厚。子蓄十男，无有折夭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '110011', '熊罴豺狼，在山阴阳。伺鹿取麞，道伏畏难。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '001100', '雕叶被霜，独蔽不伤。驾入喜门，与福为婚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '010101', '黄离白日，照我四国。元首昭明，民赖为福。一下有汉有游女，人不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100001', '101010', '顺风直北，与欢相得。岁熟年丰，邑无寇贼。一下有长女行嫁，子孙不昌，弃疾为殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '011110', '典册法书，藏在兰台。虽遭乱溃，独不遇灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '111111', '日在北陆，阴蔽阳目。万物空虚，不见长育。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '000000', '鬼泣哭社，悲商无后。甲子昧爽，殷人绝祀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '010001', '涉涂履危，不利有为。安坐垂堂，乃无灾殃。门户自开，君忧不昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '100010', '阳失其纪，枯木复起。秋华冬实，君不得失。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '010111', '大树之子，百条共母。当夏六月，枝叶盛茂。鸾凤以庇，召伯避暑。翩翩偃仰，各得其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '111010', '秉钺执殳，挑战先驱。不役元帅，败破为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '000010', '启室开门，巡狩释冤。夏台羑里，汤文悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '010000', '衰灭无几，渊溺在项。吠狗夜惊，家乃不宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '110111', '西邻小女，未有所许。志如委衣，不出房户。心无所处，傅母何咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '111011', '狗吠夜惊，履鬼头颈。危者弗倾，患者不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '000111', '当年少寡，独与孤处。鸡鸣犬吠，无敢难者。我生不辰，独婴寒苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '111000', '无道之君，鬼哭其门。命与下国，绝不得食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '111101', '乘龙南游，夜过糟丘，脱厄增忧。一下有缯绝鲁伤，羿不得美。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '101111', '马踬车伤，长舌破家。东关二五，晋君出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '000100', '瓜花瓠实，百女同室。酰苦不熟，未有配合。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '001000', '晨风文翰，火举就温。时过我邑，羿无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '011001', '浼浼促促，涂泥至毂。雨泞不进，虎囓不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '100110', '胶车驾东，与雨相逢。放革懈惰，顿禹（独坐。忧不为祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '000011', '六家作权，公室剖分。阴制其阳，唐叔失明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '110000', '去室离家，来奔大都。火息复明，姬伯以昌。商人失功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '101001', '牧羊稻园，闻虎喧讙。危惧喘息，终无祸患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '100101', '婴儿求乳，母归其子。黄麑悦喜，乃得甘饱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '100000', '廓落失业，跨祸变福，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '000001', '出入无时，忧患为灾。行人失牛，利去不来。若马遗驹，勿与久居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '111001', '风怒漂木，女感生疾。阳失其时，阴孽为贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '100111', '车马疾伤，不利越乡。幽人无贪，去晦就明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '100001', '三奇六耦，各有所主。周南召南，圣人所在。德义流行，民悦以喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '010010', '坐争立讼，纷纷哅哅。卒成祸乱，灾及家公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '101101', '凶忧为残，使我不安。从之南国，以除心疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '011100', '爱我婴女，牵引不得。冀幸高贵，反曰下贱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '001110', '宜行贾市，所取必倍。载喜抱子，与利为友。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '111100', '坐席未温，忧来扣门。踰墙北走，兵交我后。脱于虎口。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '001111', '赤帝悬车，废职不朝。叔带之灾，君子记庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '101000', '子畏于匡，厄困陈蔡。明德不危，竟自免害。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '000101', '逐雁南飞，马疾牛罢。不见鱼池，失利忧危。牢户之冤，脱免无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '110101', '推辇上山，高仰重难。终日至暮，不见阜巅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '101011', '忧不为患，福在堂门，使君偃安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '010100', '春桃生华，季女宜家。受福多年，男为邦君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '001010', '高山之巅，去地亿千。虽有兵寇，足以自守。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '100011', '过时历月，役夫憔悴。处子叹室，思我伯叔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '110001', '太微复明，说升傅岩，乃称高宗。一作疾在头颈，和不能生，灭其令名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '011111', '旁多小星，三五在东。早夜晨行，劳苦无功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '111110', '东乡烦烦，相与笑言。子般鞭革，圉人作患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '011000', '鼻移在头，枯苇复生。下朽上荣，家乃不宁。其舍不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '000110', '虾蟆群聚，从天请雨。云雷集聚，应时辄与。得其所愿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '011010', '大步上车，南到喜家。送我貂裘，与福载来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '010110', '贼仁伤德，天怒不福。斩刈宗社，失其土宇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '011101', '从猬见虎，虽危无殆，终已不处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '101110', '履行素德，卒蒙佑福。与尧侑食，君子有息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '001001', '利在北陆，寒苦难得。忧危之患，福为道门。商叔生存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '100100', '四蹇六盲，足痛难行。终日至暮，不离其邻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '110100', '台骀昧子，明知地理。障泽宣德，封居河涘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '001011', '畜水待时，以备火灾。柱车绊马，郊行出旅。可以无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '001101', '岁暮花落，君衰于德。荣宠殒坠，阴弃其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '101100', '夏败蔡悲，千里为市。黄落潱郁，利得无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '110110', '仲春巡狩，东见群后。昭德允明，不失其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '011011', '冽洁缧缧，缔构难解。嫫母衒嫁，媒不得坐。自为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '110010', '鸟噜夜中，以戒灾凶。重门击柝，备忧外客。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '010011', '朝霁暮露，纤我衣濡，道无行牛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '110011', '抱璞怀玉，与桀跖觞。诎坐不申，道无良人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '001100', '两心相悦，共其茀。夙夜在公，不离房中。得君子意。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '010101', '载馈茹田，破鉏失餐。苗稼不辟，独饥于年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011110', '101010', '甘露醴泉，太平机关。仁德感应，岁乐民安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '010010', '有鸟黄足，归呼季玉。从我睢阳，可避刀兵。与福俱行，有命久长。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '111111', '太王为父，季历孝友。文武圣明，仁德兴起。孔张四国，载福绥厚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '000000', '猿堕高木，不踒手足。保我全生，还归其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '010001', '重耳恭敏，遇谗出处。北奔戎狄，经涉齐楚。以秦代怀，诛杀子圉，身为伯主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '100010', '倚锋据戟，伤我胸臆，耗折不息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '010111', '狗冠鸡步，君失其所。出门抵山，行者忧难。水灌我园，高陆为泉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '111010', '众鸟所翔，中有大怪。丈身长颈，为我惊忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '000010', '虎行相逐，未有休息。战于平陆，为夷所覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '010000', '禹凿龙门，通利水泉。同注沧海，民得安然。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '110111', '尧舜仁德，养贤致福。众英积聚，国无寇贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '111011', '陆居少泉，山高无云。车行千里，涂不污轮。渴我为怨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '000111', '朝不见光，夜不见明。暝抵空床，季女奔亡。怆然心伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '111000', '齐鲁永国，仁圣辅德。造礼雅言，定公以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '111101', '束帛元圭，君以布德。伊吕百里，应聘辅国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '101111', '棘钩我襦，为绊所拘。灵巫拜祝，祸不成灾。东山之邑，中有肥土，可以饶饱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '000100', '门烧屋燔，为下所残。西行出户，顺其道理。虎卧不起，牛羊欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '001000', '墙高蔽目，昆仑翳日。远行无明，不见欢叔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '011001', '天地际会，不见内外。祖辞遣送，与世长诀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '100110', '深水难涉，泥涂至毂。牛罢不进，浮陷为疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '000011', '羊惊虎狼，猕猴群走。无益于僵，为齿所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '110000', '履蛇蹑虺，与鬼相视。惊恐失气，如骑虎尾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '101001', '车惊人倾，两轮脱去。行者不止，人生忧惧。结缔复解，夜明为喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '100101', '南贩北贾，与喜为市，利得百倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '100000', '延陵适鲁，观乐太史。车邻白颠，知秦兴起。卒兼其国，一统为主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '000001', '出门逢恶，与福为患。反相击刺，伤我手端。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '111001', '獐鹿群走，自然燕喜。公子好游，他人多有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '100111', '恭宽信敏，履福不殆。从其邦域，与喜相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '100001', '欲飞无翼，鼎重折足。失其福利，庖羞为贼。一下有上卿之家，富其蒙宰。喜除我忧，解吾思愁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '011110', '府藏之富，王以赈贷。捕鱼河海，布网多得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '101101', '阴生麓鹿，鼠舞鬼哭。灵龟陆处，釜甑尘生。仁智盘桓，国乱无欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '011100', '风尘坎坷，不见南北。行迷失利，复反其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '001110', '金革白黄，宜利戎市。嫁娶有息，商人悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '111100', '匏瓜之德，宜系不食。君子失舆，官正怀忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '001111', '乘船渡济，载水逢火。赖得免患，我有所持。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '101000', '道险多石，伤车折轴。与市为仇，不利客宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '000101', '托寄之徒，不利请求。结衿无言，乃有悔患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '110101', '三年争妻，相逐奔驰。终日不食，精气竭罢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '101011', '退恶防患，日之中息，解释倒悬。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '010100', '两足四翼，飞入家国。宁我伯姊，与母相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '001010', '寒露所凌，渐至坚冰。草木疮疡，花落叶亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '100011', '后稷农功，富利我国。南亩治理，一室百子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '110001', '设网张罗，捕鱼园池。网罟自决，虽得复失。危许之患，受其忻欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '011111', '路与县休，侯伯恣骄。上失其威，周室相微。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '111110', '逐走追亡，相及扶桑。复见其乡，使我悔丧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '011000', '履禄绥厚，载受福祉。衰微复起，继世长久。疾病无危，晋人起告。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '000110', '鳏寡孤独，禄命苦薄。入宫无妻，武子哀悲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '011010', '山没丘浮，陆为水鱼。燕雀无巢，民无室庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '010110', '冠带南游，与福喜期。遨游嘉国，拜位逢时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '011101', '东行亡羊，失其羝牂。少女无夫，独坐空庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '101110', '探巢捕鱼，耕田捕鳅。费日无功，右手虚空。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '001001', '东行饮酒，与喜相抱。福为我家，利来从母。水泽之徒，望邑而处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '100100', '妄怒失精，自令畏悔。怡怡之欢，君子无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '110100', '白云如带，往往来处。飞风送迎，大雹将下。击我禾稼，僵死不起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '001011', '南至之日，阳消不息。北风烈寒，万物藏伏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '001101', '火中仲夏，鸿雁解舍。体重难移，未能高举。君子显名，不失其誉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '101100', '北行出门，履蹈踬颠。踒足据涂，污我襦裤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '110110', '轻车醊祖，疾风暴起。促乱祭器，飞扬鼓舞。明神降佑，道无害寇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '011011', '酒为欢伯，除忧来乐。福喜入门，与君相索。使我有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '110010', '三足孤乌，虚鸣督邮。司过罚恶，自贼其家。毁败为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '010011', '三河俱合，水怒踊跃。坏我王屋，民饥于食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '110011', '南行枣园，恶虎畏斑。执火销锋，使我无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '001100', '求鹿过山，与利为怨。闇袭不言，谁知其欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '010101', '行旅困蹴，失明守宿。囹圄之忧，启蛰出游。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '101010', '据棘履杞，跌刺为忧。夫妇不和，乱我良家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '101101', '时乘六龙，为帝使东。达命宣旨，无所不通。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '111111', '执辔四骊，王以为师。阴阳之明，载受东齐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '000000', '春秋祷祀，解祸除忧，君子无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '010001', '坐朝乘轩，据国子民。虞叔受命，和合六亲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '100010', '门户下堂，与福相迎。禄于公室，曾孙以昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '010111', '高木腐巢，漏湿难居。不去甘棠，使我无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '111010', '三女为奸，俱行高园。倍室夜行，与伯笑言。不认主母，为设欢酒，冤尤谁祷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '000010', '漏卮盛酒，无以养老。春贷黍稷，年岁实有。履道坦坦，平安无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '010000', '松柏枝叶，常茂不落。君子欢宁，日富求乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '110111', '夫妇不谐，为燕攻齐。良弓不张，骑劫忧亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '111011', '出令不胜，反为大灾。强不克弱，君受其忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '000111', '奔走相错，败乱诸绪，民不得作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '111000', '载璧秉珪，请命于河。周公克敏，冲人瘳愈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '111101', '素车为马，不任重负。王侯出征，忧危为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '101111', '大树之子，百条共母。比之火中，枝叶盛茂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '000100', '壅遏堤防，水不得行。火盛阳光，阴蜺伏藏。走归其乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '001000', '五岳四渎，合润为德。行不失理，民赖恩福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '011001', '驾骏南游，虎惊我牛。阴不奉阳，其光灭蹴。訾之谦谦，奉义解患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '100110', '早霜晚雪，伤害禾麦。损功弃力，饥无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '000011', '岐周海隅，独乐无忧。可以避难，全身保财。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '110000', '阴蔽其阳，目暗不明。君忧其国，求骍得黄。驹犊从行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '101001', '金城铁廓，上下仝力。政平民欢，寇不敢贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '100101', '平公有疾，迎医秦国。和不能治，晋人疑惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '100000', '载尧扶禹，从乔彭祖。西遇王母，道路夷易。无敢难者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '000001', '羔羊皮革，君子朝服。辅政天德，以合万国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '111001', '振钟鼓乐，将军受福。安帖之家，虎狼为忧。履危不殆，师行何咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '100111', '嫡庶不明，孽乱生殃，陈失其邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '100001', '鸟惊孤鸿，乱国不宁。上弱下强，为阴所行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '011110', '被绣夜行，不见文章。安坐于堂，乃无咎殃。长子帅师，得其正常。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '010010', '六月采芑，征伐无道。张仲方叔，克胜饮酒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '011100', '昧暮乘车，东至伯家。踰梁越河，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '001110', '东风解冻，和气兆升，年岁丰登。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '111100', '三狸搏鼠，遮遏前后。死于圜域，不得脱走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '001111', '绥德孔明，履禄久长。贵且有光，疾病忧伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '101000', '三虎搏狼，力不相当。如摧腐枯，一击破亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '000101', '使伯采桑，狠不肯行。与叔争讼，更相毁伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '110101', '抱空握虚，鸮惊我雏，利去不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '101011', '李花再实，鸿卵降集。仁哲以兴，隆国不贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '010100', '东山皋落，勇悍不服。金瑛玩好，衣为身贼。丝麻不作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '001010', '飞蚊污身，为邪所率。青蝇分白，真孝放逐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '100011', '南山大木，丈身六目。制命出文，东里宣敷。尊主安居，郑国无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '110001', '泉起昆仑，西出玉门。流为九河，无有忧患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '011111', '命短不长，中年夭伤。思及哭堂，哀其子亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '111110', '君臣不和，上下失宜，宗子哀歌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '011000', '苛政日作，螟食华叶。割下啖上，民被其贼。秋无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '000110', '南行载铠，登履九魁。车伤牛罢，日暮嗟咨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '011010', '春东夏南，随阳有功，与利相逢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '010110', '头尾颠倒，不知绪处，君失其国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '011101', '言无要约，不成券契。殷叔季姬，公孙争之。强入委命，不悦子南。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '101110', '缺陷不成，胎卵不生，不见其形。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '001001', '见蛇交卧，惜蜒畏恶，心乃无悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '100100', '河水孔穴，坏败我室。水深无涯，鱼鳖倾倒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '110100', '五岳四渎，地得以安。高而不危，惊惧避患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '001011', '南至之日，阳消不息。北风冽寒，万物藏伏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '001101', '五利四福，俱田高邑。黍稷盛茂，多获高稻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '101100', '公孙驾车，载游东齐。延陵子产，遗我纻衣。疾病哀悲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '110110', '蛟虬当道，民困愁苦。望羊置群，长子在门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '011011', '金玉满堂，忠直乘危。三老冻饿，鬼夺我室。求鱼河海，网举必得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '110010', '日入明匿，阳精隐伏。小人心劳，求事不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '010011', '频逢招饮，失利后福。不如子息，旧器故杵。申请必得，乃无大悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '110011', '南有嘉鱼，惊黄取游。鲂鱮诩诩，利来无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '001100', '黄裳建元，文德在身。禄佑洋溢，封为齐君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '010101', '口不从心，欲东反西。与意乖戾，动举失便。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '101010', '虎狼之乡，日争凶讼。叨尔为长，不能定证。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '011100', '雌单独居，归其本巢。毛羽憔悴，志如死灰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '111111', '小窗多明，道里利通。仁贤君子，国安不僵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '000000', '心恶来恠，冲冲何惧。颜渊子骞，尼父圣诲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '010001', '鸟鸣呼子，哺以酒脯。高栖水起，来归其母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '100010', '国马生角，阴孽萌作。变易常服，君失于宅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '010111', '入年多悔，耕石不富。衡门屡空，使士失意。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '111010', '诸孺行贾，远涉山阻。与旅为市，不危不殆。利得十倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '000010', '梁破桥坏，水深多畏。陈郑之间，绝不得前。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '010000', '双凫俱飞，以归稻池。经涉萑泽，为矢所伤。损我胸臆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '110111', '谩诞不成，佶梁灭文。许人买牛，三夫争之。失利后时，公孙怀忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '111011', '南国饥凶，民食糟糠。少子困捕，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '000111', '狗吠非主，狼虎夜扰。惊我东西，不为家咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '111000', '望龙无目，不见手足。入水求玉，失其所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '111101', '以鹿为马，欺误其主。闻言不信，三口为咎。黄龙三子，中乐不殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '101111', '养幼新婚，未能出门。登宋望齐，不见太师。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '000100', '王孙贵子，相与为友。明允笃诚，升擢荐举。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '001000', '山水暴怒，坏梁折柱。稽旅难行，留连愁苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '011001', '鹯鸠徙巢，西至平州。遭逢雷电，碎我苕芦。室家饥寒，思吾故初。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '100110', '登高伤轴，土阪弃粟。贩盐不利，市贾折角。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '000011', '祝鮀王孙，能事鬼神。节用绥民，卫国以存。眉寿多年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '110000', '九里十山，道却峻难。牛马不前，复反来还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '101001', '枯树不花，空渊无鱼。旧鸟飞翔，利弃我去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '100101', '雄狐绥遗，登山崔嵬。昭告显功，大福允兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '100000', '哑哑笑言，与欢饮酒。长乐行觞，千秋起舞。拜受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '000001', '大推破毂，长舌乱国。床笫之言，三世不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '111001', '男女合室，三姓同食。婚姻孔云，宜我孝孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '100111', '千仞之墙，不得入门。金笼铁疏，利以避兵。欲上南阪，轴方不转，还车复反。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '100001', '华言风语，自相诖误。终无凶事，安宁如故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '011110', '泛泛柏舟，流行不休。耽耽寐寐，公怀大忧。仁不遇时，退隐穷居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '010010', '大尾小头，重不可摇。上弱下强，阴制其雄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '101101', '一身三口，语无所主。东西南北，迷惑失道。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '001110', '南行求福，与喜相得。封受上赏，鼎足辅国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '111100', '过时不归，雌雄苦悲。徘徊外国，与母分离。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '001111', '尧舜在国，阴阳和德。涿聚衣裳，晋人无殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '101000', '周公之隆，越裳夷通。疾病多祟，鬼哭其公。狼子野心，客宿不同。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '000101', '申酉脱服，牛马休息。君子以安，劳者得欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '110101', '凯风无母，何恃何怙。幼孤弱子，为人所苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '101011', '出门上堂，从容牖房。不失其常，天牢地户。劳者忧苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '010100', '天厌周德，命与南国。以礼静民，兵革休息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '001010', '堂桑折衡，佐斗者伤。暴臣反国，良臣被殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '100011', '合欢之国，嘉喜我福。东岳西山，朝齐成思。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '110001', '耕石不生，弃礼无名。缝衣失针，襦裤不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '011111', '聋瞢闇盲，跛倚不行。坐户孚骸，身被大灾。困其多忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '111110', '生长太平，仁政流行。四方归德，社稷康荣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '011000', '桀跖并处，民人愁苦。捕兵荷粮，战于齐鲁。合卺得牢，姬姜并居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '000110', '南与凶俱，破车失襦。西行无裤，亡其宝赂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '011010', '空曹注器，豚彘不至。张弓祝鸡，雄父飞去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '010110', '望尚阿衡，太宰周公。藩屏汤武，立为王侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '011101', '朝鲜之地，姬伯所保。宜家宜人，业处子孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '101110', '息忧解笑，故贫今富。载乐履善，与福俱忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '001001', '叔迎伯兄，遇巷在阳。君子季姬，并坐鼓簧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '100100', '顺风纵火，艾芝俱亡。三官集房，一子中伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '110100', '驾车八里，求鲜鲂鲤。非吾肆居，自令失布。君子所在，安无危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '001011', '拔剑伤手，见敌不起。良臣无佐，困辱为苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '001101', '乱君之门，佐斗伤跟。营私贪禄，身为悔残。东下泰山，见我所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '101100', '慈母望子，遥思不已。久客外野，使我心苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '110110', '鲂生淮郄，一转为百。周流四海，无有患恶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '011011', '甘露醴泉，太平机关。仁德感应，岁乐民安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '110010', '采薇出车，鱼丽思初。上下役急，君子免忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '010011', '豕生鱼鲂，鼠舞庭堂。雄佞施毒，上下昏荒。君失其邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '110011', '三头六目，道畏难宿。寒苦之国，利不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '001100', '燕雀御茅，以生孚乳。昆弟六人，欢好孝悌。各同心愿，和悦相乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '010101', '文君德义，仁圣致福。年无胎夭，国富民实。卧者在室，曾累益息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011100', '101010', '秋梁未成，无以至陈。水深难涉，使我不前。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '001110', '黄帝所生，伏羲之宇。兵刃不至，利以居止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '111111', '登墀踒足，南行折角。长夜之室，不逄忠直。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '000000', '燕雀衰老，悲鸣入海。忧在不饰，差池其羽。颉颃上下，寡位独处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '010001', '关门除忧，伯自外来。切切之患，我心得欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '100010', '郊耕择耜，有所疑止。空虚无子，蒙昧不知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '010111', '张牙切齿，断怒相视。祸起萧墙，牵引吾子。患不可解，忧惊吾母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '111010', '履不容足，南山多棘。毋出房闺，乃无病疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '000010', '牛骍亡子，鸣于大野。申后阴微，还归其母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '010000', '龙生于渊，因风升天。章虎炳文，为禽败轩。发輗温谷，暮宿昆仑，终身无患。光精照耀，不被患难。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '110111', '既嫁宜吉，出入无咎。三圣并居，国安无灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '111011', '北陆阳伏，不知黑白。君子伤谗，正害善人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '000111', '一身两头，延适二家，乱不可治。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '111000', '牝马牡驹，岁孳不休。君子衣服，利得有余。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '111101', '南行怀忧，破其金舆。安坐故庐，乃无殃患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '101111', '忧人之患，履伤浮颜。为身祸残，笃心自守。与喜相抱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '000100', '咸阳辰巳，长安戌亥。丘陵生心，非鱼鳅市。可以避水，终无凶咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '001000', '不知何孙，夜来扣门。我慎外寇，兵戎且来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '011001', '昧旦不明，目暗无光。丧灭失常，使我心伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '100110', '江阴水侧，舟楫破乏。狐不得南，豹无以北。虽欲会盟，河水梁绝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '000011', '神之在丑，逆破为咎。不利西南，商人休止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '110000', '然诺不行，欺讼误人。使我虚宿，夜归温室。神怒不直，鬼击无目。欲求福利，适反自贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '101001', '攘臂拯肘，怒不可止。狼戾愎很，无与为市。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '100101', '贩马买牛，会值空虚。利得尟少，留连为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '100000', '高楼陆处，以避风雨。深堂邃宇，君安其所。牝鸡之息，为我利福。请求弗得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '000001', '阿衡服箱，太乙载行。迯时历舍，所求吉昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '111001', '飞来之福，入我居室，以安吾国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '100111', '不孝之患，子孙为残。老耄莫养，独坐空垣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '100001', '南过棘门，驹裂我冠。断衣伤襦，使君恨忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '011110', '重门射平，不知所定。质疑蓍龟，孰可避火。明神答报，告以牺牲。宜利止居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '010010', '麟麑凤雏，安乐无忧。捕鱼河海，利踰徙居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '101101', '新田宜粟，上农得谷。君子怀德，以干百禄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '011100', '簪短带长，出思苦穷。瘠蠡小瘦，以病之癃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '111100', '争讼之门，不可与邻。出入有为，忧生我患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '001111', '朽根枯株，不生肌肤。病在心肠，日以燋枯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '101000', '雨师娶妇，黄岩季女。成礼就婚，相呼南上。膏我下土，年岁大茂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '000101', '冬采薇兰，地冻坚难。利走失北，暮无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '110101', '昧之东域，误过虎邑。失我熟（罴饥无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '101011', '日莫闭目，随阳休息。箕子以之，乃受其福。举事多言，必为悔残。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '010100', '蓼萧瀼瀼，君子龙光。鸣鸾噰噰，福禄来同。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '001010', '鸟飞无翼，兔走折足。虽不同会，未能利达。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '100011', '五胜相贼，火得水息。精光消灭，绝不能续。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '110001', '东资齐鲁，得骍大马。便辟能言，市人善贾。邻人并户，请火不与。人道闭塞，鬼祟其宇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '011111', '争鸡失羊，亡其金囊。利不得长，陈蔡之患。赖楚以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '111110', '九登十陟，马跌不前。管子佐之，乃能上山。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '011000', '东邻愁苦，君乱天纪。日贪禄宠，必受其咎。一本有意合志同，内外相从，见吾伯公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '000110', '三狸捕鼠，遮遏我前。死于坏域，不能脱走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '011010', '狼虎争强，礼义不行。兼吞其国，齐鲁无王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '010110', '五岳四渎，合润为德。行不失理，民赖恩福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '011101', '六月种黍，岁晚无雨。秋不宿酒，神失其所。先困后通，与福相从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '101110', '騋牝龙身，日取三千。南上苍梧，与福为婚。道理夷易，身安无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '001001', '出入休居，安止无忧。上室之欢，虐为季残。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '100100', '南山昊天，刺政闵身。疾病无辜，背憎为仇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '110100', '潼顿东徙，道路跛踦。日辰不良，病为祟祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '001011', '兄征东燕，弟伐辽西。大克胜还，封居河间。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '001101', '播轮折辐，马不得行。竖牛之谗，贼其父兄。布衣不伤，终身无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '101100', '驾之南海，晨夜不止。君子劳罢，仆夫憔苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '110110', '怨重被烧，忿怒生祸。褊心作事，意如为乱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '011011', '张狂妄行，窃食稻粱。狗吠非主，囓伤我足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '110010', '惊跸式道，先驱除咎。王后亲桑，以率群功。安我祖宗。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '010011', '门户乏食，困死谁告。对门不通，安所归急。积藏五谷，一花千叶，市贾有息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '110011', '破敝复完，危者得安。乡善无损，商人有息。利来入门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '001100', '迭迭累累，如岐之室。一息十子，古公治邑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '010101', '三妪治民，不胜其任。两马争车，败坏家室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001110', '101010', '蔽镜无光，不见文章。少女不市，弃于相望。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '111100', '三涂五岳，阳城太室。神明所住，独无兵革。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '111111', '软弱无辅，不能自理。意在外野，心怀劳苦。虽忧不殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '000000', '周成之隆，刑措无凶。大众赞佑，君子作仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '010001', '穴有狐乌，坎生虾蟆。象去万里，不可得捕。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '100010', '俱为天民，云过吾面。治民嫉妒，与我无恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '010111', '三首六目，政多烦惑。皋陶瘖聋，乱不可从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '111010', '德积不轻，辞王钓耕。三媒不已，大福来成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '000010', '坚固相亲，日用自完。六体不易，孰为安全。雨师驾西，濡我毂轮。张伯李季，各噬关门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '010000', '方内不行，辐摧轮伤。马禁堤与，爱子闵时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '110111', '畜牝无驹，养鸡不雏。群羊三岁，不生两头。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '111011', '老耄罢极，无取中直。悬舆致仕，得归乡国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '000111', '缩绪乱丝，手与为灾。越亩逐兔，断其裈襦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '111000', '海老水乾，鱼鳖萧索。高落无涧，独有沙石。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '111101', '入市求鹿，不见顿足。终日至夜，竟无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '101111', '筑门壅户，虎卧当道。惊我骅骝，不利出处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '000100', '陶朱白圭，善贾息资。公子王孙，富贵不贫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '001000', '王良善御，伯乐知马。周旋步骤，行中规矩。止息有前，延命寿考。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '011001', '尧问大舜，圣德增益。使民不惧，安无怵惕。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '100110', '昭公失常，季氏悖狂。游齐处郓，丧其宠身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '000011', '昏暮不行，候旦待明。复住止后，未得相从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '110000', '安止宜官，一日九迁。升擢超等，牧养常山。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '101001', '去恶就凶，东西多讼，行者无功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '100101', '老马垂耳，不见百里。君子弗恃，商人莫取。无与为市。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '100000', '蟙螺生子，深自黑丑。似类其母，虽或相就。众人莫取。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '000001', '百足俱行，相辅为强。三圣翼事，王室宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '111001', '容民蓄众，履德有信。大人受福，童蒙忧惑。利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '100111', '左跌右僵，前踬触桑。其稽据石，伤其弟兄。老蚕不作，家无织帛。贵货贱身，久留连客。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '100001', '昏人旦明，卖食老昌。国祚东表，号称太公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '011110', '敝笱在梁，鲂逸不禁。渔父劳苦，焦喉乾口。虚空无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '010010', '盛中后跌，衰者复掇。盈满或毁，疾羸肥腯。郑昭失国，重耳兴立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '101101', '折亡破瓮，使我困贫。与母生分，别离异门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '011100', '野有积庾，啬人驾取。不逢狼虎，暮归其宇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '001110', '襁褓孩孤，冠带成家。出门如宾，父母何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '001111', '陈力就列，官职无废。手不胜盆，失其宠门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '101000', '积雪大寒，万物不生。阴制庶士，时本寒贫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '000101', '龙斗海门，失理伤贤。内畔生贼，自为心疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '110101', '不畏猛虎，依人为辅。三夫执兽，伏不敢起。身安无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '101011', '南山高冈，回隤难登。道路辽远，行者无功。忧不改凶，恶亦消去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '010100', '逢时阳遂，富且尊贵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '001010', '求我所欲，得其利福。终身不辱，盈盛之门。高屋光覆，君先其固。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '100011', '安坐至暮，祸灾不到。利诘妒姝，皇宥不赦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '110001', '胶车驾东，与雨相逢。五楘（解堕，顿斩独宿。忧为身福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '011111', '择日高飞，远至东齐。见孔圣师，徒我相谐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '111110', '陈妫敬仲，兆兴齐姜。乃适营丘，八世大昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '011000', '缺将无惮，难从东西。毁破我盆，泛弃酒食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '000110', '中夜狗吠，盗在庐外。神光佐助，消散归去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '011010', '雷车不藏，隐隐西行。霖雨三旬，流为河江。使我忧心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '010110', '老河空虚，旧井无鱼。利得不饶，避患东邻。福来入门，使我悔存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '011101', '福德之士，欢悦日喜。夷吾相国，三归为臣。贵流子孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '101110', '清人高子，久屯外野。逍遥不归，思我慈母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '001001', '骢黑，东归高乡。白虎推轮，苍龙把衡。朱雀导引，灵鸟载游。远扣天门，入见真君。马全人安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '100100', '路多枳棘，前刺我足。不利旅客，为心作毒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '110100', '端坐生患，忧来入门，使我不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '001011', '小陬之市，利不足喜。二世积仁，蒙其祖先。匪躬之言，狂悖为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '001101', '登高望时，见乐无忧。求利南国，与宝相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '101100', '跛足息肩，有所忌难。金城铁郭，以铜为关。藩屏自卫，安土无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '110110', '江水沱汜，思附君子。伯仲处市，不我肯顾。侄娣恨悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '011011', '芽糵生达，阳唱于外。左手执钥，公言锡爵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '110010', '云梦苑囿，万物蕃炽。犀象玳瑁，荆人以富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '010011', '渠戎万里，昼夜愁苦。櫜甲戍服，虽荷不贼。鹰鹯之殃，害不能伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '110011', '出门东行，日利辰良。步骑与驷，径历京邦。暮宿北燕，与乐相逢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '001100', '骑骓与苍，南贾太行。逢蛟猛虎，为所吞餐。葬于渭阳。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '010101', '镃基逢时，稷契皋陶。贞良得愿，微子解囚。市恐无虎，谩言妄语。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111100', '101010', '酒为欢伯，除忧来乐。福善入门，与君相索。使我有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '001111', '左有噬熊，右有囓虎。前触铁矛，后踬强弩。无可抵者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '111111', '金齿铁牙，寿考宜家。年岁有储，贪利者得。有其咎忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '000000', '家给八足，颂声并作。四夷宾服，干戈櫜阁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '010001', '狝猴冠带，盗载非位。众犬持吠，狂走蹶足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '100010', '心患其身，不念安存。忠臣孝子，为国除患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '010111', '君不明德，臣乱为惑。丞相命驾，胡亥失所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '111010', '东行西穷，南北无功。张伯买鹿，从者失羊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '000010', '鹿下西山，欲保其群。逄羿箭锋，死于矢端。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '010000', '夷明兆初，三旦为灾。以谗复归，名曰竖牛。剥乱叔孙，馁卒虚丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '110111', '秦失嘉居，河伯为恠。还其衔璧，神怒不佑。织组无文，烧香不芬。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '111011', '至德之君，祸不过邻。使我世存，身无患灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '000111', '众恶之堂，相聚为殃。幽毒良人，使道不通。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '111000', '三痴六狂，欲之平乡。迷惑失道，不知昏明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '111101', '老弱无子，不能自理。郭氏虽忧，终不离咎。管子治国，侯伯来服。乘舆八百，尊祀祖德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '101111', '褒后生蛇，经孝曰微。追跌老耄，复灭黄离。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '000100', '聪鬣黑髯，东归南乡。白虎推轮，苍龙把衡。遂至夷伤，不离咎殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '001000', '信谲龙且，塞水上流。半渡决囊，楚师覆亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '011001', '有莘季女，为王妃后。贵夫寿子，母尊四海。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '100110', '德被八表，蛮夷率服。蝥贼不作，道无苛慝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '000011', '载日精光，骖驾六龙。禄命彻天，封为燕王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '110000', '缨急缩颈，行不得前。五石示象，襄伯不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '101001', '蛇乡其穴，载麻当丧。哀悲哭泣，送死离乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '100101', '四溃不安，兵革为患。掠我妻子，客屡饥寒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '100000', '乘风雨桥，与飞鸟俱。一举千里，见吾爱母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '000001', '雷霆所击，诛者五逆。劘灭无迹，有惧方息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '111001', '张氏揖酒，请谒左右。王时枯槁，独不蒙所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '100111', '坐争立讼，纷纷匈匈。卒成祸乱，灾及家公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '100001', '霜降门户，蛰虫隐处。不见日月，与死为伍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '011110', '鼠聚生恠，为我患悔。道绝不通，商旅失意。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '010010', '寒暑不当，轨度失常。一前一后，年岁鲜有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '101101', '筑室水上，危于一齿。丑寅不徙，辰卯有咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '011100', '畜鸡养狗，长息有储。耕田得黍，主母喜舞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '001110', '东壁余光，数暗不明。主母嫉妒，乱我事业。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '111100', '刚柔相伤，火烂销金。鵰鹰制兔，伐楚有功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '101000', '郑国谗多，数被楚忧。征夫愁苦，民困无聊。一本云三豕俱走，斗于虎口。白豕不胜，死于坎下。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '000101', '弓矢斯张，把弹弦折。丸发不至，道遇害患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '110101', '举觞饮酒，未得至口。侧弃醉酗，拔剑斫怒。武侯作悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '101011', '苍鹰群行，相得旅前。王孙申公，惊夺我雄。北天门开，神火飞灾。如不敬信，事入尘埃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '010100', '穿屋相宜，利倍我北。循邪诡道，迎不可得。南北望邑，遂归入室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '001010', '寿如松乔，与日月俱。常安康乐，不离祸忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '100011', '出门望东，伯仲不来。疾病为患，使母忧欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '110001', '太姬之孙，周文九子。咸遂受成，宠贵富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '011111', '桃李花实，累累日息。长大成熟，甘美可食。为我利福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '111110', '婚礼不明，男女失常。行路有言，出争我讼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '011000', '空穿漏敝，破桴残缺。阴弗能完，瓦碎不全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '000110', '数穷廓落，困于历室。往登玉堂，与老侑食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '011010', '道湿为坑，轮陷踬强。南国作讳，使我多畏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '010110', '鳏寡孤独，福禄苦薄。入室无妻，我子哀悲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '011101', '举袂覆目，不见日月。衣衾杖几，就其夜室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '101110', '长尾踒跎，画地为河。深不可涉，绝世之比。悯然愤息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '001001', '晨风文翰，火举就温。昧过我邑，羿无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '100100', '出入节时，南北无忧。亟行所逐，在外来归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '110100', '阳氏狂惑，季孙乱溃。陪臣执政，平子俱折。季心不快。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '001011', '五鸟六鸱，相对蹲跂。礼让不兴，虞芮争讼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '001101', '愿念所生，隔在东平。遭离满沸，河川决溃。幸得无恙，复生归室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '101100', '追猎东走，兔迯我后。吾锐不利，独空无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '110110', '犬吠非主，上下浑扰。敌人袭战，闵王迯走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '011011', '嵩高岱宗，峻直且神。触石肤寸，千里蒙恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '110010', '陈鱼观社，狼虎踰距。为民开绪，亡其祖考。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '010011', '四壁无户，三步一止。东西南北，利不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '110011', '求君衣裳，情不可当。触讳西行，为伯生殃。君之上安，得生安存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '001100', '春鸿飞东，以马货金，利可得深。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '010101', '禾生虫蠹，还自克贼，使我无得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001111', '101010', '桀乱无道，民散不聚。背室之家，遁迯出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '101000', '销锋铸耜，休牛放马。甲兵解散，夫妇相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '111111', '一衣三冠，冠无所绊。衣服不成，为身灾患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '000000', '百足俱行，相辅为强。三圣翼事，王室宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '010001', '鱼蛇之恠，大人忧惧。梁君好城，失其安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '100010', '少无强辅，长不见母。劳心远思，自伤忧苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '010111', '前不溽暑，解不可取。离门二里，败我利市。老牛病马，去之何悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '111010', '君明有德，登天大禄。布政施惠，以成恩福。中子南游，翱翔未复。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '000010', '哓然唯诺，敬上尊客。执恭除患，御侮致福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '010000', '黍稷禾稻，垂秀方造。中旱不雨，伤风病槁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '110111', '三羸六罢，不能越跪。东贾失马，往反劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '111011', '倚立相望，引衣欲装。阴云蔽日，暴雨降集。使道不通，阻我欢会。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '000111', '高脚疾步，受肩喜趋。日走千里，贾市有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '111000', '北风寒凉，雨雪盈冰。忧思不乐，哀悲伤心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '111101', '贞鸟雎鸠，执一无尤。寝门治理，君子悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '101111', '蓼萧露瀼，君子宠光。鸣鸾噰噰，福禄来同。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '000100', '南行求福，与喜相得。受封上赏，鼎足辅国。咸之恒同。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '001000', '桑华腐蠹，衣敝如络。女功不成，丝布为玉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '011001', '左服易右，王良心欢，喜利从己。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '100110', '寿考不忘，驾驷东行。三适陈宋，南贾楚荆。得利息长，旅身多罢。畏昼喜夜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '000011', '羔羊皮弁，君子朝服。辅政扶德，以合万国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '110000', '鹯鸠徙巢，西至平州。遭逢雷电，破全苇芦。室家饥寒，思吾故初。全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '101001', '大尾小头，重不可摇。上弱下强，阴制其雄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '100101', '疏足息肩，有所忌难。金城铜郭，以铁为关。藩屏自卫，安心无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '100000', '天命元鸟，下生大商。造定四表，享国久长。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '000001', '赋敛重数，政为民贼。杼轴空虚，我去其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '111001', '阴阳隔塞，许嫁不答。宛丘新台，悔往叹息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '100111', '愿望登虚，意常欲迯。贾辛丑恶，妻不安夫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '100001', '踄行窃视，有所畏避。蔽目伏藏，以夜为利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '011110', '信敏恭谦，敬鬼尊神。五岳四渎，克厌帝心。受福宜年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '010010', '悬悬南海，去家万里。飞兔腰褭。一日见母，除我忧悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '101101', '虽污不辱，因何跣足。童子褰衣，五步平复。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '011100', '宫城立见，衣就袂裾。恭谦自卫，终无祸尤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '001110', '敝笱在梁，不能得鱼。望食千里，所至空虚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '111100', '千里骍驹，为王服车。嘉其骊荣，君子有成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '001111', '鼎足承德，嘉谋生福。为王开庭，得心所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '000101', '右手无合，独折左指。禹汤失位，事功弗立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '110101', '忧凶增累，患近不解。心西意东，事无成功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '101011', '东行食榆，困于枯株。夫妻无家，志穷为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '010100', '五经六纪，仁道所在。正月繁霜，独不离咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '001010', '懈缓不前，怠堕失便。二至之戒，家无祸凶。刻木象形，闻言不信。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '100011', '仁爱笃厚，不以所忿，害其所子。徙我旧都，日益富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '110001', '缺破不成，胎卵未生，弗见兆形。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '011111', '摧角不伤，虽折复长。秉德无愆，老赖荣光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '111110', '乘桴浮海，免脱厄中，虽困无凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '011000', '孔鸾鸳雏，鸮鸃鹈鸪，翱翔紫渊。嘉禾之国，君子以说。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '000110', '甘露温润，众来得愿。乐易君子，不逢祸乱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '011010', '东骑堕落，千里独宿。高岸为谷，阳失其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '010110', '入村既登，以成嘉功。尨降庭坚，国无灾凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '011101', '邯郸反言，父兄生患。竟涉忧恨，卒死不还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '101110', '玉锐铁颐，仓库空虚。贾市无盈，兴利为仇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '001001', '白鸟御饵，鸣呼其子。施枝张翅，来从其母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '100100', '学灵三年，圣且神明。先见善祥，吉盛福庆。神马来见，告我无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '110100', '云孽蒸起，失其道理。伤害年谷，神君之精。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '001011', '春耕有息，利入利福。献大豵，以乐成功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '001101', '羸豕踯躅，虎来都邑。遮遏左右，国门敕急。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '101100', '东行西维，南北善迷。逐旅失群，亡我襦衣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '110110', '居室之伦，夫妇和亲。小人乘车，车在夫家。硕果失豢，不知孰是。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '011011', '东方孟春，乘冰载盆。惧危不安，终身所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '110010', '风吹尘起，十地无所。南国年伤，不可安处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '010011', '重载伤车，妇女无夫。三十不室，独坐空庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '110011', '败牛羸马，与利为市，不我嘉喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '001100', '月出阜东，山蔽其明。章父忧偻，箕子徉狂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '010101', '出入门所，欲道开通。杞梁之信，不失日中。少季渡江，来归其邦。疾病危亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101000', '101010', '邑居卫师，如转蓬时，居之凶危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '000101', '他山之错，与璆为仇。来攻吾城，伤我肌肤。邦家骚忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '111111', '践履寒冰，十步九寻。惟有苦痛，不为病忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '000000', '太公避纣，七十隐处。卒逢圣文，为王室辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '010001', '日月之涂，所行必到，无有患悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '100010', '讽德诵功，美风盛隆。旦辅成周，光济冲人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '010111', '童子无室，未有配合，空坐独宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '111010', '穿鼻系株，为虎所拘。王母祝祠，祸不成灾。遂然脱来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '000010', '黄帝神明，八子圣聪。佚受大福，天下平康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '010000', '深谷为陵，衰者复兴。乱倾之国，民德安息。中妇病困，遂入冥室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '110111', '道远辽绝，路宿多悔。顽嚚相聚，生我畏忌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '111011', '旦树菽豆，暮成藿羹。心之所乐，志快心欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '000111', '切切之患，凶忧不成。虎不敢囓，利当我身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '111000', '王伯远宿，长妇在室。异庖待食，所求不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '111101', '寒燠失时，阳旱为灾，虽耗无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '101111', '虽穷复通，履危不凶，得其明功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '000100', '狼虎所宅，不可以居，为我患忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '001000', '喋嗫处耀，明昧相传。多言少实，语无成事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '011001', '履冰蹈凌，虽困不穷。播鼓登岩，卒无忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '100110', '文墨且墨，祸福相杂。南北失志，东西不得。一云文墨且黑，祸福相杂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '000011', '争讼不已，更相谈询。张季弱口，被发北走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '110000', '德积逢时，宜其美才。相明辅圣，拜受福休。长女不嫁，后为大悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '101001', '江水沱汜，思附君子。仲氏爱归，不我肯顾。侄娣恨悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '100101', '光礼春成，陈室鸡鸣。师明失道，不能自守。消亡为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '100000', '惊虎无患，虞为我言，赖得以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '000001', '伪言妄语，转为诖误，不知狼虎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '111001', '履自敌，凶忧来到，痛不死哭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '100111', '牵尾不前，逆理失臣，惠朔以奔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '100001', '三狸捕鼠，遮遏我后。死于还城，不得脱走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '011110', '言笑未毕，忧来暴卒。身墨丹索，槛内装米。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '010010', '阴积不已，云作淫雨。伤害平陆，民无室屋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '101101', '山林麓薮，非人所处。鸟兽无礼，使我心苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '011100', '新作初陵，踰陷难登。三驹推车，跌损伤颐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '001110', '魂微惙惙，属纩听绝。扩然大通，复更生活。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '111100', '栾子作殃，伯氏诛伤。州吁奔楚，去其邑乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '001111', '骄卤奇形，造恶作凶。无所能成，还自灭身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '101000', '陈辞达情，使安不倾。增荣益誉，以成功名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '110101', '三杞无枣，家无积莠。使鸠求妇，顽不我许。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '101011', '慎祸重患，颜子为尤，乃能安存。牢户系羊，乃能受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '010100', '鹿得美草，鸣唤其友。九族和睦，不忧饥乏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '001010', '亡玉失鹿，不知所伏。利以避危，全我生福。甘雨时降，年谷有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '100011', '逢时积德，身受福庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '110001', '鹄思其雄，欲随凤东。顺理羽翼，出次日中。须留北邑，复反其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '011111', '环绪倚鉏，斗升属口。贫贱所处，心寒悲苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '111110', '孤独特处，莫依为辅，心劳志苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '011000', '稷为尧使，西见王母。拜请百福，赐我喜子，长乐富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '000110', '鸣条之灾，北奔于胡。左衽为长，国号匈奴。主君旄头，立为单于。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '011010', '绝而复通，虽危不穷。终得其愿，姬姜相从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '010110', '阳并悖狂，拔剑自伤，为身生殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '011101', '方圆不同，刚柔异乡。掘井得石，劳而无功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '101110', '乘风驾雨，与鸣鸟俱。动举千里，见我爱母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '001001', '三涂五岳，阳城太室。神明所扶，独无兵革。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '100100', '鸱鸮娶妇，深目窌身。折腰不媚，与伯相悖。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '110100', '转行轨轨，行近不远。旦夕入门，与君笑言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '001011', '求利难国，迯去我北。复归其城，不为吾贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '001101', '日月之涂，所行必到。无凶无咎，安宁不殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '101100', '管叔遇桓，得其愿欢。胶日杀纠，振冠无忧。笑喜不庄，空言妄行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '110110', '出入蹈践，动顺天时。俯仰有节，祸灾不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '011011', '内崩中伤，上乱无常。虽有米粟，我不得食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '110010', '逐祸除患，道德神仙。过恶万里，福常在前。身乐以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '010011', '牛惊马走，上下浑扰。鼓音不绝，项公奔败。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '110011', '西上九陂，往来留连。心须时日，灵与有德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '001100', '虎怒捕羊，猬不能攘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '010101', '涌泉涓涓，南流不绝。卒为江海，将帅袭战，获其丑虏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000101', '101010', '桃弓苇戟，除残去恶，敌人执服。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '110101', '王命赤乌，与君徼期。征伐无道，诛其君傲。居止何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '111111', '千岁槐根，身多斧痕。伤夷倒掘，枝叶不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '000000', '喭喭谔谔，虎豹相齰。畏惧悚息，终无难恶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '010001', '娶于姜吕，驾迎新妇。少齐在门，夫子欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '100010', '高壤肥泽，民人孔乐。宜利居止，长安有福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '010111', '主有圣德，上配太极。皇灵建中，授我以福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '111010', '耄老蒙钝，不见东西。少者弗慕，君不与谋。悬舆致仕，退归里居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '000010', '三狂北行，道逢大狼。暮宿患宅，为祸所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '010000', '更旦初岁，振除祸败。新衣元服，拜受利福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '110111', '杲杲白日，为月所食。损上（毁上，郑昭出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '111011', '君子失意，小人得志。乱忧并作，奸邪充塞。虽有百尧，颠不可救。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '000111', '仁德优洽，恩及异域。泽被殊方，福庆隐伏。作蚕不织，寒无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '111000', '东求金玉，反得敝石。名曰无宜，字曰丑恶。众所贱薄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '111101', '击鼓合战，士怯叛亡。威令不行，败我成功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '101111', '仲春孟夏，和气所舍。生我嘉福，国无残贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '000100', '尹氏伯奇，父子相离。无罪被辜，长舌为灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '001000', '五谷不熟，困民恶极。驾之新邑，嘉禾有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '011001', '登虚望贫，暮食无飧。长子南戍，与我生分。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '100110', '东市齐鲁，南贾荆楚。羽毛齿革，为吾利宝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '000011', '节情省欲，赋敛有度。家给人足，公刘以富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '110000', '恭宽信敏，功加四海。辟去不祥，喜来从母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '101001', '张狂妄行，与恶相逢。不得所欲，生我独凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '100101', '画龙头颈，文章不成。甘言美语，诡辞无名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '100000', '骑龙乘凤，上见神公。彭祖受制，王高赞通。巫咸就位，拜寿无穷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '000001', '温仁君子，忠孝所在八国为邻，祸灾不起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '111001', '威权分离，乌夜徘徊群蔽月光，大人诛伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '100111', '学灵三年，圣且神明先知吉祥，言喜福庆神鸟来见，告我无穷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '100001', '东山辞家，处妇思夫伊威盈室，长股羸户叹我君子，役日未已。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '011110', '张颔开口，舌直绝齿然诺不行，政乱无绪。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '010010', '吹角高邦，有失牛羊众民惊惶，敬慎避咎敕行不殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '101101', '南行出城，世德福祉。三姬嫁齐，赖其所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '011100', '心狂志悖，耳听从类。政令无常，下民多孽。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '001110', '安上宜官，一日九迁。踰群越等，牧养常山。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '111100', '东邻嫁女，为王妃后。庄公筑馆，以事主母。归于京师，季姜悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '001111', '六甲无子，以丧其戊。五丁不亲，庚失曾孙。癸走出门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '101000', '阴雾不清，浊政乱民。孟春季夏，水坏我居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '000101', '骑肫逐羊，不见所望。径涉虎庐，亡身失羊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '101011', '安床厚褥，不得久宿。弃我喜宴，困于南国。投杼之忧，不成祸灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '010100', '五日四维，安平不危。利以居止，保有玉女。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '001010', '西贾巴蜀，寒雪至毂。欲前不得，反复其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '100011', '刚柔相呼，二姓为家。霜降既同，惠我以仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '110001', '天马五道，夹大分处。往来上下，相随哭歌。凶恶如何。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '011111', '出门怀忧，东上祸丘。与凶相遇，自为灾患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '111110', '西行求玉，冀得隋璞。反见凶恶，使我惊惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '011000', '出门无至，动作失利。御忧怀祸，使我多悴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '000110', '高楼无柱，颠僵不久。纣失三仁，身死牧野。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '011010', '避祸迯殃，身全不伤。高贵疾颠，华落坠亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '010110', '张牙反目，怒齰忿怒。狂马挠犬，道惊伤轸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '011101', '泉涸龙忧，箕子为奴。干叔陨命，殷破其家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '101110', '向食饮酒，嘉宾会聚。牂羊大猪，君子饶有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '001001', '黄牛骍犊，东行折角。冀得百祥，反亡我囊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '100100', '路多枳棘，步刺我足。不利旅客，为心作毒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '110100', '执斧破薪，使媒求妇。和合二姓，亲御斯酒。召彼邻里，公姑悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '001011', '驾车出门，顺时宜西。福佑我身，安宁无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '001101', '日新东升，魁杓为祸。汉台为秦，使我久坐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '101100', '山陵丘墓，魂空室屋。精光竭尽，长卧无觉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '110110', '孩子含饵，为利所悦。探釜把甑，烂其手臂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '011011', '何村待时，门户独悲。蚯蚓冬行，解我无忧。桑蚕不得，女红无成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '110010', '解伤惊惶，散我衣裳，君不安邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '010011', '害政养贼，背主入愆。跛行不安，国为危患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '110011', '祸走患伏，喜为我福。凶恶消亡，灾害不作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '001100', '老马为驹，病鸡不雏。三雌独宿，利在山北。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '010101', '播天舞地，哓乱神所，居乐无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110101', '101010', '异国殊俗，情不相得。金木为仇，酋长擅役。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '101011', '仓盈庾亿，宜稼黍稷。年丰岁熟，民得安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '111111', '被服文衣，游视酒池。上堂见觞，喜为吾兄。使我忧忘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '000000', '邑姜叔子，天文在手。实沈参墟，封为晋侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '010001', '改柯易叶，饭温不食。豪雄争强，先者受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '100010', '馨香陟降，明德上登。社神佑顾，命为大邻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '010111', '老狼白驹，长尾大狐。前颠却踬，进退遇祟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '111010', '山没丘浮，陵为水鱼，燕雀无庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '000010', '懿公浅愚，不受深谋。无援失国，为狄所灭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '010000', '鼎易其耳，热不可举。大涂壅塞，旅人心苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '110111', '凶声丑言，要不可闻。君子舍之，往恨我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '111011', '昧暮乘车，履危蹈沟。亡失群物，摧折两轴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '000111', '南有嘉鱼，驾黄取。鲂鱮诩诩，利来毋忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '111000', '隔在九山，往来劳难。心结不通，失其所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '111101', '下流难居，任失多态。贞良温柔，年岁不富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '101111', '狐狸雉兔，畏人逃去。分首窜匿，不知所处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '000100', '异体殊俗，各有所属。西邻孤妪，欲寄我室。主母骂詈，终不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '001000', '怒非怨妒，贪得腐鼠。而呼鹰鹯，自今失饵。倒被困患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '011001', '五心六意，岐道多怪。非君本心，生我恨悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '100110', '三班六黑，同室共食。日长月息，我家有德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '000011', '方船备水，旁河燃火，终身无祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '110000', '翳屏独语，不闻朝市，利以居言，究被后门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '101001', '居处不安，徒反触患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '100101', '刺刖髡劓，人所贱弃。批捍之言，我心不快。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '100000', '皋田禾黍，堆壤麻阜。衣食我躬，室家饶有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '000001', '两目失明，日夺无光。胫足跛踦，不可以行。顿于丘傍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '111001', '金城朔方，外国多羊。履霜不时，去复为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '100111', '匿痼不医，乱政生灾。纣作淫虐，商破其墟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '100001', '鬼哭泣社，悲伤无后。甲子昧爽，殷汤绝祀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '011110', '焱风卒起，车驰袍褐。弃古追亡，失其和节。忧心惙惙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '010010', '耄老失明，闻善不从。自今颠沛，反为咎殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '101101', '随风骑龙，与利相逢。日获三狐，商伯有功。衢衢之邑，长安无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '011100', '三牛五牂，重明作福。使我有得，疾入官狱。忧在心腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '001110', '孟巳乙丑，哀呼尼父。明德讫终，乱虐滋起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '111100', '华灯百枝，消暗衰微。精光讫尽，奄如灰糜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '001111', '鹰飞雉退，兔伏不起。狐张狼鸣，野鸡惊骇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '101000', '斗身战天，门有何患。室家具在，不失其欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '000101', '东家杀牛，污臰腥臊。神背西顾，命绝衰周。亳社灾烧，宋人夷诛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '110101', '阴阳辨舒，二姓相合。婚姻孔云，生我利福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '010100', '东入海口，循流北走。一高一下，五色无主。十日六夜，死于水涘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '001010', '孤竹之墟，失妇无夫。伤于蒺藜，不见其妻。东郭棠姜，武子以亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '100011', '天门东墟，尽既为灾。迹喑聋，秦伯受殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '110001', '赖生光水，受福之祉。虽遭乱，溃独不危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '011111', '折舌闭目，不见稚叔。三足孤乌，远其无失。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '111110', '七人同室，兄弟合食。和乐相好，各得所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '011000', '继体守藩，纵欲废贤。君臣淫佚，夏氏失身。侧室之门，福禄来存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '000110', '老狐屈尾，东西为鬼。病我长女，哭涕诎指。或西或东，大革易诱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '011010', '大树之子，百条共母。当夏六月，枝叶茂盛。鸾凤以庇，召伯避暑。穉穉卭甚，各得其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '010110', '井堙木刊，国多暴残。秦王失所，坏我大坛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '011101', '驾黄买苍，与利相迎。心获所守，不累弟兄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '101110', '仓盈庾亿，宜稼黍稷。年丰岁熟，民得安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '001001', '人生马渊，寿考且神。飞腾上天，舍宿轩辕。居常乐安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '100100', '思愿所之，今乃逢时。洗我故忧，拜我欢来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '110100', '魁罡所当，初为败殃。君子留连，困于水浆。求金东山，利在茂乡。贾市有息，子载母行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '001011', '铅刀攻玉，无不钻凿。龙体具举，鲁般为辅。三圣翼事，所求必喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '001101', '喜来如云，举家欢忻。众才君子，驾福盈门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '101100', '响像无形，骨体不成。微行衰索，消灭无名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '110110', '积水不温，北陆苦寒。露宿多风，君子伤心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '011011', '黄马绿车，驾之大都。赞达才能，使我无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '110010', '从风放火，芝艾俱死。三害集聚，叔子中伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '010011', '一身三手，无益于辅。两足共节，不能克敏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '110011', '南向陋室，风雨并入。埃尘积湿，王母盲痹。偏枯心疾，乱我家次。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '001100', '采薇出车，鱼丽思初。上下促急，君子怀忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '010101', '先易后否，告我利市。骚苏自苦，思再故止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101011', '101010', '生宜地乳，上皇大喜。隆我祉福，贵寿无极。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '010100', '同济共舆，中道别去。丧我元夫，独与孤苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '111111', '叔肸居冤，祁子自邑。乘遽解患，羊舌免脱。赖得生全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '000000', '兔聚东郭，众犬俱猎。围缺不成，无所能获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '010001', '作室山根，人以为安。一夕崩颠，败我壶餐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '100010', '疾风尘起，乱我崩始。强大并小，先否后喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '010111', '洁斋沐浴，思明居德。哀公怯弱，风氏复北。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '111010', '土瘠瘦薄，培塿无柏，使我不乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '000010', '褰衣涉河，涧流波多。赖遇舟子，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '010000', '送我季女，莹于荡道。齐子旦夕，留连久处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '110111', '三孙六子，安无所苦。中藏废殆，亡我所使。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '111011', '扬风偃草，尘埃俱起。清浊溷散，忠直隐处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '000111', '历险登危，道远劳疲。去家自归，困涉大波。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '111000', '六艺之门，仁义俱存。镃基逢时，尧舜为君。伤寒执温，下至黄泉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '111101', '被服文衣，游观酒池。上堂见觞，喜为吾兄。使我忧亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '101111', '生时不利，天命灾至。制于斧瘢，当夜勤苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '000100', '天门开辟，牢户寥廓。桎梏解脱，拘囚纵释。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '001000', '川渊难游，水为我忧。多言少实，命鹿为驹。道德开基，君子逢时，利以中疑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '011001', '乡岁逢时，与生为期。枝叶盛茂，君子无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '100110', '六鹢退飞，为衰毁祥。陈师合战，左股夷伤。遂崩不起，霸功不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '000011', '雷君出装，隐隐西行。霖雨不止，流为河江。南国忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '110000', '牙孽生齿，阳倡于外。左手执钥，公言锡爵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '101001', '火起土门，不为我残。跳脱东西，独得生完。不利出邻，病疾忧患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '100101', '举事无成，不利出征。言不可用，众不能平。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '100000', '老狼白驴，长尾大胡。前颠却踬，进退遇祟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '000001', '日入道极，劳者休息。班马还师，复我燕室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '111001', '山林麓薮，非人所处。鸟兽无礼，使我心苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '100111', '蓄利积福，日新其德。高氏饮食，忧不为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '100001', '张罗百目，鸟不得北。缩颈挂翼，困于窘国。君子治德，获誉受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '011110', '伯虎仲熊，德义渊弘。使布五教，阴阳顺序。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '010010', '跛踦相随，日暮牛罢。陵迟后旅，失利亡雌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '101101', '嬴氏违良，使孟寻兵。老师不已，败于齐卿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '011100', '日月并居，常暗且微。高山崩颠，丘陵为溪。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '001110', '乌鹊食谷，张口受哺。蒙恩被德，长大成就。柔顺利贞，君臣相好。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '111100', '虽踬复起，不毁牙齿。克免平复，忧除无疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '001111', '草木黄落，岁暮无室。虐政为贼，大人失福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '101000', '避凶东走，反以祸口。制于牙爪，骨为灰土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '000101', '欲飞不能，志苦心劳，福不我来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '110101', '羔裘豹褎，东与福遇。驾迎吾兄，送我骊黄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '101011', '东耕破犁，西失良妻。灾害不避，家贫无资。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '001010', '鱼陆失所，鸟蝇困苦。泽无萑蒲，晋国以墟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '100011', '脱兔无蹄，三步五罢。南行不进，后市劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '110001', '行役未已，新事复起。姬姜劳苦，不得休止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '011111', '向日扬光，火为正王。消金厌兵，雷车避藏。阴雨不行，民定其乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '111110', '放衔垂辔，奔马不制。弃法作奸，君失其位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '011000', '司命不游，喜解我忧。皇母缓带，婴儿笑喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '000110', '黄帝出游，驾龙乘马。东上泰山，南过齐鲁。郡国咸喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '011010', '既往不说，忧来祸结。比户为患，无所申冤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '010110', '荷蒉隐居，以避乱倾。终身不仕，遂其洁清。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '011101', '折梃舂稷，君不得食。头痒搔跟，无益于疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '101110', '植根不固，华叶落去，便为枯树。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '001001', '凶门生意，牢户多冤。沙陁秃齿，使我困穷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '100100', '登山履谷，与虎相触。猬为功曹，班奴奔北。脱之喜国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '110100', '麟凤所翔，国无咎殃。贾市十倍，复归惠里。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '001011', '路险道难，水过我前。进往不利，回车复还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '001101', '延颈望邑，思归我室。台榭不成，未得安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '101100', '蒙生株瞿，棘挂我须。小人嫉妒，使恩不遂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '110110', '南至隐域，深潜处匿。聪明闭塞，与死为伍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '011011', '机饵设张，计暴子良。范叔不廉，凶害及身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '110010', '从骑出谷，游戏苦域。坡高不进，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '010011', '西国强梁，为虎作狼。东吞齐楚，并有其王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '110011', '登山伐辐，虎在我侧。王孙无惧，仁不见贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '001100', '六目睽睽，各欲有至。后来未壮，候待明旦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '010101', '道涉多阪，牛马蛇蟺。车不利载，请求不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010100', '101010', '一口三舌，相妨无益。群羊百牂，不为威强。亡马失驹，家耗于时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '001010', '驾言出游，鸟斗车前。更相捽灭，兵马且来。回车亟还，可以无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '111111', '大都之居，无物不具。抱布贸丝，所求必得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '000000', '胶着木连，不出牢关，家室相安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '010001', '孟伯食长，惧其畏王。赖四蒙五，抱福归房。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '100010', '朽舆瘦驷，不任衔辔。君子服之，谈何容易。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '010111', '许嫁既婚，利福在身。适惠生桓，为我鲁君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '111010', '入门大喜，上堂见母。妻子俱在，兄弟饶有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '000010', '推车上山，力不能任。颠蹶蹉跌，伤我中心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '010000', '鹰飞退去，不食其雏。禽尚如此，何况人乎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '110111', '福弃我走，利不可得。幽人利贞，终无怨慝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '111011', '夫妻反目，不能正室。公云子南，姬言还北。并后匹嫡，二政乱国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '000111', '阳衰伏匿，阴淫为贼。幸赖王孙，遂至家国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '111000', '入水求玉，不见和璞。终日至暮，劳无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '111101', '鸣鸾四牡，驾出行狩。合格有获，献公饮酒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '101111', '覆手齐犊，易为功力。正月元日，承平致福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '000100', '三火起明，雨灭其光。高位疾颠，骄恣诛伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '001000', '裹糗荷粮，与利相逢。高飞有得，君子获福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '011001', '水土相得，万物蕃殖。膏泽优渥，君子有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '100110', '道理和得，人不相贼。君子往之，乐有利福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '000011', '天孙帝子，与日月处。光荣于世，福禄繁祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '110000', '布衣在位，乘非其器。折足覆餗，毁伤我玉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '101001', '鹢飞中退，举事不遂。且守仁德，犹恐失坠。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '100101', '经枣整冠，意盈不厌。桀纣迷惑，谗佞伤贤。使国乱倾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '100000', '申酉退跌，阴雨前作。柯条花枝，复泥不白。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '000001', '平正贱使，至服苦事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '111001', '钓鲂河湄，水泛无涯。振衣徒归，上下昏迷。厉公经齐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '100111', '胎养萌生，始见兆形。遭逢雷电，摧角折颈。采〔p.gif〕山头，终安不倾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '100001', '阳春枯槁，夏多水潦。雷雹俱击，伤我禾黍。年岁困苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '011110', '三耳六齿，痛疾不已。龋病蠹缺，堕落其宅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '010010', '失时无友，嘉偶出走，傫如丧狗。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '101101', '宜重微民，岁乐年丰。百国无咎，君子安喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '011100', '登几上车，驾驷南游。合散从横，燕秦以强。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '001110', '鸟集茂木，心乐愿得。乌鹊食谷，张口受哺。柔顺利贞，感戴慈母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '111100', '启蛰始生，万物美荣。福祉未成，市买无赢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '001111', '骄卤火形，造恶作凶。无所能成，还自灭身。一作草木黄落，岁云暮矣。唐攻高城，大人失福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '101000', '异国他土，出良骏马。去如奔〔p.gif〕，害不能伤（。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '000101', '恪敬竞职，心不作慝。君明臣忠，民赖其福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '110101', '三女求夫，伺候山隅。不见复关，长思忧叹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '101011', '驾福乘喜，东至嘉国。戴庆南行，离家室居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '010100', '四奸为残，齐鲁道难。前驱执役，戒守无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '100011', '下忧上烦，蠹政为患，岁饥无年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '110001', '鸡雉失雏，常畏狐狸。黄池要盟，越国以昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '011111', '坚冰黄鸟，常哀悲愁。不见米粒，但观蓬蒿。数惊鸷鸟，为我心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '111110', '玉锐铁颐，仓库空虚。市贾为盈，与我为仇。元本有时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '011000', '窃名盗位，居非其家。霜陨不实，为阴所贼。三年失室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '000110', '贼仁伤德，天怒不福。斩刈家社，失其本域。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '011010', '万物和生，蛰蛊振起。益爵增福，日受其喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '010110', '和气所生，物皆不朽。圣贤居位，国无凶咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '011101', '龙游凤舞，岁乐民喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '101110', '鼎行窘步，次伯方舍。居安不惧，姬妾何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '001001', '水深难游，霜寒难涉。商伯失利，旅人稽留。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '100100', '跛踦相随，日暮牛罢。陵原徙伤，失利亡雌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '110100', '一牛九锁，更相牵挛。案明如市，不得东西。请谳得报，日中被刑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '001011', '春桃生花，季女宜家。受福孔多，男为邦君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '001101', '雷鼓东行，稼穑凋伤。大夫执政，君赞其明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '101100', '季世君忧，乱国淫游。殃祸立至，民无以休。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '110110', '发輗温阳，过雨宿房。宜时布和，无所不通。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '011011', '水中大贾，求利十千。商人不至，市空无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '110010', '春草萌生，万物敷荣。阴阳和畅，国乐无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '010011', '左眇右盲，目视不明。下民多孽，君失其常。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '110011', '悦以内安，不利出门。忧祸消除，公孙何尤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '001100', '册书之信，言不负语。易我驎骥，君子有德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '010101', '上政摇扰，虫螟并起。害我嘉谷，年岁无稷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001010', '101010', '干旄旌旗，执在载郊。虽有宝玉，无路致之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '100011', '路多枳棘，步刺我足。不利旅客，为心作毒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '111111', '鲤鲔鲋鲫，积福多鱼。资所无有，富我穷家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '000000', '景星照堂，麟游凤翔。仁施大行，颂声作兴。仁序无明，失其宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '010001', '羊肠九萦，相推稍前。止须王孙，乃能至天。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '100010', '四手共身，莫失所图。更相访接，动失事便。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '010111', '水流趋下，逮至东来。求我所有，买鳣与鲤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '111010', '春栗夏枣，山鲜希有。斗千万石，贵不可贱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '000010', '旦往暮还，相佑与聚，无有凶患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '010000', '大蛇当路，使季畏惧。汤火之灾，切直我肤。赖其天幸，归于室庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '110111', '徒足去域，乱入陈国。有所畏避，深藏邃匿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '111011', '海为水宗，聪明且圣。百流归得，无有叛逆。常饶优足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '000111', '夏麦麸曲，霜击其芒。疚君败国，使年大伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '111000', '秋隼冬翔，数被履霜。雄犬夜鸣，家忧不宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '111101', '乐仁上德，东邻慕梁，来安吾国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '101111', '还忧除殃，污泥上义，下田为江。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '000100', '暗昧冥语，传相诖误。鬼魅所居，谁知卧处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '001000', '南历玉山，东入玉关。登上福堂，饮万岁浆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '011001', '比目四翼，来安我国。福善上堂，与我同床。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '100110', '乘牛逐骥，日暮不至。路宿多畏，亡其骍骓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '000011', '元吉无咎，安宁不殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '110000', '奋翅鼓翼，翱翔外国。逍遥徙倚，来归温室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '101001', '河伯娶妇，东山氏女。新婚三日，浮云洒雨。露我管第，万邦蒙佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '100101', '婴儿求乳，慈母归子。黄麑悦喜，得其甘饱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '100000', '贫鬼守门，日破我盆。毁罂伤瓶，空虚无子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '000001', '多载重负，捐弃于野。王母谁子，但自劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '111001', '雄狐绥绥，登山崔嵬。昭告显功，大福允兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '100111', '婴儿骇笑，未有所识。狡童而争，乱我政事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '100001', '十丸同投，为雉所离。独得逃脱，完全不亏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '011110', '狐济濡尾，来揭得枳。季姜怀悔，鲍舍鱼臰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '010010', '踆足息肩，所忌不难。金城铜郭，以铁为关。藩屏周卫，安全无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '101101', '戴尧扶禹，松乔彭祖。西过王母，道路夷易。无敢难者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '011100', '京庾积聚，黍稷以极。行者疾至，可以厌饱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '001110', '良夫孔姬，负理登台。栾季不扶，卫辄走逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '111100', '天之所予，福禄常在，不忧危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '001111', '行触天网，马死车伤。身无寥赖，困穷乏粮。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '101000', '铅刀切玉，坚不可得。尽我觔力，胝胼为疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '000101', '穆逢百里，使孟奋武。将军帅战，败于殽口。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '110101', '有人追亡，为言所匿，不日而得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '101011', '府藏之富，玉以振货。捕鱼河海，罟网多得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '010100', '鸿飞遵陆，公归不复，伯氏客宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '001010', '凫过稻芦，甘乐麸。虽鹜不去，田畯怀忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '110001', '雨师娶妇，黄岩季子。成礼既婚，相呼而南。膏泽应时，年丰大喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '011111', '蓄积有余，粪土不居。美哉轮奂，出有高车。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '111110', '重门击柝，介士守护。终有他道，虽惊不惧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '011000', '大都王市，稠人多宝。公孙宜贾，资货万倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '000110', '秋隼冬翔，数被严霜。甲兵庭堂，万物不生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '011010', '招祸致凶，来螫我邦。痛在手足，不得安息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '010110', '秦失其鹿，高足先得。勇夫慕义，君子率服。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '011101', '山陵四塞，遏我径路。欲前不得，复还故处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '101110', '一指食肉，口无所得，舌嚵于腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '001001', '晨夜惊骇，不知所止。皇母相佑，卒得安处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '100100', '擒狼所言，语无成全。设我白马，使乾口来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '110100', '呼精灵来，魄生无忧。疾病瘳愈，解我患愁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '001011', '牧羊逐兔，使鱼捕鼠。任非其人，卒岁无功。不免辛苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '001101', '堂祥上楼，与福俱居。帝姬治好，国安无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '101100', '禹召诸神，会稽南山。执玉万国，天下康安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '110110', '太姒文母，仍生圣子。昌发受命，为天下主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '011011', '两罝同室，兔无谁告。与狂相触，蒙我与恶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '110010', '桃雀窃脂，巢于小枝。动摇不安，为风所吹。心寒悚惕，常忧殆危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '010011', '阳春长日，万物华实，乐有利福。一作春阳盛长，万物成实。福利所锺，忻忻过日。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '110011', '邻不顾我，而望玉女。身疾疮癞，谁肯媚者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '001100', '涸旱不雨，泽竭无流。鱼鳖乾口，皇天不忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '010101', '狼虎之乡，日争凶讼。受性贪饕，不能容纵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100011', '101010', '阴住阳疾，水离其室。舟楫大作，伤其黍稷。民饥于食，亦病心腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '110001', '文王四乳，仁爱笃厚。子畜十男，无有夭折。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '111111', '下堂出门，东西九山。逢福值喜，得其安闲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '000000', '城上有乌，自鸣破家。招呼丑毒，为国灾患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '010001', '伯虎仲熊，德义渊泓。使布五谷，阴阳顺序。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '100010', '饮酒醉卧，跳起争斗。伯伤仲僵，东家治丧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '010111', '四目相视，稍近同执。日映之后，见吾伯姨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '111010', '随时逐便，不失利门。灵获得福，富于封君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '000010', '陇西冀北，多见骏马。去如焱，害不能伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '010000', '白龙黑虎，起伏俱怒。期战盘空，蚩尤败走。死于鱼首。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '110111', '鸿飞戾天，避害紫渊。虽有锋门，不能危身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '111011', '平国不均，夏氏作乱。乌号窃发，灵公陨命。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '000111', '江汉上游，政逆民忧。阴伐其阳，雄者受殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '111000', '东家杀猪，闻臭腥臊。神怒不顾，命绝衰国。亳社火烧，宋公夷诛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '111101', '西诛不服，恃强负力。倍道趍敌，师走败覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '101111', '一妇六夫，扰乱不治。张王季庄，莫适为公。政道塞壅，周君失邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '000100', '配合相迎，利之四乡。昏以为期，明星煌煌。欣喜奭怿，所言得当。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '001000', '猿坠高木，不踒手足。握金怀玉，还归其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '011001', '卷领遁世，仁德不害。三圣攸同，周国茂兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '100110', '去危脱厄，安无怵惕。上福善堂，见我喜悦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '000011', '带季儿良，时利权兵。将师合战，敌不能当。赵魏以强。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '110000', '鹄思其雄，欲随凤东。顺理两翼，出自日中。须留北邑，复反其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '101001', '且如惊鹿，不能定足。室家分散，各走窜匿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '100101', '甲乙丙丁，俱归我庭。三丑六子，入门见母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '100000', '蹑华巅，观浮云。风不摇，雨不薄。心安吉，患无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '000001', '德施流行，利之四乡。雨师洒道，风伯逐殃。巡狩封禅，以告成功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '111001', '水流趍下，遂成东海。求我所有，买鳣与鲤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '100111', '和气相薄，膏润津泽，生我嘉谷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '100001', '忧惊以除，祸不成灾，安全以来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '011110', '坚冰黄鸟，常哀悲愁。不见甘粒，但睹藜蒿数惊鸷鸟，为我心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '010010', '翕翕〔d.gif〕，实坠崩颠。灭其令名，身命不全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '101101', '因祸受福，喜盈其身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '011100', '陆居千里，不见河海，无有鱼市。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '001110', '鹿得美草，鸣呼其友。九族和睦，不忧饥乏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '111100', '出门得堂，不逢祸殃。入户自苦，不见矛戟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '001111', '累尊重席，命我家客。福佑久长，不见咎殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '101000', '鸿雁俱飞，北就鱼池。鳣鰋鲶鲤，众鸟饶有。一鸣获两，得之过倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '000101', '当风奋翼，与鸟飞北。入我家国，见吾庆室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '110101', '麒麟凤凰，善政得祥。阴阳和调，国无灾殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '101011', '逐狐东山，水过我前。深不可涉，失其后便。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '010100', '丑戌亥子，饥馑所生。阴为暴客，水绝我食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '001010', '狐狸雉兔，畏我迯去。分走窜匿，不知处所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '100011', '桀跖恶人，使得不通。炎旱为殃，年榖大伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '011111', '兔乳立室，行来雀食。虎攫我子，长号不已。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '111110', '土阶明堂，礼让益兴。雄雌相得，使我无疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '011000', '送金出门，井失玉兔。往来井上，破瓮坏盆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '000110', '讽德诵功，美周盛隆。加其旦辅，夬济冲人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '011010', '盗窃灭身，二母不亲。王后无党，毁其宝灵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '010110', '六月骙骙，名欲有至。专征未装，俟侍明旦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '011101', '雀行求粒，误入网罭。赖仁君子，复说归室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '101110', '仁德孔明，患祸不伤。期誓不至，室人御恤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '001001', '龟厌江海，陆行不止。自今枯槁，失其都市。忧悔咎生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '100100', '孤独特处，莫依为辅。正心允济，神劳志苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '110100', '伯仲言留，叔子云去。谁云无咎，主母大喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '001011', '初忧不安，后得笑欢，虽惧无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '001101', '好战亡国，师不以律。称上殒坠，齐疾狼戾。被其灾祟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '101100', '鹿生泽陂，豺伤其麑，泣血独哀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '110110', '天地钤塞，仁智隐伏。商旅不行，利润难得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '011011', '福德之士，欢悦日喜。夷吾相桓，三归为臣。赏流子孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '110010', '上无飞鸟，下无走兽。扰乱未治，劳民于事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '010011', '月削日衰，工夫下机。宇宙灭明，不见三光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '110011', '戴盆望天，不见星辰。顾小失大，福迯墙外。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '001100', '握斗运枢，顺天无忧。所行造德，与乐并居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '010101', '操戟刺鱼，披发立忧。虎脱我舆，狼取我袍。亡马失财。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110001', '101010', '两人俱醉，相与悖戾。心乖不同，争讼匈匈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '011111', '戴尧扶禹，松乔彭祖。西遇王母，道路夷易。无敢难者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '111111', '狼戾美谋，无言不殊。允厌帝心，悦以获佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '000000', '岁暮花落，阳入阴室。万物伏匿，绝不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '010001', '鸡鸣失时，君骚于忧。犬吠不休，行者稽留。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '100010', '凫鹥游泾，君子以宁。履任不愆，福禄来成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '010111', '薄为蕃皮，劲风吹却。欲上不得，复归其宅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '111010', '东行破车，步入危家。衡门垂倒，无以为主。卖袍续食，糟糠不饱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '000010', '青牛白咽，呼我俱田。历山之下，可以多耕。岁精之节，民人安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '010000', '异国殊俗，情不相得。金木为仇，百贼擅谷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '110111', '阴阳精液，高熟脱折。治卵成鬼，肇生头目。日有大吉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '111011', '饥虫作害，多乱缠绵，不可得秋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '000111', '清冷如云，为兵导先。民人宽急，不知东西。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '111000', '班马旅师，以息劳疲。役夫嘉喜，入户见妻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '111101', '坐争立讼，纷纷哅哅。卒成祸乱，灾及家公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '101111', '鹿食美草，逍遥求饱。趍走山间，过期乃还。肥泽且厌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '000100', '田鼠野雉，意尚欲去。拘制笼槛，不得摇动。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '001000', '日趍月步，周遍次舍。历险致远，无有难处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '011001', '天孙帝子，与日月处。光荣于世，福禄祺祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '100110', '晨风文翰，大举就温。时过我邑，羿无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '000011', '旦生夕死，名曰婴鬼，不可潜视。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '110000', '疾贫望幸，使伯南贩。开牢择羊，多得大牂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '101001', '长城骊山，生民大残。涉井发难，唐叔为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '100101', '娶于姜吕，驾迎新妇。少齐在门，夫子欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '100000', '随时草木，灌时叶起。扶疏条桃，长大盛美。华沷铄疏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '000001', '姬姜悦欢，二姓为婚。霜降合好，西施在前。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '111001', '戴笠独宿，昼不见日。勤劳无妄，长劳悲思。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '100111', '始加元服，二十系室。新婚既乐，伯季有德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '100001', '二至灵台，文所止游。云物备具，长乐无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '011110', '久阴霖雨，涂行泥潦。商人休止，市空无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '010010', '城坏厌境，数为齐病。侵伐不休，君臣扰忧。上下屈竭，士民乏财。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '101101', '南国盛茂，黍稷醴酒。可以飨养，乐我嘉佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '011100', '忧在心腹，内崩为疾。祸起萧墙，意如制国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '001110', '朽根刖树，花叶落去。卒逢大焱，随风僵仆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '111100', '树表为坛，相与笑言。午中不会，宠荣弃袚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '001111', '四足俱走，驽疲任后。两战不胜，败于东楚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '101000', '执辔在朝，回还故处。麦秀伤心，叔父无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '000101', '夜长日短，阴为阳贼。万物空枯，藏于北陆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '110101', '鸣鸠七子，均而不殆。长大成就，弃合于好。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '101011', '三羊上山，驰至大原。黄龙负舟，逐到夷阳。宛其玉囊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '010100', '首足易处，头尾颠倒。公为雌妪，乱其蚕织。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '001010', '登高望家，役事未休。王事靡盬，不得逍遥。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '100011', '畏昏不行，候旦待明。燎猎受福，老赖其庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '110001', '孤独特处，莫依无辅，心劳志苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '111110', '山石朽破，消崩坠堕。上下离心，君受其祟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '011000', '文母圣子，无疆寿考，为天下主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '000110', '倔傀如仪，前后相违。言如鳖咳，语不可知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '011010', '五龙俱起，强者败走。露我苗稼，年岁大有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '010110', '雷除善猛，虽为功医。骥疲盐车，出于御棰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '011101', '江南多蝮，螫我手足。冤烦诘屈，痛彻心腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '101110', '心无可据，射鹿不得。多言少实，语无成事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '001001', '君明臣贤，鸣求其友。显德之政，可以履土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '100100', '安土宜官，一日九迁。踰越群等，牧养常山。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '110100', '保辞解谢，除去垢活。惊之成患，屡去酷残。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '001011', '不狂妪盲，相牵北行。欲归高邑，迷惑公得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '001101', '醉卧道傍，迷且失明，不合我生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '101100', '北登鬼丘，驾龙东游。王母御后，文武何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '110110', '恬淡无患，游戏道门。与神来往，长出以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '011011', '以缗易丝，抱布自媒。弃礼怠惰，卒罹悔忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '110010', '被服衣冠，游戏道门。以礼相终，身无灾患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '010011', '大麓鱼池，陆为海涯。君子失行，小人相携。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '110011', '渊泉溢出，为邑之祟。道路不通，孩子心愦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '001100', '十里望烟，散涣四方。形体灭亡，可入深渊。终不见君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '010101', '传言相谈，非好径路。鸣鼓逐狼，不知迹处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011111', '101010', '东失大珠，西行弃襦。时多不利，使我后起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '111110', '河伯大呼，津不可渡。往复示故，乃无大悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '111111', '蒙被恩泽，长大成就。柔顺利贞，君臣合好。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '000000', '东山西土，各自止安。虽欲登望，竟不同堂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '010001', '登山上谷，与虎相触。猬为功曹，班叔奔北。脱之嘉同。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '100010', '踬跌未起，失利后市。不得鹿子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '010111', '结珠怀履，卓斯以思。为君奴婢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '111010', '鸡鸣失时，民作劳苦。犬吠不休，行者稽留。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '000010', '陈妫敬仲，逃兴齐姜。营丘立适，八世大昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '010000', '鹿畏人匿，俱入深谷。短命不长，为虎所得。死于牙腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '110111', '言无约结，不成券契。殷叔季姬，公孙争之。强入委禽，不悦于心，乃适子南。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '111011', '鼓瑟歌舞，欢悦于酒。龙喜张口，大悦在后。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '000111', '凶忧灾殃，日益明章。祸不可救，王却夷伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '111000', '水流趍下，遂成东海。求我所有，贸鳣与鲤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '111101', '阴为阳贼，君不能克。举动失常，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '101111', '离床失案，龟丧其愿。都市无会，叔季怀恨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '000100', '壅遏堤防，水不得行。大慎阳光，阴霓伏藏。走归其乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '001000', '躄屈腹伸，东乘浮云，贵宠母前。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '011001', '实沈参伐，以义断割。次陆服刑，成我霸功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '100110', '金泉黄宝，宜与我市。娶嫁有息，利后过母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '000011', '禹召诸神，会稽南山。执玉万国，天下安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '110000', '三虫作蛊，践迹无与。胜母盗泉，君子不处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '101001', '花叶陨落，公归枢宅。夷子失民，洁己不食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '100101', '履机惧毁，身王子废。终得所欲，无有凶害。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '100000', '道理和得，仁不相贼。君子攸往，我有利福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '000001', '合匏同牢，姬姜并居，寿考长久。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '111001', '关雎淑女，贤妃圣偶。宜家寿母，福禄长久。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '100111', '骓骥脱乳，不知子处。旋踵悲鸣，痛伤我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '100001', '知严绝理，阴孽谋主。十日不食，困于申亥。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '011110', '凿诸攻玉，无不宜凿。麟凤成形，得象君子。三人翼事，所求必喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '010010', '昧暮乘车，以至伯家。踰梁渡河，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '101101', '吾有黍稷，委积外场。有角服箱，运致我藏。富于嘉粮。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '011100', '喜笑且语，不能掩口。官爵并至，庆贺盈门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '001110', '雾露雪霜，日暗不明。阴孽为疾，年谷大伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '111100', '伯去我东，发如飞蓬。寤寐长叹，展转空床。内怀怅恨，心摧肝肠。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '001111', '亡羊补牢，张氏失牛。骍驷奔走，鹄盗我鱼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '101000', '贩鼠卖蛙，利少无谋，难以得家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '000101', '西戎为秩，幽君去室。陈子发难，项伯成乱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '110101', '秋风生哀，花落心悲。公室多难，羊舌氏衰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '101011', '持福厌患，去除大残。日长夜尽，嘉世蒙恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '010100', '新受大喜，福履重来。乐且日富，足用丰财。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '001010', '前顿却踬，左跌右逆。登高安梯，复反来归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '100011', '梦饭不饱，酒来入口。婴女难好，媒应不许。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '110001', '大都王市，稠人多宝。公孙宜买，资祸万倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '011111', '两人俱醉，相与悖戾。心乖不同，争讼恟恟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '011000', '身无头足，超跖庶乖。不能远中，之道疲休。失利后市。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '000110', '三人俱行，六目光明。道逢淑女，与我骥子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '011010', '进士为官，不若复田，获寿保年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '010110', '先易后否，失我所市。骚苏自苦，思吾故事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '011101', '苏秦发言，韩魏无患。张子驰说，燕齐以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '101110', '武库军府，甲兵所聚。非里邑居，不可舍止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '001001', '三桃三口，莫适所与。为孺子牛，西氏生咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '100100', '西山东山，各自止安。虽相登望，竟不同堂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '110100', '不改柯叶，和气冲适。君子所在，安无怵惕。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '001011', '将戌系亥，阳藏不起。君子散乱，大上危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '001101', '天官列宿，五神舍室。宫阙完坚，君安其居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '101100', '左手把水，如光与鬼，不可得徙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '110110', '逐狐东山，水遏我前。深不可涉，失利后便。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '011011', '水渎鱼室，来灌吾邑。冲破我家，与狗俱游。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '110010', '山险难登，涧中多石。车驰轊系，重载伤轴。担负善踬，跌踒右足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '010011', '槽空无实，豚彘不食。庶民屈竭，离其居室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '110011', '执热烂手，大为灾咎。公孙无赖，败我王室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '001100', '三虎上山，更相噬囓。心志不亲，如仇如怨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '010101', '西家嫁女，借邻送女。嘉我淑姬，宾主俱喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111110', '101010', '克身洁己，逢禹巡狩。锡我元圭，拜受福祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '011000', '蒙庆受福，有所获得。不利出城，疾人困极。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '111111', '硕鼠四足，飞不上屋。颜氏渊德，未有爵禄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '000000', '新受大喜，福优重职，乐且日富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '010001', '克身洁己，逢禹巡狩。锡我元圭，拜受福祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '100010', '置筐失筥，轮破无辅。家伯为政，病我下土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '010111', '机言不发，顽不能达。齐鲁为仇，亡我葵丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '111010', '亡锥失斧，公输无辅。抱其彝器，适君子处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '000010', '家在海隅，桡短深流。伯氏难行，无木以超。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '010000', '德施流行，利之四乡。雨师洒道，风伯逐殃。巡狩封禅，以告成功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '110111', '筐倾筥覆，畏我公置。简伯无礼，太师正食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '111011', '泥滓污辱，弃捐沟渎。为众所笑，终不显禄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '000111', '狝猴兔走，腥臊少肉。漏卮盛酒，利无所有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '111000', '鹿畏人藏，俱入深谷。命短不长，为虎所得。死于牙腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '111101', '南山芝兰，君子所有。东家淑女，生我王室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '101111', '左指右挥，邪望侈靡。执节无良，灵君以亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '000100', '爵秩不明，为臣所伤。众阴群聚，共夺日光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '001000', '穿鼻系株，为虎所拘。王母祝祷，祸不成灾。突然自来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '011001', '贫鬼守门，日破我盆。毁鼠伤绶，空虚无子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '100110', '襄王束带，郑人是赖。庄公卿士，王母忧喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '000011', '昭君守国，诸夏蒙德。异类既同，崇我王室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '110000', '冬薮朽腐，当风于道。蒙被尘埃，左右劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '101001', '六爻既立，神明所告。文定吉祥，康叔受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '100101', '泣涕长诀，我心不悦。远送卫野，归宁无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '100000', '三宿无主，南行劳苦。东里失利，丧其珍宝。本卦遯同）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '000001', '大斧砍木，谗佞败国。东关良工，祸及三子。晋人乱邑，怀公出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '111001', '乘风上天，为时服轩。周旋万里，无有患难。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '100111', '大树百根，比与山连。文君作义，受福万年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '100001', '阳伏在下，阴制佑福。生不逢时，潜龙隐处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '011110', '乱头多忧，搔虱生愁。膳夫仲年，使我无聊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '010010', '江河淮海，天之都市。商人受福，国家富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '101101', '泰山幽谷，凤凰游宿。礼义有序，可以求福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '011100', '水山暴怒，坏梁折柱。稽难行旅，留连愁苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '001110', '阿衡服箱，太乙载行。延时历舍，所之吉昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '111100', '三宿无主，南行劳苦。东里失利，丧其珍宝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '001111', '生无父母，出门不喜。买椒失粟，亡我大利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '101000', '安坐玉堂，听乐行觞。饮福万锺，日受无疆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '000101', '登危入厄，四时变易。春霜夏雪，物皆凋落。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '110101', '衣空履穿，无以御寒。细小贫窭，不能自好。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '101011', '目不可合，忧来搔足。怵惕恐惧，去其邦域。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '010100', '赍贝赎狸，不听我辞。系于虎须，牵不得来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '001010', '伯夷叔齐，贞廉之师。以德防患，忧祸不存。芳声后时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '100011', '张王子季，争财相制。商君顽嚚，不知所由。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '110001', '长城既立，四夷宾服。交和结好，昭君是福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '011111', '千欢万悦，举事为决。获受嘉庆，动作有福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '111110', '种一得十，日益有息。仁政获民，四国亲睦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '000110', '安子富有，东国不殃。齐郑和亲，显比以喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '011010', '九里十山，道仰峻难。牛马不前，复反来还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '010110', '鸠杖扶老，衣食百口。曾孙寿考，凶恶不起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '011101', '雾露雪霜，日暗不明。阴孽为疾，年谷大伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '101110', '迷行数却，不知西东。阴疆暴逆，道理不通。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '001001', '登高上山，见王自言。信理我冤，得职蒙恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '100100', '三世为德，天祚以国。封建少昊，鲁侯之福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '110100', '乔木无息，汉女难得。祷神请佩，反手离汝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '001011', '东邻西家，来即我谋。中告吉诚，使君安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '001101', '褰衣出户，心欲奔走。王孙毋惊，使我长生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '101100', '三日不饮，远水无酒。昼夜焦喉，使我为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '110110', '众口销金，愆言不验。腐臭败兔，入市不售。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '011011', '妪冠应门，与伯争言。东家失狗，意在不存。争乱无怠，绝无所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '110010', '祚加明德，与我周国。公刘文母，福流子孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '010011', '针头刺手，百病瘳愈。抑按扪灸，死人复起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '110011', '元龟象齿，大赂为宝。稽疑当否，衰微复起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '001100', '故室旧庐，消散无余。不如新创，可以乐居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '010101', '老狐多态，行为蛊恠。为魅为妖，惊我王母。终无咎悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011000', '101010', '爱子多材，起迹空虚。避害如神，水不能濡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '000110', '禹凿龙门，通利水源。东注沧海，人民得安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '111111', '白鹿鸣呦，呼其老少。喜彼茂草，乐我君子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '000000', '百里南行，虽微复明。去虞适秦，为穆国卿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '010001', '王孙宜家，张名益有。龙子善行，西得大寿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '100010', '画龙头颈，文章不成。甘言善语，谲辞无名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '010111', '商子无良，相怨一方。引斗交争，咎以自当。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '111010', '衰老困极，无齿不食。痔病痏瘵，就阴为室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '000010', '鸳生会稽，稍巨能飞。翱翔桂林，为众鸟雄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '010000', '安平不倾，载福长生，君子以宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '110111', '牛骥同槽，郭氏以亡。国破为墟，君奔走逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '111011', '日中明德，两国盛兴。仁圣会遇，君受其福。臣多荣禄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '000111', '公刘之居，太王所业。可以长生，拜受福爵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '111000', '时凋岁寂，君子疾病。宋女无辜，郑受其殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '111101', '济河踰厄，脱母怵惕。四序为卫，使惠不废。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '101111', '缺破不完，残际侧偏。公孙幽遏，跛倚后门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '000100', '延颈远望，昧为目病。不见叔姬，使伯心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '001000', '上无飞鸟，下无走兽。扰乱未清，民劳于事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '011001', '久阴霖雨，涂行泥潦。民人休止，市空无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '100110', '盲者目张，跛倚起行。瞻望日月，与主相迎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '000011', '据斗运枢，顺天无忧。与乐并居，万代欢庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '110000', '稼穑不偏，重适不倾。巧言贼忠，伤我申生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '101001', '金城铁郭，上下同力。政平民欢，寇不敢贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '100101', '日镜不明，冬灾大伤。盗花失实，十年消亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '100000', '鳏寡孤独，命禄苦薄。入室无妻，武子悲哀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '000001', '饮酒醉饱，跳起争斗。伯伤叔僵，东家治丧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '111001', '介召微子，使君不殆。二国合欢，燕齐以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '100111', '牵颈系尾，诎折几死。雕世无仁，不知所比。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '100001', '东龙究毒，不知所触。南北困穷，王子危急。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '011110', '疾贫王孙，北极无辉。禄命苦薄，两守孤门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '010010', '公孙驾骊，载游东齐。延陵故产，遗季纻衣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '101101', '王良善御，伯乐知马。文王东猎，获嘉贤士。开福佑周，发且兴起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '011100', '日月不居，重耳趋舍。游燕入秦，晋国是霸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '001110', '假文翰翼，随风背北。至虞夏国，与舜相得。年岁大乐，邑无盗贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '111100', '南行北走，延颈望食。举口失利，累我子孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '001111', '开市作喜，建造利事。平准货宝，海内殷富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '101000', '三犬俱走，斗于谷口。白者不胜，死于坂下。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '000101', '骄卤火形，造恶作凶。无所能成，还自灭身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '110101', '拜跪赞辞，无益于尤。大夫顽嚚，使我心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '101011', '辰次降娄，王嘉巡狩。广佑施惠，万国咸喜。子孙荣品，长安不殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '010100', '牵瑜上楼，与福俱游。劳躬治国，安乐无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '001010', '白鸟御饵，鸣呼其子。旋枝张趐，来从其母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '100011', '盲聋独宿，莫与共食。老穷于人，病在心腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '110001', '登木出渊，稍上升天。明德孔圣，白日载荧。宠禄再荣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '011111', '彭离济东，迁之上庸。狼戾无节，失其宠功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '111110', '谮阳上舞，神明正气。禹拜受福，君使我德。居则厚禄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '011000', '从首至足，部分为六。室家离散，逐南乞食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '011010', '民迷失道，乱我统纪。空使乾华，宾无所有。先忧后乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '010110', '刻画为饰，毛嫱西施，求事必得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '011101', '日居月诸，遇暗不明。长夜丧甲，绝其纪纲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '101110', '衣裳颠倒，为王来呼。成就东周，封受大侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '001001', '当变立权，擿解患难。涣然冰释，六国以宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '100100', '西戎獯鬻，病于我国。扶阳之政，以保乾德。终无患惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '110100', '南行逐羊，子利喜亡。阴孽为病，复返其邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '001011', '游戏仁德，日益有福。凶言不至，妖孽灭息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '001101', '春日新婚，就阳日温。嘉乐万岁，获福大椿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '101100', '阴升阳伏，鬼哭其室。相饰不食，安巢如棘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '110110', '臣尊主卑，权威日衰。侵夺无光，三家逐公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '011011', '反言为贼，戎女生患。乱吾家国，父子相贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '110010', '迎福开户，喜逐我后。康伯恺悌，治民以礼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '010011', '日就月将，昭明有功。灵台观赏，胶鼓作仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '110011', '百草嘉卉，萌芽将出。昆虫扶户，阳明所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '001100', '天所佑助，福至祸去，君主何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '010101', '穷夫失居，唯守旧庐。初忧中惧，终日竞竞。无悔无虞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000110', '101010', '买玉得石，失其所欲。荷蒉击磬，隐耳无声。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '011010', '席多针刺，不可以卧，动而有悔，言行俱过。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '111111', '乌鹊食谷，张口受哺，蒙被恩德，长大成就。柔顺利贞，君臣合好。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '000000', '六鹢退飞，为襄败祥，陈师合战，右股夷伤，遂以薨崩，霸功不终。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '010001', '匍匐出走，惊惶悼恐，白虎王孙，蓐收在后，居中无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '100010', '庇卢不明，使孔德妨，女孽乱国，虐政伤仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '010111', '石属四足，不能上屋，颜氏淑德，未有爵禄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '111010', '襄送季女，至于荡道，齐子旦夕，留连久处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '000010', '麞鹿逐牧，饱归其居，还反次舍，乐得自如。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '010000', '望尚阿衡，太宰周公，藩屏汤武，立为侯王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '110111', '开廓洪绪，王迹所基，报以八子，功得俟时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '111011', '八会大都，饶富有余，安民利国，可以长居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '000111', '阴云四方，日在中央，人虽昏雾，我独昭明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '111000', '薄为灾虐，风吹云却，欲上不得，复规其宅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '111101', '昭昭略略，非忠信客，言语反复，以黑为白。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '101111', '三女为奸，俱游高园，背室夜行，与伯笑言，祸及乃身，冤死谁祷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '000100', '涉尸留鬼，大斧所视，文昌司过，简公乱死。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '001000', '大足长股，利出行道，困仓充盈，疏齿善市，宜钱富家，事得万倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '011001', '筐筥锜釜，可活百口，伊氏鼎俎，大福所起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '100110', '升高登虚，欲有望侯，驾之北邑，与喜相扶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '000011', '用彼嘉宾，政平且均，螟虫〔p.gif〕不作，民得安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '110000', '桃夭少叶，婚悦宜家，君子乐胥，长利止居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '101001', '东行失旅，不知所处，西归无妃，莫与笑语。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '100101', '玩好乱目，巧声迷耳，贼败贞良，君受其咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '100000', '明德孔嘉，万岁无亏，驾龙巡狩，王得安所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '000001', '同本巽叶，乐仁尚德，东邻慕义，来兴吾国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '111001', '戴山崔嵬，曰高无颓，军主好德，赐以家国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '100111', '筑室合欢，千里无患，周公万年，佑我二人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '100001', '养鸡生雏，畜马得驹，明堂太学，君子所居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '011110', '雷行相逐，无有休息，战于平陆，为夷所覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '010010', '委蛇循河，北至海涯，涉历要荒，君世无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '101101', '鸿声大视，高举神化，背昧向明，以道福功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '011100', '比目四翼，来安吾国，福善上堂，与我同床。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '001110', '先縠彘季，反谋桓子，不从元帅，遂行挑战，为荆所败。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '111100', '三头六足，欲盗东国，颜子在迩，祸灭不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '001111', '缘山升木，中堕于谷，子舆失劳，黄鸟哀作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '101000', '南有嘉鱼，驾黄娶鳞，鲂鲤弥弥，利来无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '000101', '邃气作云，蒙覆大君，塞聪闭明，殷人贾伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '110101', '举翅櫖翼，跂望南国，延颈却缩，未有所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '101011', '坎中虾蟆，乍盈乍虚，三夕二朝，形消无余。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '010100', '僮子射御，不知所定，质疑蓍龟，孰知所避。国安土乐，宜利止居，兵蔻不至，民无骚扰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '001010', '阴淫寒疾，水离其室，舟楫大作，伤害黍稷。民饥于食，不无病厄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '100011', '离友绝朋，巧言缠匿，覆白污玉，颜叔哀哭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '110001', '童女无媒，不宜动摇，安其室庐，傅母何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '011111', '作凶作患，北檄困贫，东与祸连，伤我老根。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '111110', '东南其户，风雨不处，曣晲仁人，父子相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '011000', '被发兽心，难与比邻，来如飘风，去似绝弦，为狼所残。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '000110', '天覆地载，日月运照。阴阳允作，方内四富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '010110', '桀乱无道，民散不聚。背室弃家，君孤出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '011101', '申酉稷射，阴慝萌作。柯葭载牧，泥涂不白。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '101110', '踝踵足伤，右指病疡。失旅后时，利走不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '001001', '四足俱走，驽疲在后。战既不胜，败于东野。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '100100', '涂行破车，丑女无媒。莫适为耦，孤困独居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '110100', '搏髀大笑，不知忧惧。开立大路，为主所召。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '001011', '伯圭东行，与利相逢。出既遭昧，孰不相知，忧不成凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '001101', '东行贼家，郑伯失辞。国无贞良，居受其殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '101100', '前屈后曲，形体饬急。绞黑大索，困于清室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '110110', '鼓腋大喜，行婚饮酒。嘉彼诸姜，乐我皇考。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '011011', '国将有事，狐嘈向城。三日悲鸣，邑主大惊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '110010', '明德克敏，重华贡举。放勋征用，公哲蒙佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '010011', '秋隼冬翔，数被严霜。甲兵充庭，万物不生。雄父夜鸣，民大扰惊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '110011', '丝纻布帛，人所衣服。掺掺女手，纺绩善织，南国饶足，取之有息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '001100', '凤有十子，同巢共母。仁圣在位，欢以相保，兴彼周鲁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '010101', '雄鸡不晨，雌鸡且伸。志庇心离，三旅出哀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011010', '101010', '光祀春成，陈宝鸡鸣。阳鸟失道，不能自守，消亡无咎。（举事不成，自取凶咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '010110', '踬跛未起，失利后市，不得鹿子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '111111', '左辅右弼，金玉满堂。常盈不亡，富如廒仓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '000000', '雨师娶妇，黄岩季女。成礼既婚，相呼南上。膏泽下土，年岁大喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '010001', '螟虫为贼，害我嘉榖。中留空虚，家无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '100010', '跛躄难步，道不及舍。露宿泽陂，亡其襦裤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '010111', '大夫祈父，无地不涉。为吾相土，莫如韩乐。可以居止，长安富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '111010', '少孤无父，长失慈母。悖悖茕茕，莫与为耦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '000010', '侧弁醉客，长舌作凶。披发夜行，迷乱相误。亡失居处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '010000', '马惊车破，王坠深津。身绝魂去，离其室庐。贞难无虞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '110111', '东行述职，征讨不服。侵齐伐陈，御璧为臣。大得意还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '111011', '百足俱行，相辅为强。三圣翼事，王室宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '000111', '根本不固，华落叶去，更为孤妪。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '111000', '牧羊稻园，闻虎喧讙。畏惧怵惕，终无祸焉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '111101', '履位乘势，靡有绝弊。为隶所图，与众庶伍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '101111', '大舆多尘，小人伤贤。皇甫司徒，使君失家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '000100', '安如泰山，福禄屡臻。虽有狼虎，不能危身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '001000', '同气异门，各别东西。南与凶遇，北伤其孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '011001', '蜺见不祥，祸起我乡。行人畏惧，使命不通。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '100110', '养虎畜狼，还自贼伤。无事招福，自取灾殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '000011', '顺风吹火，幸附骥尾。易为功力，因权受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '110000', '五岳四渎，沾濡为德。行不失理，民赖恩福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '101001', '延陵聪敏，听乐太史。鸡鸣大国，姜氏受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '100101', '神鸟五气，凤凰为主。集于王国，使君得所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '100000', '媒妁无明，虽期不行。齐女长子，乱我纪纲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '000001', '明月作书，大人失居。众星宵乱，不知所据。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '111001', '少康兴起，诛浇复祖。微灭复明，宫祀大禹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '100111', '千门万户，大福所处。黄屋左纛，龙德独右。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '100001', '乾作圣男，坤为智女。配合成就，长住乐所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '011110', '羿张乌号，彀射惊狼。钟鼓夜鸣，将军壮心。赵国雄勇，斗死荥阳。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '010010', '炙鱼铜斗，张伺夜鼠。不忍香味，机发为祟。祟在头颈。筰不得去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '101101', '高飞不视，贪饕所在。臭腐为患，自害其身。（一作窃位贪荣，内污外清。时时暂过，日日祸生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '011100', '铅刀攻玉，坚不可得。尽我觔力，胝胼为疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '001110', '方喙宣口，圣智仁厚。解释倒悬，历国安泰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '111100', '踟蹰南北，误入丧国。社季利兵，伤我心腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '001111', '公孙之政，惠而不烦。乔子相国，终身无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '101000', '弧矢大张，道绝不通。小人寇贼，君子塞壅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '000101', '藏戟之室，封豕受福。充泽肥腯，子孙蕃息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '110101', '八子同巢，心劳相思，雉苦无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '101011', '循理举手，典求相予。六休相磨，终无殃咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '010100', '公子王孙，把弹摄丸。发辄有获，室家饶足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '001010', '井渚有悔，渴蜺为怪。不亟徙乡，家受其殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '100011', '郑浍有声，国乱失倾。弘明早见，止乐不能。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '110001', '穿室凿墙，不直生讼。褰衣涉河，虽势无功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '011111', '胎卵胞乳，长大成就。君子万年，动有利得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '111110', '五心乖离，各引是非。莫适为主，道路塞壅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '011000', '百柱载梁，千岁不僵。大愿辅福，文武以昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '000110', '营城洛邑，周公所作。世连三十，年历七百。福佑丰实，坚固不落。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '011010', '从叔旅行，食于东昌。嘉伯悦喜，与我芝香。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '011101', '失耳聋蔽，不晓声味。委以鼎俎，方始乱愦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '101110', '訾娵开门，鹤鸣弹冠。文章进用，舞韶和鸾。三仁翼政，国无灾殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '001001', '游魂六子，百木所起。三男从父，三女从母。至己而足，各得其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '100100', '南山蓝蔵，使君媚好。皇女长妇，多孙众子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '110100', '黄虹之野，贤君所在。荣段为相，国无灾殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '001011', '穿凿道路，为君除舍。开辟福门，喜在我邻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '001101', '商风数起，天下昏晦。旱魃为虐，七凡兵作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '101100', '自卫反鲁，时不我与。冰炭异室，仁道闭塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '110110', '春阳生草，夏长条枝。万物蕃滋，充实益有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '011011', '大蛇奔走，奔入茂草。惊于长往，畏惧喙口。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '110010', '明月照夜，使暗为昼。国有仁贤，君尊于故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '010011', '避地东走，反入虎口。制于爪牙，骨于灰土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '110011', '倾迭不行，弱走善僵。孟絷无良，失其宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '001100', '十年俱见，黄头为首。岁尾民安，国乐无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '010101', '望风入门，来到我邻，铺吾养均。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010110', '101010', '登高连返，视失弥远。虎口不张，害贼消亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '011101', '马眼长股，宜行善市。皆蒙福佑，获金三倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '111111', '高原峻山，址大少泉。草木林麓，喜得所蓄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '000000', '一门二关，结弭不便。峻道异路，日暮不到。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '010001', '忧患解除，喜至庆来。坐立欢门，与乐为邻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '100010', '疏类异路，心不相慕。牝牛牡豭，鳏无室家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '010111', '太王为父，王季孝友。文武圣明，仁政兴起。旦隆四国，载福绥厚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '111010', '临河求鲤，燕婉笑弭。屏气摄息，不得鲤子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '000010', '买利求福，莫如南国。仁德所在，金玉为宝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '010000', '白虎赤愤，门观王庭。宫阙被甲，大小出征。天下烦愦，育不能婴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '110111', '子车针虎，善人危殆。黄鸟悲鸣，伤国无辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '111011', '两目失明，入暮无光。胫足跛步，不可以行。顿于丘傍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '000111', '罗网四张，鸟无所翔。征伐困极，饥穷不食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '111000', '伯夷叔齐，贞廉之师。以德防患，忧祸不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '111101', '疾贫望幸，使伯行贩。开牢择羊，多得大牂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '101111', '南山之杨，其叶将将。嘉乐君子，为国宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '000100', '东壁余光，数暗不明。主母嫉妒，乱我事业。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '001000', '迷行晨夜，道多湛露。沾濡襦裤，重不可步。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '011001', '目足动，嘉喜有顷，举家蒙宠。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '100110', '鹰鹞欲食，雉兔困急。延颈见尾，为我所贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '000011', '鼻移在项，枯叶伤生。下枯上荣，家扰不宁。失其金城。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '110000', '飞不远去，汝为内伤。禄养未富，终无灾咎。君善安止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '101001', '倒基败筥，重舌作凶。被发长夜，迷乱相误。深亡吉居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '100101', '亥午相错，败乱绪业。民不得作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '100000', '野麋畏人，俱入山谷。命短不长，为虎所得。死于牙腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '000001', '秋冬探巢，不得鹊雏。御指北去，愧我少姬。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '111001', '双凫俱飞，欲归稻池。经涉雚泽，为矢所射。伤我胸臆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '100111', '天门开辟，宇户寥廓。桎梏解脱，拘囚纵释。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '100001', '尼父孔丘，善钓鲤鱼。罗网一举，得获万头。富我家居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '011110', '彭生为妖，暴龙作灾。盗尧衣裳，聚跖荷兵。青禽照夜，三旦夷亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '010010', '华言风语，乱相诳误。终无凶事，安宁如故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '101101', '延颈见足，身困名辱。欲隐避仇，为害所灭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '011100', '无足断跟，居处不安。凶恶为残，君臣相得。一作君臣得安，和合于天。保下奠上，大相蒙湛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '001110', '三人俱行，北求大牂。孟长病足，借季负粮。柳下之贞，不失骊黄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '111100', '退飞见祥，伤败毁坠。守小失大，功名不遂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '001111', '持心惧怒，善摇数动。不安其处，散涣府藏。利得无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '101000', '牵尾不前，逆理失臣，怒翔以奔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '000101', '禄如周公，建国洛东，父子俱封。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '110101', '君有八人，信允笃敏，为尧所举。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '101011', '久阴霖雨，泥涂行潦。商人休止，市空无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '010100', '无足断跟，居处不安。凶恶为残。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '001010', '马蹄踬车，妇恶破家。青蝇污白，恭子离居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '100011', '噂噂所言，莫如我垣。欢喜坚固，可以长安。（乾之困，大有之屯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '110001', '懿公浅愚，不受深谋。无援失国，为狄所灭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '011111', '骐骥绿耳，章明造父。风伯所献，襄续厥绪。佐文成伯，为晋元辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '111110', '驾车十里，来鲜鲂鲤。非其肆居，自今后市。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '011000', '求麞嘉乡，恶地不行。道止中返，复还其床。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '000110', '使鸠负装，醉卧道傍。不知何功，窃我衣囊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '011010', '登昆仑，入天门。过糟丘，宿玉泉。问惠观，见仁君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '010110', '木为大床，患厌不起。季伯夜行，与善相逢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '101110', '乌孙氏女，深目黑丑。嗜欲不同，过时无耦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '001001', '子鉏执麟，春秋作经。元圣将终，尼父悲心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '100100', '灼火泉源，钓鲂山巅。鱼不可得，火不肯燃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '110100', '天马五道，炎火久处。往来上下，作文约己。衣枲丝麻，相随笑歌，凶恶如何。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '001011', '鸱鸮破斧，冲人危殆。赖旦忠德，转祸为福。危倾复立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '001101', '牡飞关启，忧患大解，不为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '101100', '石门晨门，荷蒉食贫。遁世隐居，竟不逢时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '110110', '兔聚东郭，众犬俱猎。围缺不成，无所能获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '011011', '三羊群走，雉兔惊骇。非所畏惧，自令劳苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '110010', '羽翮病伤，无以为强。宋公德薄，败于水泓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '010011', '姬姜稚叔，三人偶食。论仁议福，以安王室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '110011', '精诚所在，神人为辅。德教亡患，弥世长久。三圣仍事，多受福祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '001100', '岐周海隅，独乐不忧。可以避难，全身保财。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '010101', '孤独特处，莫为依辅，心劳志苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011101', '101010', '顾望登台，意常欲逃。买辛丑恶，妻不安夫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '101110', '积德之君，仁政且温。伊吕股肱，国富民安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '111111', '顷筐卷耳，忧不能伤。心思古人，悲慕失母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '000000', '郄叔贾贷，行禄多悔，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '010001', '蹙足跛袵，辟坐不行。弃捐平人，名字无中。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '100010', '文王四乳，仁爱笃厚。子畜十男，夭折无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '010111', '容民畜众，不离其居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '111010', '三雏相逐，蝇坠釜中。灌沸潦殪，与母长决。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '000010', '所望在外，鼎令方来。拭爵涤罍，炊食待之。不为季忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '010000', '陆居少泉，高山无云。车行千里，涂污尔轮。亦为我患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '110111', '东家杀牛，污臰腥臊。神背西顾，命绝衰周。亳社灾烧，宋人夷诛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '111011', '长子入狱，妇馈母哭。霜降旬日，向晦伏法。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '000111', '温山松柏，常茂不落。凤凰以庇，得其欢乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '111000', '大屋之下，朝多君子。德施溥育，宋受其福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '111101', '罗张目列，围合有缺。采捕无功，鱼鸟得脱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '101111', '羔裘豹衣，高易我宇。君子惟好，至老无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '000100', '大头明目，载受福喜。三雀飞来，与禄相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '001000', '销锋铸耜，纵牛放马。甲兵解散，夫妇相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '011001', '吉月车攻，田弋双禽。宣王饮酒，以告嘉功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '100110', '商人行旅，资无所有。贪贝逐利，留连王市。轘辕内安，君子何咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '000011', '火入井口，阳芒生角。犯历天门，窥见太微。登上玉床，家易其公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '110000', '秋隼冬翔，数被严霜。甲兵充庭，万物不生。雄父夜鸣，民扰大惊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '101001', '东行西步，失其次舍。乾侯野井，昭君丧居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '100101', '肿胫病腹，陷厕污辱。命短时极，孤子哀哭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '100000', '切肤近灾，虎绝我须。小人横暴，君子何灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '000001', '女室作毒，为我心疾。和弗能治，晋人赴吉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '111001', '兵征大宛，北出玉关。与胡寇战，平城道西。七日绝粮，身几不全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '100111', '十子夫九，莫适与居。贞心不宣，至今名孤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '100001', '车行稻麦，遂至家国。乐土无灾，君子何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '011110', '作室山根，所以为安。一夕崩巅，破我饔餐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '010010', '六人俱行，各遗其囊。黄鹄失珠，无以为明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '101101', '伯蹇叔盲，莫为守装。失我衣裘，我是阴邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '011100', '褒宠溢尤，败政倾家。覆我宗国，秦灭周室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '001110', '诡言译语，仇祸相得。冰入炭室，消灭不息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '111100', '彭生为妖，暴龙作灾。盗尧衣裳，聚跖荷兵。青禽照夜，三日夷亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '001111', '朝暮日月，四马过隙。岁短期促，时难再得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '101000', '耳阙道丧，所为不成，所求匪得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '000101', '申公患楚，危不自安。重耳出奔，侧丧其魂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '110101', '南上泰山，困于空桑。左沙右石，牛马无食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '101011', '海隅辽右，福禄所在。柔嘉义礼，九夷何咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '010100', '阳春生长，万物茂壮。垂秋布叶，君子比德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '001010', '低头窃视，有所畏避。行作不利，酒酸鱼败。众莫贪嗜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '100011', '左辅右弼，金玉满堂。常盈不亡，富如敖仓。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '110001', '坐朝垂轩，据德宰民。虞叔受命，六合和亲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '011111', '东行西走，丧其犬马。南求骅骝，失车林下。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '111110', '砥德砺材，果当成周。拜受大命，封为齐侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '011000', '西逢王母，慈我九子。相对欢喜，王孙万户。家蒙福祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '000110', '安坐玉床，听韶行觞。饮福万岁，曰寿无疆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '011010', '登高望家，役事未休。王事靡盬，不得逍遥。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '010110', '击鼓陷陔，不得相踰。章甫文德，福厌祸消。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '011101', '追亡逐北，呼还幼叔。至止而德，复归其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '001001', '老猾大偷，东行盗珠。困于噬敖，几不得去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '100100', '禹召诸神，南山会稽。执玉万国，天下康宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '110100', '忉忉怛怛，如将不活。黍稷之恩，灵辄以存。获生保年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '001011', '俟叔兴起，季子富有。照临楚国，蛮荆是安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '001101', '白马骏骝，更生不休。富我商人，利得如丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '101100', '灼火泉源，钓鲂山巅。鱼不可得，火不肯燃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '110110', '避患东西，反入祸门。糟糠不足，忧动我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '011011', '我王多宠，商人惶恐。生其祸心，使我危殆。终无灾咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '110010', '虎饥欲食，见猬而伏。禹通龙门，避咎除祸。元丑以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '010011', '安民呼池，玉杯大案。泉如白蜜，一挹获愿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '110011', '双凫鸳鸯，相随群行。南至饶泽，食鱼与粱。君子乐长。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '001100', '蔡侯朝楚，留连江渚。踰时历月，思其君后。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '010101', '骖车驾东，与雨相逢。五楘解堕，颓杌独坐。忧为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101110', '101010', '螟虫为贼，害我稼穑。尽禾殚麦，秋无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '001001', '枯瓠不朽，利以济舟。渡踰江海，无有溺忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '111111', '陷涂溺水，火烧我履，忧患重累。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '000000', '旦生夕死，名曰婴鬼，不可得祀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '010001', '扬水潜凿，使石洁白。衣素表朱，游戏皋泽。得君所愿，心志娱乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '100010', '众鸟所翔，呼有大怪。九身无头，魂惊魄去。不可以居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '010111', '刖根枯株，不生肌肤。病在于心，身以燋枯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '111010', '府藏之富，王以振贫。捕鱼河海，罟网多得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '000010', '一茎九躔，更用牵挛。安明俯仰，不得东西。赞谳当决，日午被刑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '010000', '耋老鲐背，齿牙动摇。近地远天，下入黄泉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '110111', '季蛇叔虎，野心善怒。黩货无厌，以灭其身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '111011', '吁疑八子，更相欺绐。管叔善政，不见邪期。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '000111', '绊逃不远，心与言反。尼丘顾家，茅簟朱华。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '111000', '蜉蝣戴盆，不能上山。摇推跛，顿伤其颜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '111101', '朝露不久，为恩惠少。膏泽欲尽，咎在枯槁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '101111', '河伯之功，九州岛攸同。载祀六百，光烈无穷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '000100', '三人北行，大见光明。道逢淑女，与我骥子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '001000', '金精耀怒，带剑过午。徘徊高库，宿于木下。两虎相距，弓弩满野。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '011001', '江河淮海，天之奥府。众利所聚，可以富有。安乐无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '100110', '不虞之患，祸至此门。奄忽暴卒，病伤我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '000011', '画龙头角，文章未成。甘言美语，说译无名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '110000', '缺破不成，胎卵不生，不见兆刑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '101001', '旁行不远，三里反复。心多畏恶，日中止舍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '100101', '四渎不安，兵革为患。探我妻子，家复饥寒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '100000', '喜来如云，举家蒙欢。众财君子，喜福盈门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '000001', '载金贩狗，利弃我走。藏匿渊底，拆晦为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '111001', '日中为市，各抱所有。交易赀贿，函珠为宝。心悦欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '100111', '日趋月步，周遍次舍。经历致远，无有难处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '100001', '阳明失时，阴凝为忧。主君哀泣，丧其元侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '011110', '年衰岁暮，精魂游去。形容消枯，哀子相呼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '010010', '少无功绩，老困失福。跌行跛踦，不知所立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '101101', '持心耀目，善数摇动。自东徂西，不安其处。涣散府藏，无有利得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '011100', '贝赎狸，不听我辞。系于虎须，牵不得来。需睽否革同人否随师）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '001110', '老狼白，长尾大胡。前颠后踬，岐人悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '111100', '背地相憎，心志不同。如火与金，君猛臣慑。虎行兔伏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '001111', '夏台羑里，汤文厄处。鬼侯歠醢，岐人悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '101000', '牙生齿，螳蜋启户。幽人利贞，鼓翼起舞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '000101', '烈女无夫，闵思苦忧。齐子无良，使我心愁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '110101', '践履危难，脱厄去患。入福喜门，见我大君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '101011', '拆臂接手，不能进酒。析杞闲旷，神怒弗喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '010100', '蚁封户穴，大雨将集。鹊数起鸣，牝鸡叹室。相薨雄文，来到在道。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '001010', '胡俗戎狄，太阴所积。涸洌冱寒，君子不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '100011', '翕翕，稍颓崩颠。灭其令名，身不得全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '110001', '螟虫为贼，害我稼穑。尽禾殚麦，秋无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '011111', '三鸟飞来，自我逢时。俱行先至，多得大利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '111110', '龙马上山，绝无水泉。喉唇燋乾，渴不可言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '011000', '春生子乳，万物蕃炽。君子所集，祸灾不至。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '000110', '王孙季子，相与为友。明允笃诚，升擢荐举。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '011010', '六明并照，政入有统。秦楚战国，民受其咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '010110', '蝃蝀充侧，人所惑。女谒横行，正道壅塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '011101', '登昆仑，入天门。过糟丘，宿玉泉。问惠观，见仁君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '101110', '体重飞难，未能越关，不离空垣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '100100', '元黄虺隤，行者劳罢。役夫憔悴，踰时得归。乾之革，师之临得作不）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '110100', '孔德如玉，出于幽谷。飞上高木，鼓其羽翼。辉光照国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '001011', '火虽炽，在吾后。寇虽众，在吾右。身安吉，不危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '001101', '旃裘膻国，文礼不饰。跨马控弦，伐我都邑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '101100', '被发八十，暮德献服。边鄙不耸，以安王国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '110110', '心得所好，口常欲笑。公孙蛾眉，鸡鸣乐夜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '011011', '马西负乘，见邑之野。并获粱稻，喜悦无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '110010', '高飞视下，贪饕所在。腐臭为患，害于躬身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '010011', '东行西步，失其次舍。乾侯野井，昭公丧居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '110011', '神鸟五彩，凤凰为主。集于山谷，使年岁育。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '001100', '石门晨门，荷蒉食贫。遁世隐居，竟不逢时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '010101', '啮啮，贫鬼相责。无有欢怡，一日九结。音涧）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '101010', '白日扬光，雷车避藏。云雨不行，为止其乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '100100', '君孤独处，单弱无辅。名曰困苦，辅心涌泉。碌碌如山。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '111111', '忧惊已深，祸不为灾，安全以来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '000000', '穿匏浥水，构铁荧火。劳疲力竭，饥渴为祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '010001', '蹇牛折角，不能载粟。灾害不避，年岁无谷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '100010', '邑将为墟，居之忧危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '010111', '根刖树残，花叶落去。卒逢火焱，随风僵仆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '111010', '元后贪欲，穷极民力。执政乖劣，为夷所覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '000010', '北山有黍，使叔寿考。东岭多粟，宜行贾市。陆梁雄雉，所至利喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '010000', '高原峻山，陆土少泉。草木林麓，嘉禾所灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '110111', '小畜）辰次降娄，王驾巡狩。广施德惠，国安无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '111011', '轠轠，岁暮偏弊。宠名复弃，君衰于位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '000111', '放衔委辔，奔乱不制。法度无常，君失其位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '111000', '独登西垣，莫与笑言。秋风多哀，使我心悲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '111101', '胫急股挛，不可出门。暮速群旅，必为身患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '101111', '情伪难知，使我偏颇。小人在位，虽圣何咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '000100', '黍稷醇醲，敬奉山宗。神嗜饮食，甘雨嘉祥。庶物蕃茂，时无灾咎，独蒙福祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '001000', '公子王孙，把弹摄丸。发辄有获，室家饶足。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '011001', '阴升阳伏，舜失其室。元元赤子，相馁不食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '100110', '七窍龙身，造易八元。法天则地，顺时施恩。引和贵长，以富永存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '000011', '逐狐东山，水遏我前。深不可涉，失利后便。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '110000', '衔命辱使，不堪其事。中坠落去，更为负载。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '101001', '温仁君子，忠孝所在。八闰为仪，祸灾不起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '100101', '春多膏泽，夏润优渥。稼穑熟成，数获百斛。师行以律，霸功不远。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '100000', '二女同室，心不聊食。首发如蓬，忧常在中。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '000001', '筑阙石颠，立本泉源。病疾不安，老孤为邻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '111001', '欲避凶门，反与祸邻。颠覆不制，痛熏我心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '100111', '踧行窃视，有所畏避。狸首伏藏，以夜为利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '100001', '人面鬼口，长舌为斧。斲破瑚琏，殷商绝后。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '011110', '和气相薄，膏泽津液，生我嘉谷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '010010', '销金铸兵，雷车不行，民安其乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '101101', '秦仪机言，解其国患。一说燕下，齐相以权。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '011100', '旦奭辅王，周德孔明。越裳献雉，万国咸宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '001110', '弱足刖跟，不利出门。贾市无过，折亡为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '111100', '坚冰黄鸟，常哀悲愁。不见甘粒，但睹藜蒿。数惊鸷鸟，为我心忧。乾之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '001111', '魂微惙惙，属纩听绝。豁然大通，复更生活。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '101000', '阴生鹿，鼠舞鬼谷。灵龟陆处釜甑草土。人知败国，桀乱无绪。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '000101', '凿诸攻玉，无不穿凿。龙体吾举，鲁班为辅。舞凤成形，德象君子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '110101', '山作天时，陆为海口，民不安处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '101011', '东风启户，隐伏欢喜。萌庶蒙恩，复得我子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '010100', '华灯百枝，植暗衰微。精光欲尽，命如灰麋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '001010', '三十无室，寄伯桑中。上宫长女，不得乐同。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '100011', '卵与石斗，糜碎无处。动而有悔，出不得时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '110001', '寻兵争强，失其贞良，败我殽乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '011111', '虐除善疑，难为攻医。骥穷盐车，困于御御。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '111110', '操笱搏狸，荷弓射鱼。非其器用，自令心劳。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '011000', '葵丘之盟，献晋会庭。见太宰辞，后秦还兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '000110', '膑诈庞子，夷书木。伏兵卒发，矢至如雨。魏师惊乱，将获为虏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '011010', '南行出城，世得大福。王姬归齐，赖其所欲。以安邦国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '010110', '冬采薇兰，地冻坚难。虽利奔走，暮无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '011101', '王乔无病，狗头不痛。亡破失履，乏我欲速。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '101110', '宛马疾步，盲师坐御。自不见路，中止弗到。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '001001', '求我难国，亡去我北。忧归其城，反为我贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '110100', '比目四翼，安我邦国。上下无思，为我嘉福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '001011', '八材既登，以成嘉功。龙降庭坚，国无灾凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '001101', '消弊穿空，家莫为宗。奴婢走，子西父东。为身作凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '101100', '鸟舞国城，邑惧卒惊。仁德不修，为下所倾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '110110', '五谷不熟，民苦困急。驾之南国，嘉乐有得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '011011', '黄裳建元，病得在身。福佑洋溢，封为齐君。贾市无门，富贵多餐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '110010', '齐东郭庐，嫔于洛都。骏良美好，利得万倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '010011', '安床厚褥，不得失宿。弃我嘉宴，困于南国。投杼之忧，不成祸灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '110011', '内崩身伤，中乱无恒。虽有美粟，不得其食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '001100', '出门逢患，与祸为怨。更有拏刺，伤我指端。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '010101', '出入节持，南北无忧。行者即至，在外归来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '101010', '公孙驾车，载游东齐。延陵说产，遗季纻衣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '110100', '别离分散，长子从军。稚叔就贼，寡老独安。莫为种瓜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '111111', '旦种谷豆，暮成藿羹。心之所愿，志快意惬。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '000000', '牡飞门启，忧患大解，不为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '010001', '东山西山，各自止安。虽相登望，竟未同堂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '100010', '众鸟所翔，中有大怪。九身无头，魂惊魄去。不可以居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '010111', '交侵如乱，民无聊赖。追我济西，狄人便殚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '111010', '麟凤所翔，国无咎殃。贾市十倍，复归惠乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '000010', '凿井求玉，非卞氏宅。身困名辱，劳无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '010000', '文山鸿豹，肥腯多脂。王孙获愿，载福巍巍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '110111', '周成之隆，刑措除凶。太宰费佑，君子作仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '111011', '珪璧琮璋，执贽见王。百里宁戚，应聘齐秦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '000111', '穿空漏敝，破坏残缺。陶弗能治，瓦甓不凿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '111000', '鸿飞循陆，公出不复，伯氏客宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '111101', '虾蟆群聚，从天请雨。云雷连集，应时辄下。得其所愿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '101111', '先弱无子，不能自理。为民虽忧，终不离咎。管子治国，侯伯宾服。乘舆八百，尊我恒德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '000100', '摇梅折枝，与母别离，绝不相知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '001000', '盛中不绝，衰老复拙。盈满减亏，瘯腯肥。郑昭失国，重耳兴起。一云去必衰，羸去却肥。郑昭失国，重耳得时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '011001', '闻虎入邑，心欲匿。走据阳德，不见霍叔。绝无忧慝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '100110', '随时逐便，不失利门。多获得福，富于封君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '000011', '禹作神鼎，伯益衒指。斧斤既折，憧立独倚。卖市不售，枯槁为福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '110000', '春鸿飞东，以马货金。利得十倍，重载归乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '101001', '金齿铁牙，寿考宜家。年岁有余，贪利者得。虽忧无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '100101', '膏泽沐浴，洗去污辱。振除灾咎，更与寿福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '100000', '履阶登墀，高升峻巍。福禄洋溢，依天之威。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '000001', '坤厚地德，庶物蕃息。平康正直，以绥大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '111001', '绝域异路，多所畏恶。使我惊惶，思吾故处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '100111', '襁褓孩幼，冠带成家。出门如宾，父母何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '100001', '一寻百节，绸缪相结。其指诘屈，不能解脱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '011110', '鹰鹯猎食，雉兔困极。走见尾，为人所贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '010010', '危坐至暮，请求不得。膏泽不降，政戾民忒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '101101', '刚柔相呼，二姓为家。霜降既同，惠我以仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '011100', '慈母念子，飨赐德士。蛮夷来服，国人欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '001110', '良夫孔姬，负悝登台。栾季不扶，卫辄走逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '111100', '子长忠直，季氏为贼。祸及无嗣，司马失福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '001111', '节庆之德，不涉乱国。虽昧无光，民受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '101000', '驱羊南行，与福相逢。狼惊我马，虎盗我子。悲恨自咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '000101', '尼父孔丘，善钓鲤鱼。罗网一举，获利万头。富我家居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '110101', '本根不用，华叶落去，更为孤妪。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '101011', '设罟捕鱼，反得居诸。负困竭忠，伍氏夷诛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '010100', '敏捷亟疾，如猿集木。彤弓虽调，终不能获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '001010', '冠带南行，与福相期。邀于嘉国，拜位逢时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '100011', '年丰岁熟，政仁民乐，禄入获福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '110001', '筑阙石巅，立基水源。疾病不安，老孤无邻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '011111', '逐狐东山，水遏我前。深不可涉，失利后还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '111110', '麟子凤雏，生长嘉国。和气所居，康乐温仁。邦多圣人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '011000', '西行求玉，莫得卞璞。反得凶恶，使我惊惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '000110', '心狂志悖，听视聋盲。正命无常，下民多孽。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '011010', '南国少子，才略美好。求我长女，贱薄不与。反得丑恶，后乃大悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '010110', '透迤高源，家伯妄施，乱其在官。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '011101', '谢恩拜德，东归吾国，欢乐有福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '101110', '鸡鸣同举，思配无家。执佩持凫，莫使致之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '001001', '凶重忧虑，身受诛罪，神不能解。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '100100', '虎豹熊罴，游戏山谷。仁贤君子，得其所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '001011', '海隅辽右，福禄所至。柔嘉蒙祉，尤夷何咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '001101', '华首之山，仙道所游。利以居止，长无咎忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '101100', '甲乙戊庚，随时转行。不失常节，萌芽律屈。咸达生出，各顺其类。归妹之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '110110', '跂踬未起，失利后市，不得鹿子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '011011', '惟恃自负，不志于下。血从地出，诛罚失理。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '110010', '江河淮海，天之都市。商人受福，国家饶有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '010011', '节情省欲，赋敛有度。家给人足，且贵且富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '110011', '牝马鸣呴，求呼其潦。云雨大会，流成河海。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '001100', '日月之涂，所行必到，无有患故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '010101', '乘风而举，与飞鸟俱。一举千里，见吾爱母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110100', '101010', '阴配阳事，卧木反立。君子攸行，丧其官职。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '001011', '坚冰黄鸟，常悲哀鸣。不见甘粒，但欢藜荆。数惊鸷鸟，为我心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '111111', '荆木冬生，司寇缓刑。威权在下，国乱且倾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '000000', '喘牛伤暑，弗能耕亩。草莱不辟，年岁无有。丙吉问牛喘）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '010001', '鱼欲负流，众不同心，至德潜伏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '100010', '春耕有息，秋入利福。献豜大豭，以乐成功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '010111', '生有圣德，上配太极。皇灵建中，授我以福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '111010', '右抚琴头，左手援带。凶讼不已，相与相戾。失利而归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '000010', '炙鱼拈斗，阴倚硕鼠。舌不思味，讥发为祟。笮不得去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '010000', '申酉说服，牛马休息。君子以安，劳者得欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '110111', '尧门尹爵，圣德增益。使民不疲，安无怵惕。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '111011', '孤公寡妇，独宿悲苦。目张耳鸣，莫与笑语。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '000111', '外得好畜，相与嫁娶。仁贤集聚，咨询厥事。倾夺我城，使家不宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '111000', '煎砂盛暑，鲜有不朽。去河千里，败我利市。老手育马，去之何悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '111101', '甲乙戊庚，随时转行。不失常节，萌芽律屈。咸达出生，各乐其类。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '101111', '依宵夜游，与君相遭。除解烦惑，使心不忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '000100', '天有绝明，巧言为谗。覆白污玉，颜叔哀音。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '001000', '逐利三年，利走如神。展转东西，如鸟避丸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '011001', '堤防坏决，河水泛溢。伤害稼穑，民流去室。君孤独宿，没溺我邑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '100110', '阴阳隔塞，许嫁不答。旄丘新台，悔往叹息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '000011', '伯夷叔齐，贞廉之师。以德防患，忧祸不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '110000', '阳为狂悖，拔剑自伤，为身生殃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '101001', '进士为官，不苦服田，获寿保年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '100101', '耕石不生，弃礼无名。缝衣失针，襦裤弗成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '100000', '灵龟陆处，一旦失所。伊子复耕，桀乱无辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '000001', '室当原口，漂溺为海。财产殚尽，衣食无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '111001', '鸡方啄粟，为狐所逐。走不得食，惶惧喘息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '100111', '家在海隅，绕旋深流。岂敢惮行，无木以趋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '100001', '他山之错，与璆为仇。来攻吾城，伤我肌肤。国家骚忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '011110', '弊镜无光，不见文章。少女不嫁，弃于其公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '010010', '大蛇巨鱼，相辅杀之。君臣隔塞，郭公失庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '101101', '绝世无嗣，福禄不存。精神涣散，离其躬身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '011100', '文君之德，养人致福。年无胎夭，国富民宝。忧者之望，曾参盗息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '001110', '合欢之国，喜为我福。东岳南山，朝济成恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '111100', '忧人之患，履悖易颜。为身祸残，率身自守。与喜相抱，长子成考，封受福佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '001111', '太公避纣，七十隐处。卒逢圣文，为王室辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '101000', '江汉上流，政逆民忧。阴代其阳，雌为雄公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '000101', '缩缩乱丝，举手为灾。越亩逐兔，濡其衣裤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '110101', '臭彘腐木，与狼相辅。亡夫失子，忧及父母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '101011', '刲羊不当，女执空筐。兔跛鹿踦，缘山坠堕。谗乱作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '010100', '拔剑伤手，见敌不喜。良臣无佐，困忧为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '001010', '三羖五羊，相随俱行。迷入空泽，循入直北。经涉六驳，为听伤败。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '100011', '争鸡失羊，亡其金囊。利得不长，陈蔡之患。赖楚以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '110001', '三洒负衡，南取芷香。秋兰芬馥，盈满神匮。利我仲季。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '011111', '孟春己丑，哀呼仲父。明德讫终，乱虐滋起。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '111110', '履不容足，南山多叶。家有芝兰，乃无病疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '011000', '三足无头，弗知所之。心在精伤，莫使为明。不见日光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '000110', '戴尧扶禹，乔松彭祖。西过王母，道路夷易。无敢难者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '011010', '式微式微，忧祸相半。隔以岩山，室家分散。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '010110', '灵龟陆处，一旦失所。伊子复耕，桀乱无辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '011101', '仁德覆洽，恩及异域。泽及殊方，祸灾隐伏。蚕不作室，寒无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '101110', '夏麦，霜击其芒。疾君败国，使年夭伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '001001', '火虽炽，在吾后。寇虽多，在吾右。身安吉，不危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '100100', '辽远绝路，客宿多悔。顽嚚相聚，生我畏恶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '110100', '悬悬南海，去家万里。飞兔褭骏，一日见母，除我忧悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '001101', '因而后通，难厄不穷。终得其愿，姬姜相从。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '101100', '西贾巴蜀，寒雪已没。欲前不得，还反空室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '110110', '作新初陵，烂焰难登。三驹推车，踬损伤颐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '011011', '延颈望酒，不入我口。深目自苦，利得无有。幽人悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '110010', '仲春孟夏，和气所舍。生我喜福，国无残贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '010011', '张网捕鸠，兔离其灾。雌雄俱得，为罝所贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '110011', '三人俱行，一人言北。伯仲欲南，少叔不得。中欲分道，争斗相贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '001100', '然诺不行，欺绐误人。使我露宿，夜归温室。神怒不直，鬼击其目。欲求福利，适反自贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '010101', '陈辞达诚，使安不倾。增禄益寿，以成功名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001011', '101010', '火烧公床，家破灭亡。然得安昌，先忧后丧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001101', '清懦行贾，径陟山阻。与狄为市，不忧危殆。利得十倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '111111', '鼎足承德，嘉谋生福。为王开庭，得心所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '000000', '曳纶江海，钓鲂与鲤。王孙列俎，以飨仲友。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '010001', '东山皋落，叛逆不服。兴师征讨，恭子败覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '100010', '千里骍驹，为王服车。嘉其骊荣，君子有成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '010111', '三龙北行，道逢六狼。莫宿中泽，为祸所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '111010', '天灾所游，凶不可居。转徙获福，留止危忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '000010', '狐狸雉兔，畏人去。分走窜匿，不知所处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '010000', '雨师娶妇，黄岩季子。成礼既婚，相呼南上。膏润下土，年岁大有。损之益，井之坤，恒之晋，本卦之大过）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '110111', '外栖野鼠，与雉为伍。疮痍不息，即去其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '111011', '天命绝后，孤伤无主。彷徨两社，独不得酒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '000111', '鹄思其雄，欲随凤东。顺理羽翼，出次日中。倾流北邑，反复其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '111000', '蜲蛇九子，长尾不殆。均明光泽，燕自受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '111101', '日走月步，趋不同舍。夫妻反目，君主失国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '101111', '定房户室，括薪除毒。文德渊府，害不能贼。一作宜房户室，括卿深毒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '000100', '东齐郭庐，嫁于洛都。骏良美好，多好让主。利得过倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001000', '病笃难医，和不能治。命期终讫，下既蒿里。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '011001', '开郭聚业，王迹所起。姬德七百，振以八子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '100110', '丰年多储，河海饶鱼。商客善贾，大国富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '000011', '鹄求鱼食，过彼食邑。缯加我颈，缴挂羽翼。欲飞不能，为羿所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '110000', '望城抱子，见邑不殆。公孙上堂，文君悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '101001', '左指右麾，邪侈靡靡。执节无良，灵君以亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '100101', '日中为市，各持所有。交易资贿，函珠怀宝。心悦欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '100000', '山没丘浮，陆为水鱼，燕雀无庐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '000001', '马服长股，宜行善市。蒙佑谐偈，获利五倍。一作终日在市，诘朝获利。既享嘉福，得久乃几。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '111001', '三狸捕鼠，遮遏前后。死于国城，不得脱走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '100111', '鬼舞国社，岁乐民喜。臣礼于君，子孝于父。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '100001', '慈母望子，遥思不已。久客外野，我心悲苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '011110', '雨师娶妇，黄岩季子。成礼既婚，相呼南上。膏润下土，年岁大有。损之益，恒之晋，井之坤，本卦之比）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '010010', '两狗围室，相咬争食。枉矢西流，射我暴国。高宗伐鬼，三年乃服。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '101101', '早霜晚雪，伤禾害黍。损功弃力，饥无可食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '011100', '腐臭何在，青蝇集聚。变白为黑，败乱邦国。君为臣逐，失其宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001110', '牵羊不前，与心戾旋。闻言不信，误绐丈人。一云言语不富，误诒丈人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '111100', '甘忍利害，还相克敌。商子酷刑，鞅丧厥身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001111', '刲羊不当，血少无羹。女执空筐，不得桑根。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '101000', '贫鬼相责。无有欢怡，一日九结。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '000101', '两足四翼，飞入嘉国。宁我伯姊，子母相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '110101', '文山紫芝，雍梁朱草。生长和气，王以为宝。公尸侑食，福禄来处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '101011', '绝世游魂，福禄不存。精神涣散，离其躬身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '010100', '北辰紫宫，衣冠立中。含弘建德，常受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001010', '伯蹇叔盲，莫为守株。失我衣裘，代尔阴乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '100011', '两女共室，心不聊食。乱发如蓬，忧常在中。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '110001', '去辛就蓼，毒愈酷甚。避遇坑，忧患日生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '011111', '初病终凶，季为死丧，不见光明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '111110', '三鸟飞来，自到逢时。俱行先至，多得大利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '011000', '鹿食山草，不思邑里，虽久无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '000110', '羊肠九萦，相催并前。止须王孙，乃能上天。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '011010', '管仲遇桓，得其愿欢。胶日杀纠，振冠无忧。笑戏不庄，空言妄行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '010110', '桀跖并处，民困愁苦。旅行迟迟，留连齐鲁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '011101', '魂孤无室，衔损不食。盗张氏馈，见敌失肉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '101110', '谗言乱国，覆是为非。伯奇乖离，恭子忧哀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001001', '卫侯东游，惑于少姬。亡我考妣，久迷不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '100100', '鸡鸣同兴，思配无家。执佩持凫，莫使致之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '110100', '义不胜情，以欲自萦。觊利危躬，催角折颈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001011', '臣尊主卑，权力日衰。侵夺无光，三家逐公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '101100', '叔仲善贾，与喜为市。不忧危殆，利得十倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '110110', '六蛇奔走，俱入茂草。惊于长路，畏惧啄口。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '011011', '水坏我里，东流为海。凫讙嚣，不可安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '110010', '飞不远去，卑厮内侍，禄食未富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '010011', '阴变为阳，女化为男。治道大通，君臣相承。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '110011', '践履危难，脱厄去患。入福喜门，见诲大君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001100', '网密纲缩，动益蹙急，困不得息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '010101', '负牛上山，力劣行难。烈风雨雪，遮遏我前。中道复还，忧者得欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '101010', '喁喁嘉草，思降甘雨。景风升上，沾洽时澍，生我禾稼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '101100', '罗网四张，鸟无所翔。征伐困极，饥渴不食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '111111', '寄生无根，如过浮云。立本不固，斯须落去。更为枯树。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '000000', '人无定法，绶降牛出。蛇雄走趋，阳不制阴。宜其家困。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '010001', '众鸟所翔，中有大怪。九身无头，魂惊魄去。不可以居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '100010', '封涿沟渎，灌溃国邑。人宿口中，民多病疾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '010111', '奋趐鼓翼，翱翔外国。消遥徙倚，来归温室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '111010', '秋蚕不成，冬种不生。设王逆理，弃其宠名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '000010', '卫侯东游，惑于少姬。亡我考妣，久迷不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '010000', '鸟会雀合，与恶相得。鸱鸮相酬，为心所贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '110111', '鸡鸣无距，与雀格斗。趐折目盲，为仇所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '111011', '木生内蠹，上下相贼。祸乱我国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '000111', '延陵适鲁，观乐太史。车邻白颠，知秦兴起。卒兼其国，一统为主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '111000', '辅相之好，无有休息。时行云集，所在遇福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '111101', '床倾箦折，屋漏垣缺，季姬不惬。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '101111', '东入海口，循流北走。一高一下，五邑失主。七夜六日，死于水浦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '000100', '群虎入邑，求索肉食。大人守御，君失其国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '001000', '四乱不安，东西为患。退身山足，无出邦域。乃得完全，赖其生福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '011001', '叔抱冤，祈子自邑。乘遽解患，羊舌以免。赖其生全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '100110', '延颈望酒，不入我口。深目自若，利得无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '000011', '仁政之德，恭一日息。成都就邑，日受厥福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '110000', '牵头系尾，屈折几死。雕世无仁，不知所归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '101001', '教羊逐兔，使鱼捕鼠。任非其人，费日无功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '100101', '生角有尾，张孽制家。排扬逐狐，张氏易公。忧祸重凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '100000', '去安就危，坠陷井池，破我玉螭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '000001', '茹芝饵黄，涂饮玉英。与神通流，长无忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '111001', '体重飞难，未能越关。不离室垣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '100111', '巢成树折，伤我彝器。伯踒叔跌，凶羊乃追。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '100001', '六人俱行，各遗其囊。黄鹄失晓，无以为明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '011110', '播枝迁岐，与母分离，绝不相知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '010010', '迎福开户，喜随我后。曹伯恺悌，为宋国主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '101101', '既痴且狂，两目又盲。箕踞坐喑，名为无用。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '011100', '金梁铁柱，十年牢固。完全不腐，圣人安处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '001110', '裹糗荷粮，与跖相逢。欲飞不得，为网所获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '111100', '彭生为妖，暴龙作灾。盗尧衣裳，聚跖荷兵。青禽照夜，三旦夷亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '001111', '褐夫老妇，不能生子，鳏寡居处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '101000', '鹪鹩窃脂，巢于小枝。摇动不安，为风所吹。内寒飘摇，常忧殆危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '000101', '素车木舆，不任负重。王子出征，忧疑为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '110101', '土陷四维，安平不危。利以居止，保其玉女。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '101011', '负牛上山，力劣行难。烈风雨雪，遮遏我前。中道复还。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '010100', '金城铁郭，上下同力。政平民亲，寇不敢贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '001010', '清洁渊塞，为谗所言。证训诘情，系于枳温。甘棠听断，昭然蒙恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '100011', '皋陶听理，岐伯悦喜。西登华道，东归无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '110001', '低头窃视，有所畏避。行作不利，酒酸鱼败。众莫贪嗜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '011111', '十雉百雏，常与母俱。抱鸡搏虎，谁肯为娱。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '111110', '高阜山陵，峻颠崩。为国妖祥，元后以薨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '011000', '六鹢退飞，为襄败祥。陈师合战，左股疾伤。遂以崩薨，霸功不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '000110', '异国殊俗，情不相得。金木为仇，酋贼擅役。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '011010', '鸦噪庭中，以戒灾凶。重门击柝，侪忧暴客。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '010110', '慈母赤子，享赐得士。获夷服除，以安王家。侧陋逢时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '011101', '迹造恶人，使得不通。炎旱为殃，年谷大伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '101110', '躬履孔德，以带束带。文王燎猎，吕尚获福。号称太师，封建齐国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '001001', '征将止恶，鼓鞞除贼。庆仲奔莒，子般获福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '100100', '良夫淑女，配合相保。多孙寿子，欢乐长久。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '110100', '逶迤四牡，思念父母。王事靡盬，不得安处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '001011', '水坏我里，东流为海。龟鼍讙嚣，不得安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '001101', '束帛戋戋，赙我盂空。征召送君，处号易子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '110110', '乾行大德，履赡六合。呕喣成熟，使我福德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '011011', '秦并六国，更相克贼。获惠质圉，郑被其咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '110010', '晦昧昏冥，君无纪纲。甲子成乱，简公丧亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '010011', '三足无头，弗知所之。心狂精伤，莫使为明。不见日光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '110011', '长夜短日，阴为阳贼。万物空枯，藏于北陆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '001100', '依宵夜游，与君相遭。除烦解惑，使我无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '010101', '逐鹿南山，知我入门。阴阳和调，国无灾残。长子出逃，须其仁君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101100', '101010', '请骋作耳，啬不我与，驱我父母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '110110', '温山松柏，常茂不落。鸾凤以芘，得其欢乐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '111111', '采唐沬乡，要我桑中。失信不会，忧思钩带。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '000000', '有鸟飞来，集于宫树。鸣声畏恶，主将出去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '010001', '仁政之德，参参日息。成都就邑，日受厥福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '100010', '他山之错，与璆为仇。夹攻吾城，伤我肌肤。邦家搔扰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '010111', '赍贝赎狸，不听我辞。系于虎须，牵不得来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '111010', '一簧两舌，言谄语。三奸成虎，曾母投杼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '000010', '薄行搔尾，逐云涂水。污泥为陆，下田宜稷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '010000', '天门九重，泽内难通。明登到暮，不见神公。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '110111', '闇昧不明，耳聋不聪。陷入深渊，灭顶成凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '111011', '雾露早霜，日暗不明。阴阳孽疾，年谷大伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '000111', '三阶土廓，德义明堂。交让往来，享燕相承。箕伯朝王，锡我元黄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '111000', '争鸡失羊，利得不长。陈蔡之患，赖楚以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '111101', '天旱水涸，枯槁无泽，未有所获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '101111', '陶朱白圭，善贾息赀。公子王孙，富利不贫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '000100', '龟厌江海，陆行不止。自令枯槁，失其都市。忧悔无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '001000', '黄鸟采蓄，既嫁不答。念吾父兄，思复邦国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '011001', '田鼠野雏，意常欲逃。拘制笼槛，不得动摇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '100110', '平国不君，夏氏作乱。乌号窃发，灵公殒命。既济之噬，嗑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '000011', '巨蛇大，战于国郊。上下闭塞，君遁走逃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '110000', '谗言乱国，覆是为非。伯奇流离，恭子忧哀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '101001', '郁怏不明，为阴所伤。众雾集聚，共夺日光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '100101', '望城抱子，见邑不殆。公孙上堂，大君欢喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '100000', '三虫为蛊，划迹无与。胜母盗泉，君子弗处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '000001', '车驰人趋，卷甲相求。齐鲁寇战，败于犬丘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '111001', '欲访子车，善相欺绐。桓叔相迎，不见所期。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '100111', '争雉失羊，亡其金囊。利得不长，陈蔡之患。赖楚以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '100001', '岁莫花落，阳入阴室。万物伏匿，利不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '011110', '晨风文翰，大举就温。过我成邑，羿无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '010010', '持鹄抱子，见蛇何咎。室家俱在，不失其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '101101', '隐隐大雷，霈为雨。有女痴狂，惊骇邻里。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '011100', '无足断跟，居处不安，凶恶为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '001110', '破筐敝筥，弃捐于道，不复为宝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '111100', '三鸡啄粟，十雏从食。饥鸢卒击，凶其两叔。中孚之颐作八雏从食）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '001111', '乘车七百，以明文德。践土葵丘，齐晋受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '101000', '百足俱行，相辅为强。三圣翼事，王室宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '000101', '典策法书，藏在兰台。虽遭溃乱，独不遇灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '110101', '西诛不服，恃强负力。倍道奔敌，师徒败覆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '101011', '春阳生草，夏长条肄。万物蕃滋，充实益有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '010100', '磝硗秃白，不生黍稷。无以供祭，祗灵代祀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '001010', '褰衣涉河，涧流浚多。幸赖舟子，济脱无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '100011', '宜行贾市，所求必倍。载喜抱子，与利为友。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '110001', '兄征东燕，弟伐辽西。大克胜还，封君河间。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '011111', '初虽惊惶，后乃无伤。受其福庆，相孝为王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '111110', '随风乘龙，与利相逢。田获三倍，商旅有功。憧憧之邑，长安无他。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '011000', '鱼扰水浊，寇围吾邑。城危不安，惊恐狂惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '000110', '虽塞复通，履危不凶。保其明功，以道立宗。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '011010', '坤厚地德，庶物蕃植。平康正直，以绥大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '010110', '山木暴怒，坏梁折柱。稽难行旅，留连愁苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '011101', '使燕筑室，身不庇宿。家无聊赖，织我衣服。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '101110', '矢石所射，襄公据。吴子巢门，伤病不治。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '001001', '日月运行，一寒一暑。荣宠赫赫，不可得保。颠陨坠堕，更为士伍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '100100', '宫门悲鸣，臣围其君，不得东西。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '110100', '戴盆望天，不见星辰。顾小失大，福逃墙外。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '001011', '天之所明，祸不遇家。反目相逐，终得和美。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '001101', '天阴霖雨，涂行泥潦。商人休止，市无所有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '101100', '善门福喜，增累盛炽。日就有得，宜其家国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '011011', '南山之阳，华叶将将。嘉乐君子，为国宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '110010', '昼龙头颈，文章未成。甘言美语，诡辞无名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '010011', '婴儿孩子，未有知识。彼童而角，乱我政事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '110011', '阴作大奸，欲君勿言。鸿鹄利口，发其祸乱。荆季怀忧，张伯被患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '001100', '德之流行，利之四乡。雨师洒道，风伯逐殃。巡狩封禅，以告成功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '010101', '禹将为君，装入昆仑。稍进阳光，登见温汤。功德昭明。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '101010', '五岳四渎，含润为德。行不失理，民赖恩福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '011011', '班马还师，以息劳疲。役夫嘉言，入户见妻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '111111', '践履危难，脱去厄患。入福嘉门，见诲大君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '000000', '子鉏执麟，春秋作经。元圣将终，尼父悲心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '010001', '夹河为婚，期至无船。淫心失望，不见所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '100010', '天孙帝子，与日月处。光荣于世，福禄繁祉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '010111', '三年争妻，相随奔驰。终日不食，精气劳疲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '111010', '禹召诸神，会稽南山。执玉万国，天下安宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '000010', '早霜晚雪，伤害禾麦。损功弃力，饥无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '010000', '嵩融持戟，杜伯荷弩。降观下国，诛逐无道。忧商之季，失福逃走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '110111', '生有圣德，上配太极。皇灵建中，受我以福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '111011', '下田陆黍，万华生齿。大雨霖集，波病渍腐。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '000111', '子畏于匡，困厄陈蔡。明德不危，竟克免害。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '111000', '有两赤头，从五岳游。淫言无佑，趍尔之林。俯伏听命，不敢动摇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '111101', '当得自知，不逢凶灾。衰来复兴，终得福来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '101111', '朽根枯树，华叶落去。卒降火焱，随风僵仆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '000100', '葛生衍蔓，絺绤为愿。家道笃厚，父兄悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '001000', '东行求玉，反得弊石。名曰无直，字曰丑恶。众所贱薄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '011001', '瞻白用弦，驽孱恐怯。任力随身，如猬见鹊。偃视怒肠，不敢拒格。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '100110', '疮痍多病，宋公危殆。吴子巢门，无命失所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '000011', '东山西岳，会合俱食。为吴从送，以成恩福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '110000', '舞非其处，失节多悔，不合我意。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '101001', '南循汝水，伐树斩枝。过时不遇，惄如周饥。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '100101', '公孙驾骊，载游东齐。延陵说产，遗季纻衣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '100000', '乘舆八百，以明文德。践土葵丘，齐鲁受福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '000001', '雄处弱水，雌在海边。别离将食，哀悲于心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '111001', '结网得鲜，受福安坐，终无患祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '100111', '秋南春北，随时休息。处和履中，无有忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '100001', '启户闭门，巡狩释冤。夏台羑里，汤文喜悦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '011110', '符左契右，相与合属。乾坤利贞，乳生六子。长大成就，夙言如母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '010010', '饥蚕作室，丝多乱绪，端不可得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '101101', '东壁余光，数暗不明。主母嫉妒，乱我事业。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '011100', '白茅漉酒，灵巫拜祷。神嗜饮食，使君寿考。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '001110', '范公陶朱，巧贾货资。东之营丘，易字子皮。抱珠载金，多得利归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '111100', '三羖五牂，相随俱行。迷入空泽，经涉虎庐。循谷直北，经涉六驳。为所伤贼，死于牙腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '001111', '雄鹄延颈，欲飞入关。雨师洒道，我袍裘。车重难前，侍者稽首。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '101000', '中年蒙庆，今岁受福，必有所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '000101', '禄如周公，建国洛东，父子俱封。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '110101', '安床厚褥，不得久宿。弃我嘉燕，困于东国。投杼之忧，不成祸灾。家人之睽，艮之筛）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '101011', '蓄积有余，粪土不居，利有所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '010100', '心愿所喜，乃今逢时。我得利福，不离兵革。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '001010', '目不可合，忧来搔足。怵惕危惧，去其邦族。萃之睽明夷）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '100011', '福德之士，欢悦日喜。夷吾相桓，三归为臣。赏流子孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '110001', '忧姬附耳，心听悦喜，利后搏取。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '011111', '叔迎兄弟，遇巷在阳。君子季姬，并坐鼓簧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '111110', '徙巢去家，南遇白鸟。东西受福，与喜相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '011000', '舜登大禹，石夷之野。征诣王庭，拜治水土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '000110', '江河淮海，天之都市。商人受福，国家富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '011010', '隐隐烦烦，火烧山根。下润我邻，独不蒙恩。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '010110', '闇昧不明，耳聋不聪。陷入深渊，灭顶忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '011101', '鸟鸣喈喈，天火将下。燔我馆舍，灾及妃后。中孚）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '101110', '十雉百雏，常与母俱。抱虎搏鸡，谁敢难者。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '001001', '营城洛邑，周公所作。世建三十，年历八百。福佑盘结，坚固不落。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '100100', '三人俱行，别离将食。一身五心，反复迷惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '110100', '三虎搏狼，力不相当。如鹰格雉，一击破亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '001011', '养虎畜狼，还自贼伤。年岁息长，疾君拜祷。虽危不凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '001101', '后时失利，不得所欲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '101100', '雉兔之东，以野为场。见鹰奔走，死于谷口。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '110110', '秋蛇见穴，不失其节。夫人姜氏，自齐复入。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '110010', '鸟鸣巢端，一呼三颠。摇动东西，危嵬不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '010011', '命夭不遂，死多为祟。妻子啼喑，早失其雄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '110011', '茆屋结席，祟我文德。三辰旗，家受其福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '001100', '罗网一张，鸟无一翔。征伐困极，饥穷不食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '010101', '天成地安，积石为山。润给万里，人赖其欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '101010', '铜人铁柱，暴露劳苦。终月卒岁，无有休止。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '110010', '望幸不到，文章未就。三子逐兔，犬踦不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '111111', '焱风阻越，车驰竭竭。弃名追亡，失其和节。忧心惙惙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '000000', '蛇得泽草，不忧危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '010001', '两犬争斗，股疮无处。不成仇雠，行解却去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '100010', '因祸受福，喜盈其室，求事皆得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '010111', '江有宝珠，海多大鱼。亟行疾去，可以得财。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '111010', '三年生狗，以戌为母。荆夷上侵，伯姬出走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '000010', '安息康居，异国穷庐。非吾习俗，使伯忧惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '010000', '行触天网，马死车伤。身无聊赖，困穷乏粮。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '110111', '裸裎逐狐，为人观笑。牝鸡司晨，主母乱门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '111011', '为季求妇，家在东海。水长无船，不见所欢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '000111', '男女合室，二姓同食。婚姻孔云，宜我多孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '111000', '天门帝室，黄帝所直。藩屏周卫，不可得入。常安长在，终无祸患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '111101', '金观市，欲置骝子。猾窃发，盗我黄宝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '101111', '三思俱行，欲归故乡。望邑入门，拜见家亲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '000100', '娶于姜女，驾迎新妇。少妻在门，夫子悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '001000', '伯仲旅行，南求大牂。孟长痛足，倩季负囊。柳下之贞，不失我邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '011001', '洁身白齿，衰老复起。多孙众子，宜利姑舅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '100110', '独宿深夜，嫫母畏昼。平王逐建，荆子忧惧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '000011', '追亡逐北，呼还幼叔。至山而得，复归其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '110000', '鸟飞无翼，兔走折足。虽欲会同，未见其功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '101001', '抱空握虚，鸮惊我雏，利出不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '100101', '山作大池，陆地为海，各得其所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '100000', '为虎所啮，太山之阳。众多从者，莫敢救藏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '000001', '逶迤四牡，思归念母。王事靡盬，不得安处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '111001', '狝猴所言，语无成全。误我白马，使口不至。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '100111', '飞不远去，卑厮内侍，禄养未富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '100001', '大尾细腰，重不可摇。阴权制国，平子逐昭。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '011110', '', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '010010', '子畏于匡，困于陈蔡。明德不危，竟免厄害。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '101101', '畏昏潜处，候时昭朗。卒逢白日，为世荣主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '011100', '白鸟御饵，鸣呼其子。旋枝张趐，来从其母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '001110', '宫商角征，五音和气。君臣父子，弟顺有序。唐虞袭德，国无灾咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '111100', '季姬踟蹰，望子城隅。终日至暮，不见齐侯。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '001111', '鬼哭于社，悲伤无后。甲子昧爽，殷人绝祀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '101000', '天之所予，福禄常在，不忧危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '000101', '比目附翼，相待为福。姜氏季女，与君合德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '110101', '翕翕，稍崩坠颠。灭其令名，长没不全。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '101011', '折芒蔽目，不见雉叔。三足飞鸟，远去家室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '010100', '羊肠九萦，相催稍前。止须王孙，乃能上天。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '001010', '坤厚地德，庶物蕃息。平康正直，以绥大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '100011', '有莘外野，不逢尧主。复归穷处，心劳志苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '110001', '咠长景行，来观柘桑。止伯自喜，都叔允藏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '011111', '周师伐纣，战于牧野。甲子平旦，天下喜悦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '111110', '踰江求橘，并得大栗。烹羊食豕，饮食歌笑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '011000', '敝笱在梁，鲂逸不禁。渔夫劳苦，口燋喉乾。虚空无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '000110', '生有阴孽，制家非阳。遂受还作，张氏易休。忧祸重凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '011010', '绝域异路，多有怪恶。使我惊惧，思我故处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '010110', '迷行失道，不得马牛。伯贾亡，市没无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '011101', '雌鸑生鵰，神异兴起。乘云龙腾，民戴为父。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '101110', '迭迭累累，如岐之室。畜一息十，古公治邑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '001001', '疮疡疥瘙，孝妇不省。君多疣赘，四时作灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '100100', '羊头兔足，羸瘦少肉。漏囊败粟，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '110100', '孽蔑徙靡，空无谁是。言季不明，乐减少解。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '001011', '妹貌亲熟，败君正色。作事不成，自为心贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '001101', '四马共辕，东上太山。骍骊同力，无有重艰。与君笑言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '101100', '阴变为阳，女化为男。治道得通，君臣相卫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '110110', '南国少子，才略美好。求我长女，贱薄不与。反得丑恶，后乃大悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '011011', '昭公失常，季女悖狂。逊齐处野，丧其宠光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '010011', '文山紫芝，雍梁朱草。生长和气，王以为宝。公尸侑食，福禄来处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '110011', '牵羊不前，与心戾旋。闻言不信，误绐丈人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '001100', '东山西山，各自止安。心虽相望，竟不同堂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '010101', '鹿求其子，虎庐之里。唐伯李耳，贪不我许。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110010', '101010', '三虎上山，更相咆哮。心志不亲，如仇与怨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '010011', '海为水王，聪圣且明。百流归德，无有叛逆。常饶优足，不利攻玉。所求弗得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '111111', '虎豹怒咆，慎戒外忧。上下俱搔，士民无聊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '000000', '探巢得雏，鸠鹊俱来，使我心忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '010001', '日望一食，常恐不足，禄命寡薄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '100010', '良马疾走，千里一宿。离逃它乡，谁能追复。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '010111', '鹊巢鸠城，上下不亲。内外乖畔，子走失顾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '111010', '云龙集会，征讨西戎。招边定众，谁敢当锋。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '000010', '春多膏泽，夏润优渥。稼穑成熟，亩获百斛。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '010000', '僮妾独宿，长女未室。利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '110111', '四野不安，东西为患。退身止足，无出邦域。乃得全完，赖其生福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '111011', '长宁履福，安我百国。嘉宾上堂，与季同床。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '000111', '骐骥绿耳，章明造父。伯夙奏献，衰续厥绪。佐文成霸，为晋元辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '111000', '张陈嘉谋，赞成汉都。主欢民喜，其乐休休。张良，陈平也）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '111101', '大面长头，来解君忧。遗吾福善，与我嘉惠。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '101111', '畏昏不行，待旦昭明。燎猎受福，老赖其庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '000100', '伯去我东，首发如蓬。长夜不寐，辗转空床。内怀惆怅，忧摧肝肠。垢之遯）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '001000', '朽条腐索，不堪施用。安静候时，以待亲知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '011001', '比目四翼，相倚为福。姜氏季女，与君合德。焕之明夷）。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '100110', '履阶升墀，高登崔嵬。福禄洋溢，依天之威。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '000011', '奢淫吝啬，神所不福。灵祗凭怒，鬼瞰其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '110000', '大步上车，南到喜家。送我狐裘，与福载来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '101001', '东行西步，失次后舍。乾侯野井，昭王失居与彼。作期，不觉至夜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '100101', '喜乐踊跃，来迎欢客。鹊巢百两，以成嘉福多获。利益。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '100000', '非理所求，谁肯相与。往来不获，徒劳道路。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '000001', '北虏匈奴，数侵边境。左衽为长，国犹未庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '111001', '续事康域，针折不成。婴儿短舌，说辞无名。一作征不以理，辞乃无名。纵获臣子，伯功不成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '100111', '景星明堂，麟游凤翔。仁施大行，颂声作兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '100001', '文明之世，销锋铸耜。以道顺昌，百王不易。一作焚膏销锋，镇压危凶。招来文德，君安其国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '011110', '鸟飞无羽，鸡斗折距。徒自长嗟，谁肯为侣。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '010010', '群队虎狼，囓彼牛羊。道路不通，妨农害商。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '101101', '商伯沉醉，庶兄奔走。淫女荡夫，仁德并孤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '011100', '三狸搏鼠，遮遏前后。当此之时，不能脱走。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '001110', '陶叔孔圉，不处乱国。初虽未萌，后受福庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '111100', '奋翅鼓翼，翱翔外国。逍遥北域，不入温室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '001111', '德音孔博，升在王室。八极蒙佑，受其福禄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '101000', '当变立权，擿解患难。涣然冰释，大国以安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '000101', '羽动角甘，雨续草木，茂年岁熟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '110101', '天所佑助，福来祸去，君王何忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '101011', '方啄广口，圣智仁厚。释解倒悬，唐国大安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '010100', '葛藟蒙棘，华不得实。谗乱政，使恩壅塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '001010', '皇母多恩，字养孝孙。脱于襁褓，成就为君。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '100011', '积水下湿，北陆苦寒。露宿多风，君子伤心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '110001', '伯夷叔齐，贞廉之师。以德防患，忧祸不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '011111', '一雌二雄，子不得公。乱我族类，使吾心愦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '111110', '主安多福，天禄所伏。居之宠昌，君子有光。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '011000', '千载槐根，身多斧瘢。树维枯屈，枝叶不出。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '000110', '周师伐纣，胜殷牧野。甲子平旦，天下大喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '011010', '日走月步，趍不同舍。夫妻反目，主君失位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '010110', '宣劳就力，为王主国。安土成稷，天下蒙福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '011101', '讽德诵功，美周盛隆。奭旦辅成，光济冲人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '101110', '三夜不寝，忧来益甚。戒以危惧，弃其安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '001001', '思愿所之，乃今逢时。洗濯故忧，并其所来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '100100', '噂噂慑慑，夜行昼伏。谋议我资，来攻吾室。空尽己财，几无所食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '110100', '骍牛亡子，鸣于大野。申后阴征，还归其母。说我除悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '001011', '王良善御，伯乐知马。周旋步骤，行中规矩。止息有节，延命寿考。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '001101', '释然远咎，避患革害。田获三狐，以贝为宝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '101100', '仁兽所处，国无凶咎。市贾十倍，复归惠里。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '110110', '六目俱视，各欲有志。一言不同，乖戾生讼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '011011', '傅说休明，骖御四龙。周径万里，无有危凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '110010', '伯仲叔季，日暮寝寐。醉醒失明，丧其贝囊。卧拜道旁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '110011', '江有宝珠，海多大鱼。亟行疾至，可以得财。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '001100', '远视千里，不见所视。离娄之明，无益于耳。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '010101', '弱足刖跟，不利出门。市贾无赢，折亡为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010011', '101010', '利尽得媒，时不我来。鸣雌深步，寡宿独居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '110011', '鸟鸣喈喈，天火将下。燔我屋室，灾及妃后。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '111111', '黄虹之野，贤君所在。管仲为相，国无灾咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '000000', '叔梁有名，相与合齿。乾坤利贞，乳生六子。长大成就，风言如母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '010001', '蝗囓我稻，驱不可去。实穗无有，但见空槁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '100010', '婴孩求乳，母归其子，黄麑悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '010111', '折箬蔽目，不见稚叔。失旅亡民，远去家室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '111010', '牂羊羵首，君子不饱。年饥孔荒，士民危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '000010', '灵龟陆处，盘桓失所。伊子退耕，桀乱无辅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '010000', '威约拘囚，为人所诬。皋陶平理，几得脱免。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '110111', '乌升鹊举，照临东海。龙降庭坚，为陶叔后。封于蓼丘，福履绥厚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '111011', '四目相视，稍延同埶。日映之后，见吾伯姊。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '000111', '大步上车，南至喜家。送我狐裘，与福载来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '111000', '穿都相合，未敢面见。媒妁无良，使我不乡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '111101', '鸿飞遵陆，公母不复，伯氏客宿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '101111', '代戍失期，患至无聊。惧以发难，为我开基，邦国忧愁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '000100', '伯氏争言，战于龙门。构怨结祸，三世不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '001000', '周政养贼，背生人足。陆行不安，国危为患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '011001', '蜩螗欢喜，草木嘉茂。百果蕃生，日增富有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '100110', '薄灾暴虎，风吹云却。欲上不得，复归其宅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '000011', '乘骝驾骊，游至东齐。遭遇行旅，送我以货，厚得利归。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '110000', '凤生十子，同巢共乳，欢悦相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '101001', '桃雀窃脂，巢于小枝。动摇不安，为风所吹。心寒栗摇，常忧殆危。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '100101', '东山西山，各自止安。虽相登望，不得同堂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '100000', '匍匐出走，惊惧皇恐。白虎生孙，蓐收在后。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '000001', '重弋射隼，不知所定。质疑蓍龟，告以肥牡。明神答报，宜利止居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '111001', '开门内福，喜至我侧。加以善祥，为吾家宅。宫城洛邑，以昭文德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '100111', '乌飞狐鸣，国乱不宁。下强上弱，为阴所刑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '100001', '三鸡啄粟，八雏从食。饥鹰卒击，失亡两叔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '011110', '叹息不悦，忧逆中出。丧我金罂，无妄失位。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '010010', '刚柔相呼，二姓为家。霜降既同，惠我以仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '101101', '送我季女，至于荡道。齐子旦夕，留连久处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '011100', '低头窃视，有所畏避。行作不利，酒酸鱼败，众莫贪嗜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '001110', '典策法书，藏在兰台。虽遭乱溃，独不遇灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '111100', '旦醉病酒，暮即瘳愈，独不及咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '001111', '画龙头颈，文章不成。甘言美语，说辞不名。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '101000', '日月运行，一寒一暑。荣光赫赫，不可得保。颠踬殒坠，更为士伍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '000101', '争利王市，朝多君子。苏氏六国，获其荣宠。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '110101', '六蛇奔走，俱入茂草。惊于长涂，畏惧啄口。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '101011', '悬素餐，食非其任。失舆剥庐，休坐徙居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '010100', '欢欣九子，俱见大喜。携提福至，王孙是富。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '001010', '伯夷叔齐，贞廉之师。以德防患，忧祸不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '100011', '雄圣伏名，人匿麟惊。走凤飞北，乱溃未息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '110001', '久鳏无偶，思配织女。求其非望，自令寡处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '011111', '破亡之国，天所不福，难以止息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '111110', '老慵多欲，弊政为贼。阿房骊山，子婴失国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '011000', '三羖六牂，相随俱行。迷入空泽，经涉虎庐。为所伤贼，死于牙腹。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '000110', '噬嗫嚾，昧冥相搏。多言少实，语无成事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '011010', '舞阳渐离，击筑善歌。慕丹之义，为燕荆轲。阴谋不遂，霍目死亡，功名何施。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '010110', '尹氏伯奇，父子分离。无罪被辜，长舌为灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '011101', '五精乱行，政逆皇恩。汤武赫怒，天伐利域。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '101110', '西历玉山，东入玉门。登上福堂，饮万岁浆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '001001', '行触忌讳，与司命忤。执囚束缚，拘制于吏，迷人有喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '100100', '机父不贤，朝多谗臣。君失其政，保我久贫。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '110100', '三人俱行，北求大牂。孟长病足，倩季负囊。柳下之贞，不失我邦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '001011', '鹄思其雄，欲随凤东。顺理羽翼，出次日中。虽留比邑，复归其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '001101', '常德自如，不逢祸灾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '101100', '白鹄游望，君子以宁。履德不愆，福禄来成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '110110', '肤敏之德，发愤忘食。虏豹擒越，为王得福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '011011', '百足俱行，相辅为强。三圣翼事，王室宠光，国富民康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '110010', '生不逢时，困且多忧。年老衰极，中心悲愁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '010011', '出门蹉跌，看道后旅。买羊逸亡，所谓走。空手握拳，坐狼为咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '001100', '牧羊稻田，闻虎喧讙。畏惧惕息，终无祸患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '010101', '龙潜凤池，箕子变服，阴孽萌作。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110011', '101010', '国无比邻，相与争强。纷纷凶凶，天下扰攘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '001100', '初虽惊惶，后乃无伤。受其福庆，永永其祥。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '111111', '积德累仁，灵佑顺信。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '000000', '谨慎重言，不幸遭患。周召述职，脱免牢门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '010001', '鸟飞鼓翼，喜乐尧德。虞夏着功，要荒宾服。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '100010', '牙生齿，室堂启户。幽人利贞，鼓翼起舞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '010111', '使伯东求，拒不肯行。与叔争讼，更相伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '111010', '手足易处，头尾颠倒。公为雌妪，乱其蚕织。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '000010', '匠卿操斧，豫章危殆。袍衣既剥，禄命讫已。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '010000', '天女踞床，不成文章。南箕无舌，饭多砂糠。虐众盗名，雌雄折颈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '110111', '大椎破毂，长舌乱国。床笫之言，三世不安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '111011', '衔命辱使，不堪厥事。中坠落去，更为负载。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '000111', '三蛇共室，同类相得。甘露时降，生我百谷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '111000', '衣绣夜游，与君相逢。除患解惑，使君不忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '111101', '被发兽心，难与为邻。来如风雨，去如绝弦，为狼所残。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '101111', '刚柔相呼，二姓为家。霜降既同，惠我以仁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '000100', '牛耳聋瞶，不晓声味。委以鼎俎，治乱溃溃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '001000', '低头窃视，有所畏避。行旅不利，酒酸鱼馁，众莫贪嗜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '011001', '雨师娶妇，黄岩季子。成礼既婚，相呼南上。膏我下土，年岁大有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '100110', '戴盆望天，不见星辰。顾小失大，遁墙外。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '000011', '二人辇车，徙去其家。井沸釜鸣，不可以居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '110000', '攘臂反肘，怒不可止。狼戾腹心，无与为市。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '101001', '汤火之忧，转解喜来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '100101', '忠信辅成，王政不倾。公刘肇基，文武绥之。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '100000', '登高折木，顿踬蹈险。车倾马疲，叔伯嗟嘘。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '000001', '桑方陨落，黄叶败散。失势倾侧，如无所立。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '111001', '鸾凤翱翔，集于家国。念我伯姊，与母相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '100111', '阴淫所居，盈溢过度，伤害禾稼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '100001', '霄冥高山，道险峻难。王孙罢极，困于阪间。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '011110', '和璧隋珠，为火所烧。冥昧失明，夺精无光，弃于道傍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '010010', '虞君好田，惠我老亲。恭承宗庙，长愠不去，复我内事。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '101101', '爪牙之士，怨毒祈父。转忧与己，伤不及母。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '011100', '仓盈庾亿，宜稼黍稷，年岁有息。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '001110', '窗牖户傍，通利明光。贤智辅圣，仁德大行。家给人足，海内殷昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '111100', '忉忉之患，凶重与荐，为虎所吞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '001111', '水无鱼滋，陆为海涯。君子失居，小人相携。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '101000', '九疑郁林，沮湿不中。鸾凤所恶，君子攸去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '000101', '六翮泛飞，走归不及。脱归王室，上其骍特。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '110101', '不直庄公，与我争讼。媒伯无礼，自令壅塞。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '101011', '仓庚多亿，宋公危殆。吴子巢门，殒命失所。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '010100', '失羊捕牛，无损无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '001010', '夏麦麸，霜击其芒。疾君败国，使我诛伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '100011', '昧昧暗暗，不知白黑。风雨乱扰，光明伏匿，幽王失国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '110001', '执斧破薪，使媒求妇。和合二姓，亲御饮酒。色比毛嫱，姑公悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '011111', '六疾生狂，痴走妄行。北入患门，与祸为邻。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '111110', '驱羊就群，狼不肯前。庆季愎谏，子之被患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '011000', '二人异路，东趍西步。十里之外，不知相处。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '000110', '义不胜情，以欲自营。睹利为躬，折角摧颈。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '011010', '骚骚扰扰，不安其类。疾在颈项，凶危为忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '010110', '三河俱合，水怒涌跃。坏我王室，民困于食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '011101', '阳曜旱疾，伤病稼穑，农人无食。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '101110', '流浮出食，载豢入屋。释辔系马，西南庑下。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '001001', '门户之居，可以止舍。进士不殆，安乐相保。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '100100', '过时不归，雌雄苦悲。徘徊外国，与母分离。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '110100', '中田有庐，疆埸有瓜。献进皇祖，曾孙寿考。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '001011', '失时无友，覆家出走，何如丧狗。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '001101', '反鼻岐头，三寡独居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '101100', '衣裳颠倒，为王来呼。成就东周，封受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '110110', '飞不远去，还归故处，兴事多悔。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '011011', '含血走禽，不晓五音。匏巴鼓瑟，不悦于心。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '110010', '求玉获石，非心所欲，祝愿不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '010011', '山崩谷绝，大福尽歇。泾渭失纪，玉石既已。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '110011', '杂目惧怒，不安其居。散漫府藏，无有利得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '010101', '众邪充侧，凤凰折翼。微子复北，去其邦国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001100', '101010', '六月采芑，征伐无道。张仲季叔，孝友饮酒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '010101', '元兔捐掌，与足相视。证讯诘问，诖情自侣。死诬难告，口为身祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '111111', '游驹石门，騄耳安全。受福西邻，归隐玉泉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '000000', '阳春草生，万物风兴。君子所居，祸灾不到。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '010001', '人无足法，绂除牛出。雄走羊惊，不失其家。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '100010', '太山上奔，变见太傲。陈吾废忽，作为祸患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '010111', '乘龙光土，先暗后明。燎猎大得，太师以昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '111010', '羊头兔足，羸瘦少肉。漏囊贮粟，利无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '000010', '因祸受福，喜盈其室。螟虫不作，君无苛惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '010000', '舜升大禹，石夷之野。征诣黄门，拜治水土。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '110111', '乌子鹊雏，常与母居。顾类群聚，不离其巢。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '111011', '夷羿所射，发辄有获。增加仓鹰，双鸟俱得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '000111', '晨风文翰，火举就温。昧过我邑，羿无所得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '111000', '六喜三福，南至欢国。与喜同乐，嘉我洁德。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '111101', '斗龙股折，日就遂明。自外为主，弟伐其兄。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '101111', '蒙庆受福，有所获得，不利出域。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '000100', '蛮夷戎狄，太阴所积。涸水冱寒，君子不存。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '001000', '畏昏潜处，候时昭明。卒遭白日，为荣禄主。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '011001', '水流趍下，欲至东海。求我所有，买鲔与鲤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '100110', '冠带南行，与福喜期。徼为嘉国，释为逢时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '000011', '莎鸡振羽，为季门户。新沐弹冠，仲父悦喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '110000', '结衿流溺，遭谗桎梏。周召述职，身受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '101001', '田鼠野鸡，意常欲。拘制笼槛，不得动摇。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '100101', '居华山巅，游观浮云。有雨不濡，心乐无忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '100000', '倾倚将颠，乱不能存。英雄作业，家困无年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '000001', '心愿所喜，乃今逢时。保我利福，不离兵革。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '111001', '灵龟陆处，盘桓失所。阿衡退耕，夏封于国。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '100111', '弱水之右，有西王母。生不知老，与天相保。不利行旅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '100001', '抱瑰求金，日暮坐吟。终身卒岁，竟无成功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '011110', '言笑未毕，忧来暴卒。身加槛缆，囚系缚束。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '010010', '望幸不至，文章未成。王子逐兔，犬踦不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '101101', '震悚恐惧，多所畏忌。行道留难，不可以步。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '011100', '雄狐绥绥，登山崔嵬。昭告显功，大福允兴。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '001110', '火起吾后，喜炙我庑。仓龙含水，深潠吾柱，虽忧无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '111100', '危坐至暮，请求不得。膏泽不降，政戾民忒。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '001111', '孟春和气，鹰隼搏鸷，众雀忧溃。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '101000', '缓法长奸，不能理冤。沉湎失节，君受其患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '000101', '鱼鳖贪饵，死于网钓。受危因宠，为身殃咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '110101', '金精耀怒，带剑过午。徘徊高原，宿于山谷。两虎相距，弓矢满野。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '101011', '四目相望，精近同光，并坐鼓簧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '010100', '茹芝饵黄，饮酒玉浆。与神流通，长无忧凶。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '001010', '求獐嘉乡，恶蛇不行。豳岐口还，复反其床。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '100011', '天门地户，幽冥不观，不知所在。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '110001', '跛足息肩，有所忌难。金城铁郭，以铜为关。藩屏息卫，安止无患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '011111', '三雁俱飞，欲归稻池。经涉山泽，为矢所射。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '111110', '济深难渡，濡我衣裤。王子善濯，决无他故。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '011000', '饮酒醉饱，跳趋争斗。伯伤叔僵，东家治丧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '000110', '跛踬未起，失利后市。蒙被殃咎，不得鹿子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '011010', '辰次降娄，建星中坚。子无远行，外颠霄陷，遂合讫终。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '010110', '商风召寇，来呼外盗。间谍内应，与我争斗。殚己宝藏，主人不胜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '011101', '甘露醴泉，太平机关。仁德感应，岁乐民安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '101110', '蔡仲子突，要门逐急。祸起子伤，弟伐其兄，郑文不昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '001001', '反孽难步，留不及舍。露宿泽陂，亡其襦裤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '100100', '狼虎结谋，相聚为保。伺候牛羊，病我商人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '110100', '明德克敏，乘兴贡举。勋御用，哲蒙佑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '001011', '贫鬼守门，日破我盆。罂破瓮，空虚无子。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '001101', '天命赤乌，与兵徼期。征伐无道，箕子遨游。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '101100', '威约拘囚，为人所诬。皋陶平理，剖械出牢，脱归家闾。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '110110', '羊惊虎狼，耸耳群聚。无益威僵，为齿所伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '011011', '初虽啼号，后必庆笑。光明照耀，百嘉如意。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '110010', '马服长股，宜行善市。蒙佑谐耦，获金五倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '010011', '应门内崩，诛贤杀暴。上下咸惬，景公失位。长归元恒，望妻不来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '110011', '执斧破薪，使媒求妇。好合二姓，亲御斯酒。色比毛嫱，姑悦公喜。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '001100', '两轮日转，南上大阪。四马共辕，无有险难，与禹笑言。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010101', '101010', '千柱百梁，终不倾僵，周家宁康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '101010', '志慢未习，单酒糗脯。数至神前，欲求所愿，反得大患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '111111', '且生夕死，名曰婴鬼，不可得祀。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '000000', '大步上车，南至喜家。送我狐裘，与福喜来。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '010001', '西多小星，三五在东。早夜晨行，劳苦无功。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '100010', '北陆藏冰，君子心悲。困于粒食，鬼惊我门。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '010111', '山泉暴怒，坏梁折柱。稽难行旅，留连愁苦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '111010', '比目四翼，来安吾国。福喜上堂，与我同床。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '000010', '狡兔趯趯，良犬逐咋。雄雌爰爰，为鹰所获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '010000', '增禄益福，喜来入室，解除忧惑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '110111', '骑龙乘凤，上见神公。彭祖受制，王乔赞通。巫咸就位，拜福无穷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '111011', '天火卒起，烧我旁里。延及吾家，空尽己财。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '000111', '金帛黄宝，宜与我市。嫁娶有息，利得万倍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '111000', '鬼魅之居，凶不可舍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '111101', '飞鸟逐兔，各有畏恶。鵰鹰为贼，乱我室舍。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '101111', '初虽惊惶，后乃无伤，受其福庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '000100', '两金相击，勇气均敌。日月斗战，不破不缺。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '001000', '曳纶河海，挂钓鲂鲤。王孙利德，以享仲发。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '011001', '犬畏虎狼，依人作辅。三夫执戟，伏不敢起，身安无咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '100110', '蜘蛛作网，以伺行旅。青蝇嚵聚，触我罗域。为网所得，死于网罗。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '000011', '所望在外，鼎命方来。拭爵涤罍，炊食待之，不为季忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '110000', '日月并居，常暗匪明。高山崩颠，丘陵为溪。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '101001', '春服既成，载华复生。茎叶茂盛，实穗泥泥。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '100101', '华首山头，仙道所游。利以居止，长无咎忧。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '100000', '三狐嗥哭，自悲孤独。野无所由，死于丘室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '000001', '火中暑退，求藿其食。商人不至，市空无有。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '111001', '独立山巅，求麋耕田。草木不辟，秋饥无年。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '100111', '火虽炽，在吾后。寇虽近，在吾右。身安吉，不危殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '100001', '贫鬼相贲。无有欢怡，一日九结。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '011110', '追亡逐北，呼还幼叔。至山而得，反归其室。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '010010', '衔命辱使，不堪厥事。遂堕落去，更为欺吏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '101101', '被珠衔玉，沐浴仁德。应聘唐国，四门穆穆。蟊贼不作，凶恶伏匿。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '011100', '机关不便，不能出言。精诚适通，为人所冤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '001110', '瓮破缶缺，南行凶失。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '111100', '唇亡齿寒，积日凌根。朽不可用，为身灾患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '001111', '蒙惑憧憧，不知西东。魁罡指南，告我失中。利以宜止，去国忧患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '101000', '乌鸱搏翼，以避阴贼。盗伺二女，赖厥生福。旱灾为疾，君无黍稷。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '000101', '名成德就，项领不试。景公耄，尼父避去。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '110101', '言与心诡，西行东望。鲧湮洪水，佞贼为祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '101011', '猃狁匪度，治兵焦获。伐镐及方，与周争疆。元戎其驾，衰及夷王。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '010100', '三火起明，雨灭其光。高位疾颠，骄恣诛伤。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '001010', '阴涿川决，水为吾祟。使我溃心，毋树枲麻，居止凶殆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '100011', '厌浥晨夜，道多湛露。沾我襦裤，重难以步。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '110001', '宜行贾市，所求必倍。载喜抱子，与利为友。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '011111', '阴变为阳，女化为男。治道得通，君臣相承。焕之旅。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '111110', '渊蔽杜荆，生蘙山旁。仇敌皆憎，孰肯相迎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '011000', '坐茵乘轩，握德宰臣。虞叔受命，六合和亲。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '000110', '云兴蔽日，雨集草木，年茂岁熟。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '011010', '播枝折岐，与母别离。绝不相知。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '010110', '天旱水涸，枯槁无泽。困于沙石，未有所获。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '011101', '圭璧琮璜，执贽见王。百里宁戚，应聘齐秦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '101110', '龙渴求饮，云黑景从。河伯捧醴，跪进酒浆，流潦滂滂。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '001001', '雹梅零蔕，心思积愤，乱我云气。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '100100', '鹿求其子，虎庐之西。唐伯李耳，贪不我许。焕之既济。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '110100', '穿匏挹水，构铁燃火。劳瘦力竭，饥渴为祸。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '001011', '龙生马渊，寿考且神。舍宿轩辕，居乐常安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '001101', '崔嵬北岳，天神贵客。温仁正直，主布恩德。衣冠不已，蒙受大福。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '101100', '鬼夜哭泣，齐失其国，为下所贼。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '110110', '二政多门，君失其权。三家专制，祸起季孙。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '011011', '望幸不到，文章未就。三子逐兔，犬踦不得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '110010', '伯虎仲熊，德义渊弘。使布五教，阴阳顺序。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '010011', '两足四翼，飞入家国。宁我伯姊，与母相得。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '110011', '春秋祷祝，解祸除忧，君无灾咎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '001100', '牧羊稻园，闻虎喧讙。畏惧悚息，终无祸患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101010', '010101', '大蛇巨鱼，相搏于郊。君臣隔塞，郭公出庐。', datetime('now'));
